    },
    searchParcels: async (tableName: string, filters: { sodoto?: string, sothua?: string, tenchu?: string, diachi?: string }): Promise<LandParcel[]> => {
        try {
             let queryString = `?t=${Date.now()}`;
             if (filters.sodoto) queryString += `&sodoto=${encodeURIComponent(filters.sodoto)}`;
             if (filters.sothua) queryString += `&sothua=${encodeURIComponent(filters.sothua)}`;
             if (filters.tenchu) queryString += `&tenchu=${encodeURIComponent(filters.tenchu)}`;
             if (filters.diachi) queryString += `&diachi=${encodeURIComponent(filters.diachi)}`;
             const data = await apiCall(`/data/${tableName}${queryString}`);
             if (!Array.isArray(data)) return [];
             return data.map((item: any) => ({
                 id: item.gid?.toString() || `p-${Math.random()}`,
                 gid: item.gid,
                 geometry: item.geometry,
                 properties: { ...item, so_to: item.sodoto, so_thua: item.sothua, ownerName: item.tenchu, address: item.diachi, area: item.dientich, landType: item.loaidat || item.kyhieumucd || 'Chưa cập nhật', tableName: tableName }
             }));
        } catch (e) { return []; }
    }
};

