interface MessagingProps {
    user: User;
}

const MailCenter: React.FC<MessagingProps> = ({ user }) => {
    const [view, setView] = useState<'INBOX' | 'SENT' | 'COMPOSE' | 'READ'>('INBOX');
    const [mails, setMails] = useState<Message[]>([]);
    const [selectedMail, setSelectedMail] = useState<Message | null>(null);
    const [recipients, setRecipients] = useState<User[]>([]);
    const [loading, setLoading] = useState(false);

    // Compose State
    const [composeData, setComposeData] = useState({ receiverId: '', content: '' });
    const [searchRecipient, setSearchRecipient] = useState('');

    // System Dialog State
    const [dialog, setDialog] = useState<{
        isOpen: boolean;
        type: 'alert' | 'confirm' | 'success' | 'error';
        title: string;
        message: string;
        onConfirm?: () => void;
    }>({ isOpen: false, type: 'alert', title: '', message: '' });

    const showDialog = (type: any, title: string, message: string, onConfirm?: () => void) => {
        setDialog({ isOpen: true, type, title, message, onConfirm });
    };

    useEffect(() => {
        loadMails();
        loadRecipients();
    }, [view]);

    const loadMails = async () => {
        if (view === 'COMPOSE' || view === 'READ') return;
        setLoading(true);
        try {
            const data = view === 'INBOX' 
                ? await messageService.getInbox() 
                : await messageService.getSent();
            setMails(data);
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    const loadRecipients = async () => {
        try {
            const users = await adminService.getUsers();
            setRecipients(users.filter(u => u.id !== user.id));
        } catch (e) {}
    };

    const handleReadMail = async (mail: Message) => {
        setSelectedMail(mail);
        setView('READ');
        if (!mail.is_read && view === 'INBOX') {
            try {
                await messageService.markAsRead(mail.id);
                setMails(prev => prev.map(m => m.id === mail.id ? { ...m, is_read: true } : m));
            } catch (e) {}
        }
    };

    const handleSendMail = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!composeData.receiverId || !composeData.content.trim()) return;

        setLoading(true);
        try {
            await messageService.sendMessage(composeData.receiverId, composeData.content);
            showDialog('success', 'Thành công', 'Thư của bạn đã được gửi đi.');
            setComposeData({ receiverId: '', content: '' });
            setView('SENT');
        } catch (e: any) {
            showDialog('error', 'Lỗi gửi thư', e.message);
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteMail = (id: number) => {
        showDialog('confirm', 'Xác nhận xóa', 'Bạn có chắc chắn muốn xóa thư này khỏi hộp thư?', async () => {
            try {
                await messageService.deleteMessage(id);
                setMails(prev => prev.filter(m => m.id !== id));
                if (selectedMail?.id === id) setView('INBOX');
            } catch (e: any) {
                showDialog('error', 'Lỗi', e.message);
            }
        });
    };

    const getAvatarUrl = (path?: string) => {
        if (!path) return null;
        if (path.startsWith('http') || path.startsWith('data:')) return path;
        return `${API_URL}${path.startsWith('/') ? path : '/' + path}`;
    };

    const filteredRecipients = recipients.filter(r => 
        r.name.toLowerCase().includes(searchRecipient.toLowerCase()) || 
        r.email.toLowerCase().includes(searchRecipient.toLowerCase())
    );

    return (
        <div className="flex h-full bg-slate-950 overflow-hidden font-sans">
            {/* Sidebar Navigation */}
            <div className="w-64 border-r border-slate-800 flex flex-col bg-slate-900/50 backdrop-blur-md">
                <div className="p-6">
                    <button 
                        onClick={() => { setView('COMPOSE'); setSelectedMail(null); }}
                        className="w-full bg-blue-600 hover:bg-blue-500 text-white p-3 rounded-2xl font-black uppercase text-[11px] tracking-widest flex items-center justify-center gap-2 shadow-lg shadow-blue-900/40 transition-all active:scale-95 mb-8"
                    >
                        <Plus size={18}/> Soạn thư mới
                    </button>

                    <div className="space-y-1">
                        <button 
                            onClick={() => { setView('INBOX'); setSelectedMail(null); }}
                            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${view === 'INBOX' ? 'bg-slate-800 text-blue-400' : 'text-slate-400 hover:bg-slate-800/50 hover:text-white'}`}
                        >
                            <Inbox size={18}/>
                            <span className="text-xs font-bold uppercase tracking-wider">Hộp thư đến</span>
                        </button>
                        <button 
                            onClick={() => { setView('SENT'); setSelectedMail(null); }}
                            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${view === 'SENT' ? 'bg-slate-800 text-blue-400' : 'text-slate-400 hover:bg-slate-800/50 hover:text-white'}`}
                        >
                            <SendHorizontal size={18}/>
                            <span className="text-xs font-bold uppercase tracking-wider">Thư đã gửi</span>
                        </button>
                    </div>
                </div>
            </div>

            {/* List & Detail Area */}
            <div className="flex-1 flex flex-col relative bg-slate-950">
                {/* Header */}
                <div className="p-4 border-b border-slate-800 bg-slate-900/30 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="bg-blue-600/20 p-2 rounded-lg">
                            {view === 'INBOX' ? <Inbox className="text-blue-500" size={20}/> : 
                             view === 'SENT' ? <SendHorizontal className="text-blue-500" size={20}/> : 
                             <Mail className="text-blue-500" size={20}/>}
                        </div>
                        <h2 className="text-sm font-black text-white uppercase tracking-widest">
                            {view === 'INBOX' ? 'Hộp thư đến' : view === 'SENT' ? 'Thư đã gửi' : view === 'READ' ? 'Chi tiết thư' : 'Soạn thư mới'}
                        </h2>
                    </div>
                    {(view === 'INBOX' || view === 'SENT') && (
                        <button onClick={loadMails} className="text-slate-500 hover:text-white transition-all">
                            <RefreshCw size={18} className={loading ? "animate-spin" : ""}/>
                        </button>
                    )}
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                    {loading ? (
                        <div className="flex flex-col items-center justify-center h-full gap-4">
                            <Loader2 className="animate-spin text-blue-500" size={32}/>
                            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Đang tải dữ liệu...</p>
                        </div>
                    ) : view === 'READ' && selectedMail ? (
                        /* VIEW MAIL */
                        <div className="p-8 max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-300">
                            <button onClick={() => setView(selectedMail.sender_id === user.id ? 'SENT' : 'INBOX')} className="flex items-center gap-2 text-slate-500 hover:text-white transition-all text-xs font-bold uppercase mb-4">
                                <ArrowLeft size={16}/> Quay lại
                            </button>

                            <div className="bg-slate-900/50 border border-slate-800 rounded-3xl p-8 space-y-6">
                                <div className="flex justify-between items-start border-b border-slate-800 pb-6">
                                    <div className="flex gap-4">
                                        <div className="w-12 h-12 rounded-full border-2 border-slate-700 overflow-hidden bg-slate-800">
                                            {selectedMail.sender_avatar ? (
                                                <img src={getAvatarUrl(selectedMail.sender_avatar)!} className="w-full h-full object-cover" />
                                            ) : (
                                                <div className="w-full h-full flex items-center justify-center text-blue-400 font-black">{selectedMail.sender_name?.charAt(0)}</div>
                                            )}
                                        </div>
                                        <div>
                                            <p className="text-white font-black text-lg leading-none mb-1">{selectedMail.sender_name}</p>
                                            <p className="text-slate-500 text-xs font-mono">{selectedMail.sender_email || 'No email'}</p>
                                        </div>
                                    </div>
                                    <div className="text-right">
                                        <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest flex items-center gap-2">
                                            <Clock size={12}/> {new Date(selectedMail.timestamp).toLocaleString()}
                                        </p>
                                        <button onClick={() => handleDeleteMail(selectedMail.id)} className="mt-4 text-red-500/50 hover:text-red-500 transition-all">
                                            <Trash2 size={18}/>
                                        </button>
                                    </div>
                                </div>

                                <div className="text-slate-200 leading-relaxed whitespace-pre-wrap text-sm py-4">
                                    {selectedMail.content}
                                </div>
                            </div>
                        </div>
                    ) : view === 'COMPOSE' ? (
                        /* COMPOSE MAIL */
                        <div className="p-8 max-w-4xl mx-auto space-y-6 animate-in fade-in duration-300">
                            <form onSubmit={handleSendMail} className="bg-slate-900 border border-slate-800 rounded-3xl p-8 space-y-6 shadow-2xl">
                                <div>
                                    <label className="text-[10px] text-slate-500 font-black uppercase tracking-widest block mb-2 ml-1">Người nhận *</label>
                                    <div className="relative">
                                        <select 
                                            required
                                            className="w-full bg-slate-950 border border-slate-700 rounded-xl p-4 text-sm text-white focus:border-blue-500 outline-none appearance-none cursor-pointer"
                                            value={composeData.receiverId}
                                            onChange={e => setComposeData({...composeData, receiverId: e.target.value})}
                                        >
                                            <option value="">-- Chọn cán bộ tiếp nhận --</option>
                                            {recipients.map(r => <option key={r.id} value={r.id}>{r.name} ({r.role})</option>)}
                                        </select>
                                    </div>
                                </div>

                                <div>
                                    <label className="text-[10px] text-slate-500 font-black uppercase tracking-widest block mb-2 ml-1">Nội dung thư *</label>
                                    <textarea 
                                        required
                                        className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-4 text-sm text-white focus:border-blue-500 outline-none h-64 resize-none shadow-inner"
                                        placeholder="Nhập nội dung thư của bạn tại đây..."
                                        value={composeData.content}
                                        onChange={e => setComposeData({...composeData, content: e.target.value})}
                                    />
                                </div>

                                <div className="flex justify-end gap-4 pt-4">
                                    <button type="button" onClick={() => setView('INBOX')} className="px-6 py-3 text-slate-500 hover:text-white font-bold uppercase text-xs">Hủy bỏ</button>
                                    <button 
                                        type="submit" 
                                        disabled={loading}
                                        className="bg-blue-600 hover:bg-blue-500 text-white px-10 py-3 rounded-xl font-black uppercase text-xs tracking-widest flex items-center gap-2 shadow-xl shadow-blue-900/30 transition-all active:scale-95"
                                    >
                                        {loading ? <Loader2 className="animate-spin" size={16}/> : <Send size={16}/>} Gửi thư ngay
                                    </button>
                                </div>
                            </form>
                        </div>
                    ) : (
                        /* LIST MAILS (INBOX/SENT) */
                        <div className="divide-y divide-slate-800/50">
                            {mails.length === 0 ? (
                                <div className="p-20 text-center flex flex-col items-center gap-4 opacity-30">
                                    <Mail size={48} className="text-slate-600"/>
                                    <p className="text-xs font-black uppercase tracking-widest">Hộp thư đang trống</p>
                                </div>
                            ) : mails.map(m => (
                                <div 
                                    key={m.id} 
                                    onClick={() => handleReadMail(m)}
                                    className={`group flex items-center gap-4 p-5 hover:bg-slate-800/40 cursor-pointer transition-all border-l-4 ${m.is_read || view === 'SENT' ? 'border-transparent' : 'border-blue-600 bg-blue-600/5'}`}
                                >
                                    <div className="w-10 h-10 rounded-full border border-slate-700 overflow-hidden bg-slate-900 shrink-0">
                                        {(view === 'INBOX' ? m.sender_avatar : m.receiver_avatar) ? (
                                            <img src={getAvatarUrl(view === 'INBOX' ? m.sender_avatar : m.receiver_avatar)!} className="w-full h-full object-cover" />
                                        ) : (
                                            <div className="w-full h-full flex items-center justify-center text-[10px] font-black text-slate-500">{(view === 'INBOX' ? m.sender_name : m.receiver_name)?.charAt(0)}</div>
                                        )}
                                    </div>

                                    <div className="flex-1 overflow-hidden">
                                        <div className="flex justify-between items-center mb-0.5">
                                            <p className={`text-xs uppercase tracking-tighter ${m.is_read || view === 'SENT' ? 'text-slate-400 font-bold' : 'text-white font-black'}`}>
                                                {view === 'INBOX' ? m.sender_name : m.receiver_name}
                                            </p>
                                            <p className="text-[9px] font-bold text-slate-600 uppercase">{new Date(m.timestamp).toLocaleDateString()}</p>
                                        </div>
                                        <p className={`text-sm truncate ${m.is_read || view === 'SENT' ? 'text-slate-500' : 'text-slate-200'}`}>{m.content}</p>
                                    </div>

                                    <div className="opacity-0 group-hover:opacity-100 transition-opacity">
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); handleDeleteMail(m.id); }}
                                            className="p-2 text-slate-600 hover:text-red-500 transition-colors"
                                        >
                                            <Trash2 size={16}/>
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            {/* --- SYSTEM DIALOG --- */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-slate-900 rounded-[2.5rem] w-full max-w-sm border border-slate-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'confirm' && <div className="w-14 h-14 bg-orange-500/20 text-orange-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}

                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>

                            <div className="flex gap-2 w-full">
                                {dialog.type === 'confirm' ? (
                                    <>
                                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 text-gray-400 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">HỦY BỎ</button>
                                        <button onClick={() => { setDialog({ ...dialog, isOpen: false }); dialog.onConfirm?.(); }} className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg transition-all">XÁC NHẬN</button>
                                    </>
                                ) : (
                                    <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg transition-all">OK</button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MailCenter;

import React, { useState, useEffect, useRef } from 'react';
import { User, UserRole, MenuItem, SystemNotification } from '../types';
import { LogOut, LogIn, ChevronLeft, ChevronRight, User as UserIcon, Database, HelpCircle, ExternalLink, Bell, X, Info, AlertTriangle, Clock, Mail } from 'lucide-react';
import * as Icons from 'lucide-react';
import { adminService, notificationService, API_URL } from '../services/mockBackend';

interface SidebarProps {
  user: User | null;
  activePage: string;
  onNavigate: (page: string) => void;
  onLogout: () => void;
  onLoginClick: () => void;
  onCollapse: () => void;
  isCollapsed: boolean;
  systemName?: string;
  logoUrl?: string;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    user, 
    activePage, 
    onNavigate, 
    onLogout, 
    onLoginClick, 
    onCollapse, 
    isCollapsed,
    systemName, 
    logoUrl 
}) => {
  const [dynamicMenu, setDynamicMenu] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [imgError, setImgError] = useState(false);

  // Notification States
  const [notifications, setNotifications] = useState<SystemNotification[]>([]);
  const [isNotiOpen, setIsNotiOpen] = useState(false);
  const [unreadCount, setUnreadCount] = useState(0);
  const notiRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
      setImgError(false);
  }, [user?.avatar]);

  useEffect(() => {
      const fetchMenu = async () => {
          try {
              if (adminService && typeof adminService.getMenuItems === 'function') {
                  const items = await adminService.getMenuItems();
                  setDynamicMenu(items.filter(i => i.is_active).sort((a, b) => a.order_index - b.order_index));
              }
          } catch (e) {
              console.error("Failed to load sidebar menu", e);
          } finally {
              setLoading(false);
          }
      };
      fetchMenu();
  }, [user?.role]);

  // Fetch Notifications
  useEffect(() => {
      if (user) {
          const fetchNoti = async () => {
              try {
                  const data = await notificationService.getNotifications();
                  setNotifications(data);
                  const lastRead = localStorage.getItem(`last_read_noti_${user.id}`) || '0';
                  const count = data.filter(n => new Date(n.created_at).getTime() > parseInt(lastRead)).length;
                  setUnreadCount(count);
              } catch (e) {}
          };
          fetchNoti();
          const interval = setInterval(fetchNoti, 60000);
          return () => clearInterval(interval);
      }
  }, [user]);

  useEffect(() => {
      const handleOutside = (e: MouseEvent) => {
          if (notiRef.current && !notiRef.current.contains(e.target as Node)) setIsNotiOpen(false);
      };
      document.addEventListener('mousedown', handleOutside);
      return () => document.removeEventListener('mousedown', handleOutside);
  }, []);

  const handleOpenNoti = () => {
      setIsNotiOpen(!isNotiOpen);
      if (!isNotiOpen && user) {
          setUnreadCount(0);
          localStorage.setItem(`last_read_noti_${user.id}`, Date.now().toString());
      }
  };

  const visibleItems = dynamicMenu.filter(item => {
    if (!user) return item.roles.includes('GUEST');
    return item.roles.includes(user.role);
  });

  const handleMenuClick = (item: MenuItem) => {
      if (item.type === 'EXTERNAL' && item.url) {
          window.open(item.url, '_blank');
      } else {
          onNavigate(item.id);
      }
  };

  const getAvatarUrl = (path?: string) => {
      if (!path) return null;
      if (path.startsWith('http') || path.startsWith('data:')) return path;
      const cleanPath = path.startsWith('/') ? path : `/${path}`;
      const baseUrl = API_URL.endsWith('/') ? API_URL.slice(0, -1) : API_URL;
      return `${baseUrl}${cleanPath}?cache_bust=${new Date().getTime()}`;
  };

  const renderAvatar = () => {
      if (!user) return <UserIcon size={18} className="text-blue-400" />;
      const avatarSrc = getAvatarUrl(user.avatar);
      if (avatarSrc && !imgError) {
          return <img src={avatarSrc} alt={user.name} className="w-full h-full object-cover" onError={() => setImgError(true)} />;
      }
      return (
          <div className="w-full h-full bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white font-bold text-xs uppercase">
              {user.name ? user.name.charAt(0) : <UserIcon size={16} />}
          </div>
      );
  };

  return (
    <div className={`${isCollapsed ? 'w-20' : 'w-72'} bg-[#0f172a] text-white h-screen flex flex-col transition-all duration-300 ease-in-out border-r border-slate-800 relative z-50 shadow-2xl`}>
      <button 
        onClick={onCollapse} 
        className="absolute -right-3 top-10 bg-blue-600 text-white rounded-full p-1.5 shadow-lg border-2 border-[#0f172a] hover:bg-blue-500 transition-all z-[60]"
      >
        {isCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
      </button>

      <div className={`p-6 border-b border-slate-800/80 flex flex-col items-center ${isCollapsed ? 'justify-center' : 'items-start'}`}>
        <div className="flex items-center justify-between w-full">
            <div className="flex items-center gap-3.5">
                {logoUrl ? (
                    <img src={logoUrl} alt="Logo" className="w-9 h-9 object-contain drop-shadow-[0_0_15px_rgba(59,130,246,0.6)]" />
                ) : (
                    <div className="w-9 h-9 bg-blue-600 rounded-lg flex items-center justify-center shadow-lg shadow-blue-900/50">
                        <Database className="w-5 h-5 text-white" />
                    </div>
                )}
                {!isCollapsed && (
                    <div className="animate-in fade-in slide-in-from-left-2 duration-300">
                        <h1 className="text-base font-black text-white leading-none uppercase tracking-tighter mb-1">
                            {systemName || 'GeoMaster'}
                        </h1>
                        <div className="flex items-center gap-1.5">
                            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
                            <p className="text-[9px] text-slate-400 font-bold tracking-[0.2em] uppercase">Enterprise</p>
                        </div>
                    </div>
                )}
            </div>

            {user && !isCollapsed && (
                <div className="relative" ref={notiRef}>
                    <button 
                        onClick={handleOpenNoti}
                        className={`p-2 rounded-xl transition-all ${isNotiOpen ? 'bg-blue-600 text-white' : 'bg-slate-800/50 text-slate-400 hover:bg-slate-800'}`}
                    >
                        <Bell size={18} />
                        {unreadCount > 0 && (
                            <span className="absolute -top-1 -right-1 w-4 h-4 bg-red-600 text-white text-[8px] font-black rounded-full flex items-center justify-center border-2 border-[#0f172a] animate-bounce">
                                {unreadCount}
                            </span>
                        )}
                    </button>

                    {isNotiOpen && (
                        <div className="absolute left-10 top-0 w-80 bg-slate-900 border border-slate-700 rounded-2xl shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-200 z-[100]">
                            <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-950/50">
                                <h4 className="text-[10px] font-black uppercase tracking-widest text-white">Trung tâm Thông báo</h4>
                                <button onClick={() => setIsNotiOpen(false)} className="text-slate-500 hover:text-white"><X size={14}/></button>
                            </div>
                            <div className="max-h-96 overflow-y-auto custom-scrollbar">
                                {notifications.length === 0 ? (
                                    <div className="p-10 text-center text-slate-600 italic text-xs">Không có thông báo mới</div>
                                ) : notifications.map(n => (
                                    <div key={n.id} className="p-4 border-b border-slate-800/50 hover:bg-slate-800/30 transition-colors">
                                        <div className="flex gap-3">
                                            <div className={`w-8 h-8 rounded-full shrink-0 flex items-center justify-center ${
                                                n.type === 'DANGER' ? 'bg-red-900/30 text-red-500' :
                                                n.type === 'WARNING' ? 'bg-orange-900/30 text-orange-500' :
                                                'bg-blue-900/30 text-blue-500'
                                            }`}>
                                                {n.type === 'DANGER' ? <AlertTriangle size={14}/> : <Info size={14}/>}
                                            </div>
                                            <div className="flex-1 overflow-hidden">
                                                <p className="text-xs font-black text-slate-200 mb-1">{n.title}</p>
                                                <p className="text-[10px] text-slate-500 leading-relaxed mb-2">{n.content}</p>
                                                <div className="flex items-center gap-2 text-[8px] font-bold text-slate-600 uppercase">
                                                    <Clock size={8}/> {new Date(n.created_at).toLocaleDateString()}
                                                    <span>•</span>
                                                    <span>Admin: {n.sender_name}</span>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            )}
        </div>
      </div>

      <div className="flex-1 py-6 space-y-1.5 overflow-y-auto custom-scrollbar no-scrollbar px-3">
        {loading ? (
            <div className="animate-pulse flex flex-col gap-3 px-2">
                {[1,2,3].map(i => <div key={i} className="h-11 bg-slate-800/50 rounded-xl w-full"></div>)}
            </div>
        ) : visibleItems.map(item => {
          const isActive = activePage === item.id;
          let IconComponent = (Icons as any)[item.icon] || HelpCircle;

          // Sửa label và icon cho Messaging động nếu cần
          let label = item.label;
          if (item.id === 'messaging') {
              label = 'Hộp thư nội bộ';
              IconComponent = Mail;
          }

          return (
            <button
              key={item.id}
              onClick={() => handleMenuClick(item)}
              title={isCollapsed ? label : ''}
              className={`w-full flex items-center gap-3.5 px-4 py-3 rounded-xl transition-all relative group overflow-hidden ${
                isActive 
                  ? 'text-white bg-blue-600 shadow-lg shadow-blue-900/20' 
                  : 'text-slate-400 hover:text-white hover:bg-slate-800/80'
              }`}
            >
              <div className={`${isCollapsed ? 'mx-auto' : ''} transition-transform group-hover:scale-110 flex items-center z-10`}>
                <IconComponent size={20} className={isActive ? 'text-white' : 'text-slate-400 group-hover:text-blue-400'} />
              </div>

              {!isCollapsed && (
                <div className="flex-1 flex items-center justify-between animate-in fade-in slide-in-from-left-2 duration-300 z-10">
                    <span className={`font-bold text-xs uppercase tracking-wide ${isActive ? 'text-white' : ''}`}>
                        {label}
                    </span>
                    {item.type === 'EXTERNAL' && (
                        <ExternalLink size={12} className="text-slate-500 group-hover:text-white transition-colors" />
                    )}
                </div>
              )}
            </button>
          );
        })}
      </div>

      <div className="p-4 border-t border-slate-800/80 bg-slate-900/50 backdrop-blur-sm">
        {user ? (
          <div className="flex flex-col gap-3">
            {isCollapsed && (
                <button onClick={handleOpenNoti} className="w-10 h-10 mx-auto rounded-full bg-slate-800 flex items-center justify-center text-slate-400 hover:text-blue-400 transition-colors relative mb-2">
                    <Bell size={18}/>
                    {unreadCount > 0 && <span className="absolute top-0 right-0 w-3 h-3 bg-red-600 rounded-full border-2 border-[#0f172a]"></span>}
                </button>
            )}

            {!isCollapsed ? (
              <div 
                onClick={() => onNavigate('profile')}
                className="flex items-center gap-3.5 p-2.5 rounded-xl cursor-pointer hover:bg-slate-800 transition-all group border border-transparent hover:border-slate-700/50"
                title="Cập nhật hồ sơ"
              >
                  <div className="w-10 h-10 rounded-full border-2 border-slate-700 group-hover:border-blue-500 overflow-hidden shrink-0 shadow-lg transition-all">
                    {renderAvatar()}
                  </div>
                  <div className="overflow-hidden flex-1">
                      <p className="text-xs font-black text-white truncate group-hover:text-blue-400 transition-colors">
                          {user.name}
                      </p>
                      <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider mt-0.5 flex items-center gap-1">
                          <span className={`w-1.5 h-1.5 rounded-full ${user.role === 'ADMIN' ? 'bg-orange-500' : 'bg-blue-500'}`}></span>
                          {user.role}
                      </p>
                  </div>
              </div>
            ) : (
                 <div 
                    onClick={() => onNavigate('profile')} 
                    className="w-10 h-10 mx-auto rounded-full border-2 border-slate-700 hover:border-blue-500 overflow-hidden cursor-pointer mb-3 shadow-lg transition-all"
                    title={user.name}
                 >
                    {renderAvatar()}
                 </div>
            )}

            <button 
              onClick={onLogout}
              title={isCollapsed ? "Đăng xuất" : ""}
              className={`flex items-center gap-3 px-4 py-2.5 bg-red-500/10 text-red-400 rounded-xl hover:bg-red-500 hover:text-white transition-all border border-red-500/10 hover:border-red-500 ${isCollapsed ? 'justify-center' : ''}`}
            >
              <LogOut size={18} />
              {!isCollapsed && <span className="text-[10px] font-black uppercase tracking-widest">Đăng xuất</span>}
            </button>
          </div>
        ) : (
          <button 
            onClick={onLoginClick}
            className="w-full flex items-center gap-2 px-4 py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl transition-all shadow-lg shadow-blue-900/30 group"
          >
            <LogIn size={18} className="group-hover:-translate-x-0.5 transition-transform" />
            {!isCollapsed && <span className="text-[10px] font-black uppercase tracking-widest">Đăng nhập</span>}
          </button>
        )}
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect, useRef } from 'react';
import { User, Message, UserRole } from '../types';
import { messageService, adminService, API_URL } from '../services/mockBackend';
import { Send, User as UserIcon, Search, Loader2, Mail, Inbox, SendHorizontal, Trash2, ArrowLeft, Plus, RefreshCw, Clock, ShieldCheck, CheckCircle2, AlertTriangle, Info, Check, CheckCheck } from 'lucide-react';

interface MessagingProps {
    user: User;
}

const MailCenter: React.FC<MessagingProps> = ({ user }) => {
    const [view, setView] = useState<'INBOX' | 'SENT' | 'COMPOSE' | 'READ'>('INBOX');
    const [mails, setMails] = useState<Message[]>([]);
    const [selectedMail, setSelectedMail] = useState<Message | null>(null);
    const [recipients, setRecipients] = useState<User[]>([]);
    const [loading, setLoading] = useState(false);

    // Compose State
    const [composeData, setComposeData] = useState({ receiverId: '', content: '' });
    const [searchRecipient, setSearchRecipient] = useState('');

    // System Dialog State
    const [dialog, setDialog] = useState<{
        isOpen: boolean;
        type: 'alert' | 'confirm' | 'success' | 'error';
        title: string;
        message: string;
        onConfirm?: () => void;
    }>({ isOpen: false, type: 'alert', title: '', message: '' });

    const showDialog = (type: any, title: string, message: string, onConfirm?: () => void) => {
        setDialog({ isOpen: true, type, title, message, onConfirm });
    };

    useEffect(() => {
        loadMails();
        loadRecipients();
    }, [view]);

    const loadMails = async () => {
        if (view === 'COMPOSE' || view === 'READ') return;
        setLoading(true);
        try {
            const data = view === 'INBOX' 
                ? await messageService.getInbox() 
                : await messageService.getSent();
            setMails(data);
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    const loadRecipients = async () => {
        try {
            const users = await adminService.getUsers();
            setRecipients(users.filter(u => u.id !== user.id));
        } catch (e) {}
    };

    const handleReadMail = async (mail: Message) => {
        setSelectedMail(mail);
        setView('READ');
        if (!mail.is_read && view === 'INBOX') {
            try {
                await messageService.markAsRead(mail.id);
                setMails(prev => prev.map(m => m.id === mail.id ? { ...m, is_read: true } : m));
            } catch (e) {}
        }
    };

    const handleSendMail = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!composeData.receiverId || !composeData.content.trim()) return;

        setLoading(true);
        try {
            await messageService.sendMessage(composeData.receiverId, composeData.content);
            showDialog('success', 'Thành công', 'Thư của bạn đã được gửi đi.');
            setComposeData({ receiverId: '', content: '' });
            setView('SENT');
        } catch (e: any) {
            showDialog('error', 'Lỗi gửi thư', e.message);
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteMail = (id: number) => {
        showDialog('confirm', 'Xác nhận xóa', 'Bạn có chắc chắn muốn xóa thư này khỏi hộp thư?', async () => {
            try {
                await messageService.deleteMessage(id);
                setMails(prev => prev.filter(m => m.id !== id));
                if (selectedMail?.id === id) setView('INBOX');
            } catch (e: any) {
                showDialog('error', 'Lỗi', e.message);
            }
        });
    };

    const getAvatarUrl = (path?: string) => {
        if (!path) return null;
        if (path.startsWith('http') || path.startsWith('data:')) return path;
        return `${API_URL}${path.startsWith('/') ? path : '/' + path}`;
    };

    const filteredRecipients = recipients.filter(r => 
        r.name.toLowerCase().includes(searchRecipient.toLowerCase()) || 
        r.email.toLowerCase().includes(searchRecipient.toLowerCase())
    );

    return (
        <div className="flex h-full bg-slate-950 overflow-hidden font-sans">
            {/* Sidebar Navigation - Fixed with shrink-0 */}
            <div className="w-64 shrink-0 border-r border-slate-800 flex flex-col bg-slate-900/50 backdrop-blur-md">
                <div className="p-6">
                    <button 
                        onClick={() => { setView('COMPOSE'); setSelectedMail(null); }}
                        className="w-full bg-blue-600 hover:bg-blue-500 text-white p-3 rounded-2xl font-black uppercase text-[11px] tracking-widest flex items-center justify-center gap-2 shadow-lg shadow-blue-900/40 transition-all active:scale-95 mb-8"
                    >
                        <Plus size={18}/> Soạn thư mới
                    </button>

                    <div className="space-y-1">
                        <button 
                            onClick={() => { setView('INBOX'); setSelectedMail(null); }}
                            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${view === 'INBOX' ? 'bg-slate-800 text-blue-400' : 'text-slate-400 hover:bg-slate-800/50 hover:text-white'}`}
                        >
                            <Inbox size={18}/>
                            <span className="text-xs font-bold uppercase tracking-wider">Hộp thư đến</span>
                        </button>
                        <button 
                            onClick={() => { setView('SENT'); setSelectedMail(null); }}
                            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${view === 'SENT' ? 'bg-slate-800 text-blue-400' : 'text-slate-400 hover:bg-slate-800/50 hover:text-white'}`}
                        >
                            <SendHorizontal size={18}/>
                            <span className="text-xs font-bold uppercase tracking-wider">Thư đã gửi</span>
                        </button>
                    </div>
                </div>
            </div>

            {/* List & Detail Area */}
            <div className="flex-1 flex flex-col relative bg-slate-950 min-w-0">
                {/* Header */}
                <div className="p-4 border-b border-slate-800 bg-slate-900/30 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="bg-blue-600/20 p-2 rounded-lg shrink-0">
                            {view === 'INBOX' ? <Inbox className="text-blue-500" size={20}/> : 
                             view === 'SENT' ? <SendHorizontal className="text-blue-500" size={20}/> : 
                             <Mail className="text-blue-500" size={20}/>}
                        </div>
                        <h2 className="text-sm font-black text-white uppercase tracking-widest truncate">
                            {view === 'INBOX' ? 'Hộp thư đến' : view === 'SENT' ? 'Thư đã gửi' : view === 'READ' ? 'Chi tiết thư' : 'Soạn thư mới'}
                        </h2>
                    </div>
                    {(view === 'INBOX' || view === 'SENT') && (
                        <button onClick={loadMails} className="text-slate-500 hover:text-white transition-all shrink-0">
                            <RefreshCw size={18} className={loading ? "animate-spin" : ""}/>
                        </button>
                    )}
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                    {loading ? (
                        <div className="flex flex-col items-center justify-center h-full gap-4">
                            <Loader2 className="animate-spin text-blue-500" size={32}/>
                            <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Đang tải dữ liệu...</p>
                        </div>
                    ) : view === 'READ' && selectedMail ? (
                        /* VIEW MAIL */
                        <div className="p-8 max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-300">
                            <button onClick={() => setView(selectedMail.sender_id === user.id ? 'SENT' : 'INBOX')} className="flex items-center gap-2 text-slate-500 hover:text-white transition-all text-xs font-bold uppercase mb-4">
                                <ArrowLeft size={16}/> Quay lại
                            </button>

                            <div className="bg-slate-900/50 border border-slate-800 rounded-3xl p-8 space-y-6 shadow-xl">
                                <div className="flex justify-between items-start border-b border-slate-800 pb-6">
                                    <div className="flex gap-4 min-w-0">
                                        <div className="w-12 h-12 rounded-full border-2 border-slate-700 overflow-hidden bg-slate-800 shrink-0">
                                            {selectedMail.sender_avatar ? (
                                                <img src={getAvatarUrl(selectedMail.sender_avatar)!} className="w-full h-full object-cover" />
                                            ) : (
                                                <div className="w-full h-full flex items-center justify-center text-blue-400 font-black text-xl">{selectedMail.sender_name?.charAt(0)}</div>
                                            )}
                                        </div>
                                        <div className="min-w-0 overflow-hidden">
                                            <p className="text-white font-black text-lg leading-none mb-1 truncate">{selectedMail.sender_name}</p>
                                            <p className="text-slate-500 text-xs font-mono truncate">{selectedMail.sender_email || 'No email'}</p>
                                        </div>
                                    </div>
                                    <div className="text-right shrink-0">
                                        <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest flex items-center gap-2 justify-end">
                                            <Clock size={12}/> {new Date(selectedMail.timestamp).toLocaleString()}
                                        </p>
                                        <button onClick={() => handleDeleteMail(selectedMail.id)} className="mt-4 text-red-500/50 hover:text-red-500 transition-all">
                                            <Trash2 size={18}/>
                                        </button>
                                    </div>
                                </div>

                                <div className="text-slate-200 leading-relaxed whitespace-pre-wrap text-sm py-4">
                                    {selectedMail.content}
                                </div>
                            </div>
                        </div>
                    ) : view === 'COMPOSE' ? (
                        /* COMPOSE MAIL */
                        <div className="p-8 max-w-4xl mx-auto space-y-6 animate-in fade-in duration-300">
                            <form onSubmit={handleSendMail} className="bg-slate-900 border border-slate-800 rounded-3xl p-8 space-y-6 shadow-2xl">
                                <div>
                                    <label className="text-[10px] text-slate-500 font-black uppercase tracking-widest block mb-2 ml-1">Người nhận *</label>
                                    <div className="relative">
                                        <select 
                                            required
                                            className="w-full bg-slate-950 border border-slate-700 rounded-xl p-4 text-sm text-white focus:border-blue-500 outline-none appearance-none cursor-pointer"
                                            value={composeData.receiverId}
                                            onChange={e => setComposeData({...composeData, receiverId: e.target.value})}
                                        >
                                            <option value="">-- Chọn cán bộ tiếp nhận --</option>
                                            {recipients.map(r => <option key={r.id} value={r.id}>{r.name} ({r.role})</option>)}
                                        </select>
                                    </div>
                                </div>

                                <div>
                                    <label className="text-[10px] text-slate-500 font-black uppercase tracking-widest block mb-2 ml-1">Nội dung thư *</label>
                                    <textarea 
                                        required
                                        className="w-full bg-slate-950 border border-slate-700 rounded-2xl p-4 text-sm text-white focus:border-blue-500 outline-none h-64 resize-none shadow-inner"
                                        placeholder="Nhập nội dung thư của bạn tại đây..."
                                        value={composeData.content}
                                        onChange={e => setComposeData({...composeData, content: e.target.value})}
                                    />
                                </div>

                                <div className="flex justify-end gap-4 pt-4">
                                    <button type="button" onClick={() => setView('INBOX')} className="px-6 py-3 text-slate-500 hover:text-white font-bold uppercase text-xs">Hủy bỏ</button>
                                    <button 
                                        type="submit" 
                                        disabled={loading}
                                        className="bg-blue-600 hover:bg-blue-500 text-white px-10 py-3 rounded-xl font-black uppercase text-xs tracking-widest flex items-center gap-2 shadow-xl shadow-blue-900/30 transition-all active:scale-95"
                                    >
                                        {loading ? <Loader2 className="animate-spin" size={16}/> : <Send size={16}/>} Gửi thư ngay
                                    </button>
                                </div>
                            </form>
                        </div>
                    ) : (
                        /* LIST MAILS (INBOX/SENT) */
                        <div className="divide-y divide-slate-800/50">
                            {mails.length === 0 ? (
                                <div className="p-20 text-center flex flex-col items-center gap-4 opacity-30">
                                    <Mail size={48} className="text-slate-600"/>
                                    <p className="text-xs font-black uppercase tracking-widest">Hộp thư đang trống</p>
                                </div>
                            ) : mails.map(m => (
                                <div 
                                    key={m.id} 
                                    onClick={() => handleReadMail(m)}
                                    className={`group flex items-center gap-4 p-5 hover:bg-slate-800/40 cursor-pointer transition-all border-l-4 ${m.is_read || view === 'SENT' ? 'border-transparent' : 'border-blue-600 bg-blue-600/5'}`}
                                >
                                    <div className="w-10 h-10 rounded-full border border-slate-700 overflow-hidden bg-slate-900 shrink-0">
                                        {(view === 'INBOX' ? m.sender_avatar : m.receiver_avatar) ? (
                                            <img src={getAvatarUrl(view === 'INBOX' ? m.sender_avatar : m.receiver_avatar)!} className="w-full h-full object-cover" />
                                        ) : (
                                            <div className="w-full h-full flex items-center justify-center text-[10px] font-black text-slate-500">{(view === 'INBOX' ? m.sender_name : m.receiver_name)?.charAt(0)}</div>
                                        )}
                                    </div>

                                    <div className="flex-1 overflow-hidden min-w-0">
                                        <div className="flex justify-between items-center mb-0.5">
                                            <p className={`text-xs uppercase tracking-tighter truncate ${m.is_read || view === 'SENT' ? 'text-slate-400 font-bold' : 'text-white font-black'}`}>
                                                {view === 'INBOX' ? m.sender_name : m.receiver_name}
                                            </p>
                                            <p className="text-[9px] font-bold text-slate-600 uppercase shrink-0 ml-4">{new Date(m.timestamp).toLocaleDateString()}</p>
                                        </div>
                                        <p className={`text-sm truncate ${m.is_read || view === 'SENT' ? 'text-slate-500' : 'text-slate-200'}`}>{m.content}</p>
                                    </div>

                                    <div className="opacity-0 group-hover:opacity-100 transition-opacity shrink-0">
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); handleDeleteMail(m.id); }}
                                            className="p-2 text-slate-600 hover:text-red-500 transition-colors"
                                        >
                                            <Trash2 size={16}/>
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            {/* --- SYSTEM DIALOG --- */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-slate-900 rounded-[2.5rem] w-full max-w-sm border border-slate-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'confirm' && <div className="w-14 h-14 bg-orange-500/20 text-orange-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}

                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>

                            <div className="flex gap-2 w-full">
                                {dialog.type === 'confirm' ? (
                                    <>
                                        <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="flex-1 py-3 bg-slate-800 hover:bg-slate-700 text-gray-400 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">HỦY BỎ</button>
                                        <button onClick={() => { setDialog({ ...dialog, isOpen: false }); dialog.onConfirm?.(); }} className="flex-1 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg transition-all">XÁC NHẬN</button>
                                    </>
                                ) : (
                                    <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg transition-all">OK</button>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

