                    >
                        <Plus size={18}/> Soạn thư mới
                    </button>

                    <div className="space-y-1">
                        <button 
                            onClick={() => { setView('INBOX'); setSelectedMail(null); }}
                            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${view === 'INBOX' ? 'bg-slate-800 text-blue-400' : 'text-slate-400 hover:bg-slate-800/50 hover:text-white'}`}
                        >
                            <Inbox size={18}/>
