                                >
                                    <div className="w-10 h-10 rounded-full border border-slate-700 overflow-hidden bg-slate-900 shrink-0">
                                        {/* Fix: Added support for receiver_avatar in SENT view */}
                                        {(view === 'INBOX' ? m.sender_avatar : m.receiver_avatar) ? (
                                            <img src={getAvatarUrl(view === 'INBOX' ? m.sender_avatar : m.receiver_avatar)!} className="w-full h-full object-cover" alt="avatar" />
