const getApiUrl = () => {
    const { hostname, protocol } = window.location;

    const isLocal = 
        hostname === 'localhost' || 
        hostname === '127.0.0.1' || 
        hostname.startsWith('192.168.') || 
        hostname.startsWith('10.') || 
        hostname.startsWith('172.');

    if (isLocal) {
        return `${protocol}//${hostname}:3004`;
    }

    return 'https://apigeo.gisvn.space'; 
};

export const API_URL = getApiUrl();

const getAuthHeaders = () => {
    const headers: any = {};
    const userStr = localStorage.getItem('geo_user');
    if (userStr) {
        try {
            const u = JSON.parse(userStr);
            headers['x-user-id'] = u.id;
            headers['x-user-name'] = encodeURIComponent(u.name);
            headers['x-branch-id'] = u.branchId || u.branch_id;
        } catch (e) {}
    }
    return headers;
};

const apiCall = async (endpoint: string, options?: RequestInit) => {
    const cleanEndpoint = endpoint.startsWith('/api') ? endpoint : `/api${endpoint}`;
    const finalUrl = `${API_URL}${cleanEndpoint}`;

    try {
        const headers: any = { 'Content-Type': 'application/json', ...getAuthHeaders(), ...options?.headers };

        if (options?.body instanceof FormData) delete headers['Content-Type'];

        const res = await fetch(finalUrl, { ...options, headers });
        const responseText = await res.text();

        let responseData: any = null;
        if (responseText) {
            try { responseData = JSON.parse(responseText); } catch (e) {}
        }

        if (!res.ok) {
            let errorMessage = `Lỗi hệ thống (${res.status})`;
            if (responseData && (responseData.error || responseData.message)) {
                errorMessage = responseData.error || responseData.message;
            }
            throw new Error(errorMessage);
        }

        return responseData || { status: 'ok' };
    } catch (error: any) {
        throw error;
    }
};

