    const handleReply = () => {
        if (!selectedMail) return;
        const replyContent = `\n\n--- Trả lời thư của ${selectedMail.sender_name} vào lúc ${new Date(selectedMail.timestamp).toLocaleString()} ---\n> ${selectedMail.content.split('\n').join('\n> ')}`;
