    // Hands & Gestures
    '👍', '👎', '👌', '✌️', '🤞', '🤙', '🖐️', '✋', '🖖', '🤝', '👏', '🙌', '🙏', '✍️', '🤳', '💪', '🦾', '👂', '👃', '🧠', '👀',
    // Work & Tools
    '📍', '📍', '🗺️', '🏢', '🏗️', '💼', '🤝', '📧', '🚀', '🎉', '💡', '📅', '📝', '📁', '📂', '📊', '📈', '📉', '📎', '📌', '📏', '📐', '✂️', '🔨', '🛠️', '⚙️', '⚖️', '⛓️', '🧰', '🔧', '📦', '🔔', '🔕', '📧', '📩', '📨', '📫', '📦', '✏️', '✒️', '💻', '⌨️', '🖥️', '🖨️', '🖱️', '💾', '💿', '📀',
