import React, { useState, useEffect, useRef } from 'react';
import QRCode from 'qrcode';
import { QrCode, Link as LinkIcon, Type, Phone, Download, Copy, RefreshCw, Check, Share2, Palette } from 'lucide-react';

const QRGenerator: React.FC = () => {
    const [inputType, setInputType] = useState<'URL' | 'TEXT' | 'PHONE'>('URL');
    const [inputValue, setInputValue] = useState('');
    const [qrColor, setQrColor] = useState('#000000');
    const [qrDataUrl, setQrDataUrl] = useState('');
    const [copied, setCopied] = useState(false);
    const canvasRef = useRef<HTMLCanvasElement>(null);

    const generateQR = async () => {
        if (!inputValue.trim()) {
            setQrDataUrl('');
            return;
        }

        let finalValue = inputValue;
        if (inputType === 'PHONE') {
            finalValue = `tel:${inputValue.replace(/[^0-9+]/g, '')}`;
        } else if (inputType === 'URL' && !inputValue.startsWith('http')) {
            finalValue = `https://${inputValue}`;
        }

        try {
            const url = await QRCode.toDataURL(finalValue, {
                width: 1024,
                margin: 2,
                color: {
                    dark: qrColor + 'ff',
                    light: '#ffffffff'
                },
                errorCorrectionLevel: 'H'
            });
            setQrDataUrl(url);
        } catch (err) {
            console.error(err);
        }
    };

    useEffect(() => {
        const timer = setTimeout(generateQR, 300);
        return () => clearTimeout(timer);
    }, [inputValue, inputType, qrColor]);

    const handleCopy = () => {
        if (!qrDataUrl) return;
        setCopied(true);
        // Trong thực tế, trình duyệt không hỗ trợ copy image trực tiếp dễ dàng như text, 
        // ở đây ta copy link base64 hoặc thông báo thành công khi lưu ảnh.
