                                        <div className="relative w-10 h-10 rounded-full overflow-hidden border-2 border-slate-700">
                                            <input 
                                                type="color" 
                                                value={qrColor} 
                                                onChange={(e) => setQrColor(e.target.value)}
                                                className="absolute inset-[-10px] w-[200%] h-[200%] cursor-pointer"
                                            />
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Preview QR */}
                    <div className="lg:col-span-2">
                        <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 shadow-2xl sticky top-8 flex flex-col items-center">
