import { Coordinate } from 'ol/coordinate';
import Draw from 'ol/interaction/Draw';
import { getArea, getLength } from 'ol/sphere';
import { unByKey } from 'ol/Observable';

proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const MapPage: React.FC<{ user: User | null; systemSettings?: Record<string, string> }> = ({ user, systemSettings }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const popupElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);

    const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const locationLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const measureSource = useRef<VectorSource>(new VectorSource());
    const wmsLayerGroup = useRef<LayerGroup | null>(null);
    const baseLayerRef = useRef<TileLayer<any> | null>(null);
    const overlayInstance = useRef<Overlay | null>(null);

    const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
    const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
    const [activeLayerId, setActiveLayerId] = useState<string | null>(null);

    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState<string>('');

    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);
    const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isQuerying, setIsQuerying] = useState(false);
    const [isLocating, setIsLocating] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [printingParcel, setPrintingParcel] = useState<LandParcel | null>(null);
    const [mapRotation, setMapRotation] = useState(0);
    const [mapZoom, setMapZoom] = useState(0);
    const [mouseCoord, setMouseCoord] = useState<Coordinate | null>(null);
    const [wmsCacheBust, setWmsCacheBust] = useState(Date.now());

    const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);
    const drawInteraction = useRef<Draw | null>(null);

    // Edit State
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [editFormData, setEditFormData] = useState<ParcelDTO>({ sothua: '', sodoto: '' });
    const [editLoading, setEditLoading] = useState(false);
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    const highlightStyle = new style.Style({
        stroke: new style.Stroke({ color: '#00ffff', width: 4 }),
        fill: new style.Fill({ color: 'rgba(0, 255, 255, 0.2)' }),
        image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#00ffff' }), stroke: new style.Stroke({color: '#ffffff', width: 2}) })
    });

    const locationStyle = (feature: any) => {
        const type = feature.get('type');
        if (type === 'accuracy') {
            return new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: 'rgba(59, 130, 246, 0.3)', width: 1 })
            });
        }
        if (type === 'search_result') {
            return new style.Style({
                image: new style.Icon({
                    anchor: [0.5, 1],
                    src: 'https://raw.githubusercontent.com/lucide-react/lucide/main/icons/map-pin.svg', 
                    color: '#ef4444',
                    scale: 2
                }),
                text: new style.Text({ text: '📍', scale: 2, offsetY: -10 })
            });
        }
        return new style.Style({
            image: new style.Circle({
                radius: 8,
                fill: new style.Fill({ color: '#3b82f6' }),
                stroke: new style.Stroke({ color: '#fff', width: 3 })
            })
        });
    };

    const measureStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.2)' }),
        stroke: new style.Stroke({ color: '#3b82f6', lineDash: [10, 10], width: 3 }),
        image: new style.Circle({ radius: 5, stroke: new style.Stroke({ color: '#3b82f6', width: 2 }), fill: new style.Fill({ color: '#fff' }) })
    });

    const smartMapProperties = (props: any) => {
        const findVal = (keys: string[]) => {
            for (const k of keys) {
                if (props[k] !== undefined && props[k] !== null && props[k] !== '') return props[k];
                const lower = k.toLowerCase();
                if (props[lower] !== undefined && props[lower] !== null && props[lower] !== '') return props[lower];
            }
            return null;
        };
        return {
            ...props,
            so_to: findVal(['sodoto', 'so_to', 'shbando', 'sh_ban_do', 'tobando', 'tờ']),
            so_thua: findVal(['sothua', 'so_thua', 'shthua', 'sh_thua', 'thửa']),
            ownerName: findVal(['tenchu', 'ten_chu', 'ten_chu_sd', 'owner']),
            area: parseFloat(findVal(['dientich', 'dien_tich', 'area']) || 0),
            landType: findVal(['loaidat', 'kyhieumucd', 'mucdich']) || 'N/A',
            address: findVal(['diachi', 'dia_chi', 'dc']) || ''
        };
    };

    const formatLength = (line: LineString) => {
        const length = getLength(line);
        return length > 100 ? (length / 1000).toFixed(2) + ' km' : length.toFixed(2) + ' m';
    };

    const formatArea = (polygon: Polygon) => {
        const area = getArea(polygon);
        return area > 10000 ? (area / 10000).toFixed(2) + ' ha' : area.toFixed(2) + ' m²';
    };

    const handlePrint = async (parcel: LandParcel) => {
        setIsPrinting(true);
        setPrintingParcel(parcel);
        setTimeout(async () => {
            const element = document.getElementById('print-template');
            if (!element) { setIsPrinting(false); setPrintingParcel(null); return; }
            try {
                const canvas = await html2canvas(element, { scale: 2.5, useCORS: true, logging: false, backgroundColor: '#ffffff' });
                const pdf = new jsPDF('p', 'mm', 'a4');
                const pdfWidth = pdf.internal.pageSize.getWidth();
                const pdfHeight = pdf.internal.pageSize.getHeight();
                const imgWidth = pdfWidth;
                const imgHeight = (canvas.height * pdfWidth) / canvas.width;
                let heightLeft = imgHeight;
                let position = 0;
                const imgData = canvas.toDataURL('image/jpeg', 1.0);
                pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
                heightLeft -= pdfHeight;
                while (heightLeft > 0) { position -= pdfHeight; pdf.addPage(); pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight); heightLeft -= pdfHeight; }
                pdf.save(`TrichLuc_To${parcel.properties.so_to}_Thua${parcel.properties.so_thua}.pdf`);
            } catch (error) { console.error("Print Error:", error); } finally { setIsPrinting(false); setPrintingParcel(null); }
        }, 1200);
    };

    // --- LOGIC CHỈNH SỬA ---
    const handleOpenEdit = (parcel: LandParcel) => {
        const p = parcel.properties;
        setEditFormData({
            gid: parcel.gid,
            sodoto: (p.so_to || '').toString(),
            sothua: (p.so_thua || '').toString(),
            tenchu: p.ownerName || '',
            diachi: p.address || '',
            loaidat: p.landType || '',
            dientich: p.area || 0,
            geometry: parcel.geometry,
            tableName: p.tableName, // Lấy tên bảng từ property lúc click
            file: null
        });
        setIsEditOpen(true);
    };

    const handleUpdateParcel = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!editFormData.tableName) return;

        setEditLoading(true);
        try {
            if (editFormData.file) {
                await parcelApi.createWithUpload(editFormData.tableName, editFormData);
            } else {
                await parcelApi.update(editFormData.tableName, editFormData.gid!, editFormData);
            }

            setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: 'Thông tin thửa đất đã được cập nhật.' });
            setIsEditOpen(false);
            overlayInstance.current?.setPosition(undefined);
            setSelectedParcel(null);
            highlightLayer.current?.getSource()?.clear();

            // Làm mới lớp WMS bằng cách đổi cache bust
            setWmsCacheBust(Date.now());
        } catch (err: any) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: err.message });
        } finally {
            setEditLoading(false);
        }
    };

    const handleSelectResult = useCallback((parcel: LandParcel, fallbackCoord?: Coordinate) => {
        if (!mapInstance.current || !highlightLayer.current) return;
        const normalizedParcel = { ...parcel, properties: smartMapProperties(parcel.properties) };
        setSelectedParcel(normalizedParcel);
        const source = highlightLayer.current.getSource();
        source?.clear();
        let popupPos = fallbackCoord;
        if (parcel.geometry) {
            try {
                const format = new GeoJSON();
                let firstCoord: any = null;
                if (parcel.geometry.type === 'Polygon') firstCoord = parcel.geometry.coordinates[0][0];
                else if (parcel.geometry.type === 'MultiPolygon') firstCoord = parcel.geometry.coordinates[0][0][0];
                else if (parcel.geometry.type === 'Point') firstCoord = parcel.geometry.coordinates;

                let dataProj = 'EPSG:4326';
                if (firstCoord) {
                    const x = Math.abs(firstCoord[0]);
                    const y = Math.abs(firstCoord[1]);
                    if (x > 2000000 || y > 2000000) dataProj = 'EPSG:3857';
                    else if (x > 300000 && x < 900000) dataProj = 'EPSG:9210';
                }
                const geometry = format.readGeometry(parcel.geometry, { dataProjection: dataProj, featureProjection: 'EPSG:3857' });
                if (geometry) {
                    const feature = new Feature({ geometry });
                    source?.addFeature(feature);
                    const extent = geometry.getExtent();
                    if (extent && !isExtentEmpty(extent)) {
                        popupPos = getExtentCenter(extent);
                        mapInstance.current.getView().fit(extent, { padding: [120, 120, 120, 120], duration: 800, maxZoom: 21 });
                    }
                }
            } catch (err) {}
        }
        if (popupPos) overlayInstance.current?.setPosition(popupPos);
    }, []);

    const handleActivateLayer = async (id: string) => {
        setActiveLayerId(id);
        if (!visibleLayerIds.includes(id)) setVisibleLayerIds(prev => [...prev, id]);
        const layer = availableLayers.find(l => l.id === id);
        if (layer && layer.type !== 'XYZ') {
            const tableName = layer.layers.includes(':') ? layer.layers.split(':')[1] : layer.layers;
            try {
                const res = await fetch(`${API_URL}/api/data/${tableName}/extent`);
                if (res.ok) {
                    const bounds = await res.json();
                    if (bounds && bounds.xmin !== undefined) {
                        let sourceProj = 'EPSG:4326';
                        if (Math.abs(bounds.xmin) > 100000) sourceProj = 'EPSG:9210';
                        const extent = proj.transformExtent([bounds.xmin, bounds.ymin, bounds.xmax, bounds.ymax], sourceProj, 'EPSG:3857');
                        if (mapInstance.current) mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000, maxZoom: 19 });
                    }
                }
            } catch (e) {}
        }
    };

    const handleSearchCoordinate = (lat: number, lon: number) => {
        const coords = proj.fromLonLat([lon, lat]);
        if (locationLayer.current) {
            const source = locationLayer.current.getSource();
            source?.getFeatures().forEach(f => { if (f.get('type') === 'search_result') source.removeFeature(f); });
            const feature = new Feature({ geometry: new Point(coords) });
            feature.set('type', 'search_result');
            source?.addFeature(feature);
        }
        mapInstance.current?.getView().animate({ center: coords, zoom: 18, duration: 1000 });
    };

    const initData = async () => {
        try {
            const [layers, tables, maps] = await Promise.all([
                gisService.getLayers().catch(() => []), 
                gisService.getSpatialTables().catch(() => []),
                gisService.getBasemaps().catch(() => [])
            ]);

            setAvailableLayers(layers);
            setVisibleLayerIds(layers.filter(l => l.visible).map(l => l.id));
            setSpatialTables(tables);
            setBasemaps(maps);
            const defMap = maps.find(m => m.isDefault) || maps[0];
            if (defMap) setActiveBasemapId(defMap.id);
            if (layers.length && !activeLayerId) setActiveLayerId(layers[0].id);
        } catch (e) { console.error(e); } finally { setIsInitialLoading(false); }
    };

    useEffect(() => {
        if (!mapElement.current || mapInstance.current) return;
        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }),
                new LayerGroup({ zIndex: 10 }),
                new VectorLayer({ source: new VectorSource(), zIndex: 10000, style: highlightStyle }),
                new VectorLayer({ source: new VectorSource(), zIndex: 20000, style: locationStyle }),
                new VectorLayer({ source: measureSource.current, zIndex: 30000, style: measureStyle }),
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 13, minZoom: 5, maxZoom: 22 }),
            controls: defaultControls({ attribution: false })
        });
        const layers = map.getLayers().getArray();
        baseLayerRef.current = layers[0] as TileLayer<any>;
        wmsLayerGroup.current = layers[1] as LayerGroup;
        highlightLayer.current = layers[2] as VectorLayer<VectorSource>;
        locationLayer.current = layers[3] as VectorLayer<VectorSource>;
        overlayInstance.current = new Overlay({ element: popupElement.current!, autoPan: { animation: { duration: 250 } }, positioning: 'bottom-center' });
        map.addOverlay(overlayInstance.current);

        map.on('singleclick', async (evt) => {
            if (measureMode) return; 
            const view = map.getView();
            const layers = wmsLayerGroup.current?.getLayers().getArray() || [];
            if (layers.length === 0) return;
            const targetConfig = availableLayers.find(l => l.id === activeLayerId);
            if (targetConfig?.type === 'XYZ') return;
            const targetLayer = (layers.find(l => l.get('layerId') === activeLayerId) || layers[layers.length - 1]) as TileLayer<any>;
            if (!targetLayer.getSource()?.getFeatureInfoUrl) return;
            const url = targetLayer.getSource().getFeatureInfoUrl(evt.coordinate, view.getResolution()!, view.getProjection(), { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 });
            if (url) {
                setIsQuerying(true);
                overlayInstance.current?.setPosition(undefined);
                setSelectedParcel(null);
                highlightLayer.current?.getSource()?.clear();
                try {
                    const res = await fetch(url);
                    const data = await res.json();
                    if (data.features?.length > 0) {
                        const f = data.features[0];
                        const tableName = targetConfig?.layers.includes(':') ? targetConfig.layers.split(':').pop() : targetConfig?.layers;
                        handleSelectResult({ 
                            id: f.id, 
                            gid: f.properties.gid || parseInt(f.id.split('.').pop()||'0'), 
                            geometry: f.geometry, 
                            properties: { ...f.properties, tableName } 
                        }, evt.coordinate);
                    }
                } catch (e) {} finally { setIsQuerying(false); }
            }
        });
        map.on('pointermove', (evt) => { if (!evt.dragging) setMouseCoord(proj.toLonLat(evt.coordinate)); });
        map.getView().on('change:rotation', () => setMapRotation(map.getView().getRotation()));
        map.getView().on('change:resolution', () => setMapZoom(map.getView().getZoom() || 0));
        const resizeObserver = new ResizeObserver(() => map.updateSize());
        resizeObserver.observe(mapElement.current);
        mapInstance.current = map;
        initData();
        return () => resizeObserver.disconnect();
    }, [handleSelectResult, measureMode, activeLayerId]);

    useEffect(() => {
        if (!mapInstance.current || !measureMode) { if (drawInteraction.current) mapInstance.current?.removeInteraction(drawInteraction.current); return; }
        const map = mapInstance.current;
        drawInteraction.current = new Draw({ source: measureSource.current, type: measureMode, style: measureStyle });
        map.addInteraction(drawInteraction.current);
        let listener: any;
        drawInteraction.current.on('drawstart', (evt) => {
            const feature = evt.feature;
            const tooltipElement = document.createElement('div');
            tooltipElement.className = 'bg-black/80 text-white px-2 py-1 rounded text-[10px] font-bold shadow-xl backdrop-blur-sm border border-white/20 pointer-events-none whitespace-nowrap';
            const tooltip = new Overlay({ element: tooltipElement, offset: [0, -15], positioning: 'bottom-center', stopEvent: false, insertFirst: false });
            map.addOverlay(tooltip);
            listener = feature.getGeometry()?.on('change', (evt: any) => {
                const geom = evt.target;
                let output = '';
                let tooltipCoord: Coordinate | undefined;
                if (geom instanceof Polygon) { output = formatArea(geom); tooltipCoord = geom.getInteriorPoint().getCoordinates(); }
                else if (geom instanceof LineString) { output = formatLength(geom); tooltipCoord = geom.getLastCoordinate(); }
                tooltipElement.innerHTML = output;
                if (tooltipCoord) tooltip.setPosition(tooltipCoord);
            });
        });
        drawInteraction.current.on('drawend', () => { if (listener) unByKey(listener); setMeasureMode(null); });
        return () => { if (drawInteraction.current) map.removeInteraction(drawInteraction.current); };
    }, [measureMode]);

    const handleClearMeasure = () => { measureSource.current.clear(); mapInstance.current?.getOverlays().getArray().filter(o => o !== overlayInstance.current).forEach(o => mapInstance.current?.removeOverlay(o)); };
    const handleZoomIn = () => { const view = mapInstance.current?.getView(); if (view) view.animate({ zoom: (view.getZoom() || 0) + 1, duration: 250 }); };
    const handleZoomOut = () => { const view = mapInstance.current?.getView(); if (view) view.animate({ zoom: (view.getZoom() || 0) - 1, duration: 250 }); };
    const handleResetRotation = () => mapInstance.current?.getView().animate({ rotation: 0, duration: 500 });
    const handleLocate = () => {
        if (!navigator.geolocation) return alert("Không hỗ trợ định vị.");
        setIsLocating(true);
        navigator.geolocation.getCurrentPosition( (pos) => {
                const coords = proj.fromLonLat([pos.coords.longitude, pos.coords.latitude]);
                if (locationLayer.current) {
                    const source = locationLayer.current.getSource();
                    source?.getFeatures().forEach(f => { const type = f.get('type'); if (type === 'accuracy' || type === 'position') source.removeFeature(f); });
                    source?.addFeature(new Feature({ geometry: new GeomCircle(coords, pos.coords.accuracy) }).set('type', 'accuracy') as any);
                    source?.addFeature(new Feature({ geometry: new Point(coords) }).set('type', 'position') as any);
                }
                mapInstance.current?.getView().animate({ center: coords, zoom: Math.max(18, mapInstance.current.getView().getZoom() || 0), duration: 1000 });
                setIsLocating(false);
            }, () => setIsLocating(false), { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 } );
    };

    useEffect(() => {
        if (!baseLayerRef.current || !activeBasemapId || basemaps.length === 0) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') {
            source = new OSM({ crossOrigin: 'anonymous' });
        } else {
            const rawUrl = config.url.startsWith('/') ? `${API_URL}${config.url}` : config.url;
            const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(rawUrl)}`
                .split('%7Bz%7D').join('{z}')
                .split('%7Bx%7D').join('{x}')
                .split('%7By%7D').join('{y}');
            source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
        }
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!wmsLayerGroup.current) return;
        const olLayers = availableLayers.filter(l => visibleLayerIds.includes(l.id)).map(config => {
            let source;
            if (config.type === 'XYZ') {
                const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`
                    .split('%7Bz%7D').join('{z}')
                    .split('%7Bx%7D').join('{x}')
                    .split('%7By%7D').join('{y}');

                source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
            } else {
                source = new TileWMS({ 
                    url: `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`, 
                    params: { 'LAYERS': config.layers, 'TILED': true, 'TRANSPARENT': true, 'FORMAT': 'image/png', 't': wmsCacheBust }, 
                    crossOrigin: 'anonymous' 
                });
            }

            let zIndex = 10;
            if (config.category === 'PLANNING') zIndex = 100;
            if (activeLayerId === config.id) zIndex += 50;

            const layer = new TileLayer({ source: source, opacity: Number(config.opacity ?? 1), zIndex: zIndex });
            layer.set('layerId', config.id);
            return layer;
        });
        wmsLayerGroup.current.setLayers(new Collection(olLayers));
    }, [availableLayers, visibleLayerIds, activeLayerId, wmsCacheBust]);

    return (
        <div className="relative w-full h-full bg-slate-950 flex flex-col min-h-0 overflow-hidden font-sans">
            {isInitialLoading && (
                <div className="absolute inset-0 z-[1000] bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={48} />
                    <p className="font-display uppercase tracking-[0.3em] text-[10px] text-blue-400 font-black animate-pulse">GeoMaster Engine Loading...</p>
                </div>
            )}

            {/* Query Loading Indicator */}
            {isQuerying && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 z-[400] bg-slate-900/90 backdrop-blur-md border border-blue-500/30 px-5 py-3 rounded-2xl shadow-[0_0_40px_rgba(37,99,235,0.3)] flex items-center gap-3 animate-in fade-in slide-in-from-bottom-4 duration-300">
                    <div className="relative">
                        <Loader2 className="animate-spin text-blue-500" size={20} />
                        <div className="absolute inset-0 flex items-center justify-center">
                            <div className="w-1.5 h-1.5 bg-white rounded-full animate-ping"></div>
                        </div>
                    </div>
                    <span className="text-[11px] font-black text-white uppercase tracking-[0.2em] whitespace-nowrap">Đang lấy thông tin thửa đất...</span>
                </div>
            )}

            <div className="absolute bottom-6 left-6 z-[400] flex flex-col gap-2 pointer-events-none">
                {mouseCoord && (
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-3 py-1.5 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300">
                        <div className="flex items-center gap-1.5 text-blue-400"><MousePointer2 size={12}/><span className="text-[9px] font-black uppercase tracking-[0.1em]">Tọa độ</span></div>
                        <div className="flex gap-4 font-mono text-[11px] font-bold text-gray-100">
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">X:</span><span>{mouseCoord[0].toFixed(6)}</span></div>
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">Y:</span><span>{mouseCoord[1].toFixed(6)}</span></div>
                        </div>
                    </div>
                )}
                <div className="w-fit bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-2.5 py-1 rounded-lg flex items-center gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Zoom: <span className="text-white ml-1">{Math.round(mapZoom)}</span></span>
                </div>
            </div>
            {isPrinting && ( <div className="absolute inset-0 z-[2000] bg-black/70 backdrop-blur-md flex flex-col items-center justify-center text-white gap-4"> <Printer className="animate-bounce text-orange-500" size={64} /> <div className="text-center"> <p className="font-display font-bold text-xl uppercase tracking-tighter">Đang xuất trích lục đa trang</p> </div> </div> )}
            <div ref={mapElement} className="flex-1 w-full relative" />
            <MeasureTools activeMode={measureMode} onModeChange={setMeasureMode} onClear={handleClearMeasure} />
            <div ref={popupElement} className="absolute bottom-0 left-0 pointer-events-none"> {selectedParcel && ( <div className="pointer-events-auto"> <ParcelPopup parcel={selectedParcel} user={user} onClose={() => { overlayInstance.current?.setPosition(undefined); setSelectedParcel(null); highlightLayer.current?.getSource()?.clear(); }} onPrint={handlePrint} onEdit={handleOpenEdit} /> </div> )} </div>
            <div className="fixed -left-[4000px] top-0 opacity-0 pointer-events-none overflow-hidden"> {printingParcel && <PrintTemplate parcel={printingParcel} user={user} systemSettings={systemSettings} />} </div>
            <div className="absolute bottom-6 right-6 z-[400] flex flex-col gap-3">
                {Math.abs(mapRotation) > 0.01 && ( <button onClick={handleResetRotation} className="p-3 bg-white rounded-full shadow-2xl text-orange-600 hover:bg-orange-50 transition-all"><Compass size={24} style={{ transform: `rotate(${-mapRotation}rad)` }}/></button> )}
                <div className="flex flex-col bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden"> <button onClick={handleZoomIn} className="p-3.5 text-gray-700 hover:bg-gray-50 border-b border-gray-100 transition-colors"><Plus size={20}/></button> <button onClick={handleZoomOut} className="p-3.5 text-gray-700 hover:bg-gray-50 transition-colors"><Minus size={20}/></button> </div>
                <button onClick={handleLocate} className={`p-3.5 rounded-full shadow-2xl text-white transition-all ${isLocating ? 'bg-gray-400' : 'bg-blue-600 hover:bg-blue-700'}`}><Crosshair size={24} className={isLocating ? "animate-spin" : ""}/></button>
            </div>
            <SearchPanel isOpen={isSearchOpen} onToggle={() => setIsSearchOpen(!isSearchOpen)} spatialTables={spatialTables} onSelectResult={p => handleSelectResult(p)} onSearchCoordinate={handleSearchCoordinate} />
            <LayerControl isOpen={isLayerMenuOpen} onToggleMenu={() => setIsLayerMenuOpen(!isLayerMenuOpen)} basemaps={basemaps} activeBasemapId={activeBasemapId} onBaseLayerChange={setActiveBasemapId} availableLayers={availableLayers} visibleLayerIds={visibleLayerIds} activeLayerId={activeLayerId} onToggleWMS={id => setVisibleLayerIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id])} onSetActiveWMS={handleActivateLayer} onOpacityChange={(id, opacity) => setAvailableLayers(prev => prev.map(l => l.id === id ? { ...l, opacity } : l))} />

            {/* Parcel Edit Modal */}
            <ParcelForm isOpen={isEditOpen} onClose={() => setIsEditOpen(false)} editingId={editFormData.gid || null} formData={editFormData} setFormData={setEditFormData} handleSubmit={handleUpdateParcel} loading={editLoading} />

            {/* System Dialog (MapPage specific) */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'info' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}
                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95">OK</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MapPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, LandParcel, WMSLayerConfig, BasemapConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { parcelApi, ParcelDTO } from '../services/parcelApi';
import { Loader2, Crosshair, Map as MapIcon, Layers as LayersIcon, Printer, Plus, Minus, Compass, AlertCircle, RefreshCw, Zap, Search, Fingerprint, MousePointer2, Navigation2, ArrowRight, MapPin, CheckCircle2, AlertTriangle, Info } from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

// Components
import ParcelPopup from '../components/map/ParcelPopup';
import SearchPanel from '../components/map/SearchPanel';
import LayerControl from '../components/map/LayerControl';
import PrintTemplate from '../components/map/PrintTemplate';
import MeasureTools from '../components/map/MeasureTools';
import ParcelForm from '../components/admin/parcel/ParcelForm';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import Overlay from 'ol/Overlay';
import Feature from 'ol/Feature';
import { Tile as TileLayer, Vector as VectorLayer, Group as LayerGroup } from 'ol/layer';
import { OSM, TileWMS, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Point, LineString, Polygon, Circle as GeomCircle } from 'ol/geom';
import GeoJSON from 'ol/format/GeoJSON';
import { defaults as defaultControls } from 'ol/control/defaults';
import Collection from 'ol/Collection';
import { isEmpty as isExtentEmpty, getCenter as getExtentCenter } from 'ol/extent';
import { Coordinate } from 'ol/coordinate';
import Draw from 'ol/interaction/Draw';
import { getArea, getLength } from 'ol/sphere';
import { unByKey } from 'ol/Observable';

proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const MapPage: React.FC<{ user: User | null; systemSettings?: Record<string, string> }> = ({ user, systemSettings }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const popupElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);

    const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const locationLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const measureSource = useRef<VectorSource>(new VectorSource());
    const wmsLayerGroup = useRef<LayerGroup | null>(null);
    const baseLayerRef = useRef<TileLayer<any> | null>(null);
    const overlayInstance = useRef<Overlay | null>(null);

    const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
    const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
    const [activeLayerId, setActiveLayerId] = useState<string | null>(null);

    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState<string>('');

    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);
    const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isQuerying, setIsQuerying] = useState(false);
    const [isLocating, setIsLocating] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [printingParcel, setPrintingParcel] = useState<LandParcel | null>(null);
    const [mapRotation, setMapRotation] = useState(0);
    const [mapZoom, setMapZoom] = useState(0);
    const [mouseCoord, setMouseCoord] = useState<Coordinate | null>(null);
    const [wmsCacheBust, setWmsCacheBust] = useState(Date.now());

    const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);
    const drawInteraction = useRef<Draw | null>(null);

    // Edit State
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [editFormData, setEditFormData] = useState<ParcelDTO>({ sothua: '', sodoto: '' });
    const [editLoading, setEditLoading] = useState(false);
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    const highlightStyle = new style.Style({
        stroke: new style.Stroke({ color: '#00ffff', width: 4 }),
        fill: new style.Fill({ color: 'rgba(0, 255, 255, 0.2)' }),
        image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#00ffff' }), stroke: new style.Stroke({color: '#ffffff', width: 2}) })
    });

    const locationStyle = (feature: any) => {
        const type = feature.get('type');
        if (type === 'accuracy') {
            return new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: 'rgba(59, 130, 246, 0.3)', width: 1 })
            });
        }
        if (type === 'search_result') {
            return new style.Style({
                image: new style.Icon({
                    anchor: [0.5, 1],
                    src: 'https://raw.githubusercontent.com/lucide-react/lucide/main/icons/map-pin.svg', 
                    color: '#ef4444',
                    scale: 2
                }),
                text: new style.Text({ text: '📍', scale: 2, offsetY: -10 })
            });
        }
        return new style.Style({
            image: new style.Circle({
                radius: 8,
                fill: new style.Fill({ color: '#3b82f6' }),
                stroke: new style.Stroke({ color: '#fff', width: 3 })
            })
        });
    };

    const measureStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.2)' }),
        stroke: new style.Stroke({ color: '#3b82f6', lineDash: [10, 10], width: 3 }),
        image: new style.Circle({ radius: 5, stroke: new style.Stroke({ color: '#3b82f6', width: 2 }), fill: new style.Fill({ color: '#fff' }) })
    });

    const smartMapProperties = (props: any) => {
        const findVal = (keys: string[]) => {
            for (const k of keys) {
                if (props[k] !== undefined && props[k] !== null && props[k] !== '') return props[k];
                const lower = k.toLowerCase();
                if (props[lower] !== undefined && props[lower] !== null && props[lower] !== '') return props[lower];
            }
            return null;
        };
        return {
            ...props,
            so_to: findVal(['sodoto', 'so_to', 'shbando', 'sh_ban_do', 'tobando', 'tờ']),
            so_thua: findVal(['sothua', 'so_thua', 'shthua', 'sh_thua', 'thửa']),
            ownerName: findVal(['tenchu', 'ten_chu', 'ten_chu_sd', 'owner']),
            area: parseFloat(findVal(['dientich', 'dien_tich', 'area']) || 0),
            landType: findVal(['loaidat', 'kyhieumucd', 'mucdich']) || 'N/A',
            address: findVal(['diachi', 'dia_chi', 'dc']) || ''
        };
    };

    const formatLength = (line: LineString) => {
        const length = getLength(line);
        return length > 100 ? (length / 1000).toFixed(2) + ' km' : length.toFixed(2) + ' m';
    };

    const formatArea = (polygon: Polygon) => {
        const area = getArea(polygon);
        return area > 10000 ? (area / 10000).toFixed(2) + ' ha' : area.toFixed(2) + ' m²';
    };

    const handlePrint = async (parcel: LandParcel) => {
        setIsPrinting(true);
        setPrintingParcel(parcel);
        setTimeout(async () => {
            const element = document.getElementById('print-template');
            if (!element) { setIsPrinting(false); setPrintingParcel(null); return; }
            try {
                const canvas = await html2canvas(element, { scale: 2.5, useCORS: true, logging: false, backgroundColor: '#ffffff' });
                const pdf = new jsPDF('p', 'mm', 'a4');
                const pdfWidth = pdf.internal.pageSize.getWidth();
                const pdfHeight = pdf.internal.pageSize.getHeight();
                const imgWidth = pdfWidth;
                const imgHeight = (canvas.height * pdfWidth) / canvas.width;
                let heightLeft = imgHeight;
                let position = 0;
                const imgData = canvas.toDataURL('image/jpeg', 1.0);
                pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
                heightLeft -= pdfHeight;
                while (heightLeft > 0) { position -= pdfHeight; pdf.addPage(); pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight); heightLeft -= pdfHeight; }
                pdf.save(`TrichLuc_To${parcel.properties.so_to}_Thua${parcel.properties.so_thua}.pdf`);
            } catch (error) { console.error("Print Error:", error); } finally { setIsPrinting(false); setPrintingParcel(null); }
        }, 1200);
    };

    // --- LOGIC CHỈNH SỬA ---
    const handleOpenEdit = (parcel: LandParcel) => {
        const p = parcel.properties;
        setEditFormData({
            gid: parcel.gid,
            sodoto: (p.so_to || '').toString(),
            sothua: (p.so_thua || '').toString(),
            tenchu: p.ownerName || '',
            diachi: p.address || '',
            loaidat: p.landType || '',
            dientich: p.area || 0,
            geometry: parcel.geometry,
            tableName: p.tableName, 
            file: null
        });
        setIsEditOpen(true);
    };

    const handleUpdateParcel = async (e: React.FormEvent) => {
        e.preventDefault();

        // Kiểm tra an toàn trước khi gọi API
        if (!editFormData.tableName) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi cấu hình', message: 'Không xác định được lớp dữ liệu gốc để cập nhật.' });
            return;
        }

        if (!editFormData.gid && !editFormData.file) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi dữ liệu', message: 'Mã định danh thửa đất (GID) không tồn tại.' });
            return;
        }

        setEditLoading(true);
        try {
            if (editFormData.file) {
                // Nếu có upload file mới (cập nhật hình học qua file)
                await parcelApi.createWithUpload(editFormData.tableName, editFormData);
            } else {
                // Cập nhật thông tin thuộc tính
                await parcelApi.update(editFormData.tableName, editFormData.gid!, editFormData);
            }

            setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: 'Thông tin thửa đất đã được cập nhật thành công.' });
            setIsEditOpen(false);

            // Xóa trạng thái chọn hiện tại để yêu cầu người dùng click lại lấy data mới
            overlayInstance.current?.setPosition(undefined);
            setSelectedParcel(null);
            highlightLayer.current?.getSource()?.clear();

            // Làm mới lớp WMS bằng cách đổi cache bust để xóa cache trình duyệt/Geoserver
            setWmsCacheBust(Date.now());
        } catch (err: any) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi cập nhật', message: err.message || 'Đã xảy ra lỗi trong quá trình lưu dữ liệu.' });
        } finally {
            setEditLoading(false);
        }
    };

    const handleSelectResult = useCallback((parcel: LandParcel, fallbackCoord?: Coordinate) => {
        if (!mapInstance.current || !highlightLayer.current) return;
        const normalizedParcel = { ...parcel, properties: smartMapProperties(parcel.properties) };
        setSelectedParcel(normalizedParcel);
        const source = highlightLayer.current.getSource();
        source?.clear();
        let popupPos = fallbackCoord;
        if (parcel.geometry) {
            try {
                const format = new GeoJSON();
                let firstCoord: any = null;
                if (parcel.geometry.type === 'Polygon') firstCoord = parcel.geometry.coordinates[0][0];
                else if (parcel.geometry.type === 'MultiPolygon') firstCoord = parcel.geometry.coordinates[0][0][0];
                else if (parcel.geometry.type === 'Point') firstCoord = parcel.geometry.coordinates;

                let dataProj = 'EPSG:4326';
                if (firstCoord) {
                    const x = Math.abs(firstCoord[0]);
                    const y = Math.abs(firstCoord[1]);
                    if (x > 2000000 || y > 2000000) dataProj = 'EPSG:3857';
                    else if (x > 300000 && x < 900000) dataProj = 'EPSG:9210';
                }
                const geometry = format.readGeometry(parcel.geometry, { dataProjection: dataProj, featureProjection: 'EPSG:3857' });
                if (geometry) {
                    const feature = new Feature({ geometry });
                    source?.addFeature(feature);
                    const extent = geometry.getExtent();
                    if (extent && !isExtentEmpty(extent)) {
                        popupPos = getExtentCenter(extent);
                        mapInstance.current.getView().fit(extent, { padding: [120, 120, 120, 120], duration: 800, maxZoom: 21 });
                    }
                }
            } catch (err) {}
        }
        if (popupPos) overlayInstance.current?.setPosition(popupPos);
    }, []);

    const handleActivateLayer = async (id: string) => {
        setActiveLayerId(id);
        if (!visibleLayerIds.includes(id)) setVisibleLayerIds(prev => [...prev, id]);
        const layer = availableLayers.find(l => l.id === id);
        if (layer && layer.type !== 'XYZ') {
            const tableName = layer.layers.includes(':') ? layer.layers.split(':').pop() : layer.layers;
            try {
                const res = await fetch(`${API_URL}/api/data/${tableName}/extent`);
                if (res.ok) {
                    const bounds = await res.json();
                    if (bounds && bounds.xmin !== undefined) {
                        let sourceProj = 'EPSG:4326';
                        if (Math.abs(bounds.xmin) > 100000) sourceProj = 'EPSG:9210';
                        const extent = proj.transformExtent([bounds.xmin, bounds.ymin, bounds.xmax, bounds.ymax], sourceProj, 'EPSG:3857');
                        if (mapInstance.current) mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000, maxZoom: 19 });
                    }
                }
            } catch (e) {}
        }
    };

    const handleSearchCoordinate = (lat: number, lon: number) => {
        const coords = proj.fromLonLat([lon, lat]);
        if (locationLayer.current) {
            const source = locationLayer.current.getSource();
            source?.getFeatures().forEach(f => { if (f.get('type') === 'search_result') source.removeFeature(f); });
            const feature = new Feature({ geometry: new Point(coords) });
            feature.set('type', 'search_result');
            source?.addFeature(feature);
        }
        mapInstance.current?.getView().animate({ center: coords, zoom: 18, duration: 1000 });
    };

    const initData = async () => {
        try {
            const [layers, tables, maps] = await Promise.all([
                gisService.getLayers().catch(() => []), 
                gisService.getSpatialTables().catch(() => []),
                gisService.getBasemaps().catch(() => [])
            ]);

            setAvailableLayers(layers);
            setVisibleLayerIds(layers.filter(l => l.visible).map(l => l.id));
            setSpatialTables(tables);
            setBasemaps(maps);
            const defMap = maps.find(m => m.isDefault) || maps[0];
            if (defMap) setActiveBasemapId(defMap.id);
            if (layers.length && !activeLayerId) setActiveLayerId(layers[0].id);
        } catch (e) { console.error(e); } finally { setIsInitialLoading(false); }
    };

    useEffect(() => {
        if (!mapElement.current || mapInstance.current) return;
        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }),
                new LayerGroup({ zIndex: 10 }),
                new VectorLayer({ source: new VectorSource(), zIndex: 10000, style: highlightStyle }),
                new VectorLayer({ source: new VectorSource(), zIndex: 20000, style: locationStyle }),
                new VectorLayer({ source: measureSource.current, zIndex: 30000, style: measureStyle }),
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 13, minZoom: 5, maxZoom: 22 }),
            controls: defaultControls({ attribution: false })
        });
        const layers = map.getLayers().getArray();
        baseLayerRef.current = layers[0] as TileLayer<any>;
        wmsLayerGroup.current = layers[1] as LayerGroup;
        highlightLayer.current = layers[2] as VectorLayer<VectorSource>;
        locationLayer.current = layers[3] as VectorLayer<VectorSource>;
        overlayInstance.current = new Overlay({ element: popupElement.current!, autoPan: { animation: { duration: 250 } }, positioning: 'bottom-center' });
        map.addOverlay(overlayInstance.current);

        map.on('singleclick', async (evt) => {
            if (measureMode) return; 
            const view = map.getView();
            const layers = wmsLayerGroup.current?.getLayers().getArray() || [];
            if (layers.length === 0) return;
            const targetConfig = availableLayers.find(l => l.id === activeLayerId);
            if (targetConfig?.type === 'XYZ') return;
            const targetLayer = (layers.find(l => l.get('layerId') === activeLayerId) || layers[layers.length - 1]) as TileLayer<any>;
            if (!targetLayer.getSource()?.getFeatureInfoUrl) return;
            const url = targetLayer.getSource().getFeatureInfoUrl(evt.coordinate, view.getResolution()!, view.getProjection(), { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 });
            if (url) {
                setIsQuerying(true);
                overlayInstance.current?.setPosition(undefined);
                setSelectedParcel(null);
                highlightLayer.current?.getSource()?.clear();
                try {
                    const res = await fetch(url);
                    const data = await res.json();
                    if (data.features?.length > 0) {
                        const f = data.features[0];
                        const tableName = targetConfig?.layers.includes(':') ? targetConfig.layers.split(':').pop() : targetConfig?.layers;
                        handleSelectResult({ 
                            id: f.id, 
                            gid: f.properties.gid || parseInt(f.id.split('.').pop()||'0'), 
                            geometry: f.geometry, 
                            properties: { ...f.properties, tableName } 
                        }, evt.coordinate);
                    }
                } catch (e) {} finally { setIsQuerying(false); }
            }
        });
        map.on('pointermove', (evt) => { if (!evt.dragging) setMouseCoord(proj.toLonLat(evt.coordinate)); });
        map.getView().on('change:rotation', () => setMapRotation(map.getView().getRotation()));
        map.getView().on('change:resolution', () => setMapZoom(map.getView().getZoom() || 0));
        const resizeObserver = new ResizeObserver(() => map.updateSize());
        resizeObserver.observe(mapElement.current);
        mapInstance.current = map;
        initData();
        return () => resizeObserver.disconnect();
    }, [handleSelectResult, measureMode, activeLayerId]);

    useEffect(() => {
        if (!mapInstance.current || !measureMode) { if (drawInteraction.current) mapInstance.current?.removeInteraction(drawInteraction.current); return; }
        const map = mapInstance.current;
        drawInteraction.current = new Draw({ source: measureSource.current, type: measureMode, style: measureStyle });
        map.addInteraction(drawInteraction.current);
        let listener: any;
        drawInteraction.current.on('drawstart', (evt) => {
            const feature = evt.feature;
            const tooltipElement = document.createElement('div');
            tooltipElement.className = 'bg-black/80 text-white px-2 py-1 rounded text-[10px] font-bold shadow-xl backdrop-blur-sm border border-white/20 pointer-events-none whitespace-nowrap';
            const tooltip = new Overlay({ element: tooltipElement, offset: [0, -15], positioning: 'bottom-center', stopEvent: false, insertFirst: false });
            map.addOverlay(tooltip);
            listener = feature.getGeometry()?.on('change', (evt: any) => {
                const geom = evt.target;
                let output = '';
                let tooltipCoord: Coordinate | undefined;
                if (geom instanceof Polygon) { output = formatArea(geom); tooltipCoord = geom.getInteriorPoint().getCoordinates(); }
                else if (geom instanceof LineString) { output = formatLength(geom); tooltipCoord = geom.getLastCoordinate(); }
                tooltipElement.innerHTML = output;
                if (tooltipCoord) tooltip.setPosition(tooltipCoord);
            });
        });
        drawInteraction.current.on('drawend', () => { if (listener) unByKey(listener); setMeasureMode(null); });
        return () => { if (drawInteraction.current) map.removeInteraction(drawInteraction.current); };
    }, [measureMode]);

    const handleClearMeasure = () => { measureSource.current.clear(); mapInstance.current?.getOverlays().getArray().filter(o => o !== overlayInstance.current).forEach(o => mapInstance.current?.removeOverlay(o)); };
    const handleZoomIn = () => { const view = mapInstance.current?.getView(); if (view) view.animate({ zoom: (view.getZoom() || 0) + 1, duration: 250 }); };
    const handleZoomOut = () => { const view = mapInstance.current?.getView(); if (view) view.animate({ zoom: (view.getZoom() || 0) - 1, duration: 250 }); };
    const handleResetRotation = () => mapInstance.current?.getView().animate({ rotation: 0, duration: 500 });
    const handleLocate = () => {
        if (!navigator.geolocation) return alert("Không hỗ trợ định vị.");
        setIsLocating(true);
        navigator.geolocation.getCurrentPosition( (pos) => {
                const coords = proj.fromLonLat([pos.coords.longitude, pos.coords.latitude]);
                if (locationLayer.current) {
                    const source = locationLayer.current.getSource();
                    source?.getFeatures().forEach(f => { const type = f.get('type'); if (type === 'accuracy' || type === 'position') source.removeFeature(f); });
                    source?.addFeature(new Feature({ geometry: new GeomCircle(coords, pos.coords.accuracy) }).set('type', 'accuracy') as any);
                    source?.addFeature(new Feature({ geometry: new Point(coords) }).set('type', 'position') as any);
                }
                mapInstance.current?.getView().animate({ center: coords, zoom: Math.max(18, mapInstance.current.getView().getZoom() || 0), duration: 1000 });
                setIsLocating(false);
            }, () => setIsLocating(false), { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 } );
    };

    useEffect(() => {
        if (!baseLayerRef.current || !activeBasemapId || basemaps.length === 0) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') {
            source = new OSM({ crossOrigin: 'anonymous' });
        } else {
            const rawUrl = config.url.startsWith('/') ? `${API_URL}${config.url}` : config.url;
            const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(rawUrl)}`
                .split('%7Bz%7D').join('{z}')
                .split('%7Bx%7D').join('{x}')
                .split('%7By%7D').join('{y}');
            source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
        }
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!wmsLayerGroup.current) return;
        const olLayers = availableLayers.filter(l => visibleLayerIds.includes(l.id)).map(config => {
            let source;
            if (config.type === 'XYZ') {
                const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`
                    .split('%7Bz%7D').join('{z}')
                    .split('%7Bx%7D').join('{x}')
                    .split('%7By%7D').join('{y}');

                source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
            } else {
                source = new TileWMS({ 
                    url: `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`, 
                    params: { 'LAYERS': config.layers, 'TILED': true, 'TRANSPARENT': true, 'FORMAT': 'image/png', 't': wmsCacheBust }, 
                    crossOrigin: 'anonymous' 
                });
            }

            let zIndex = 10;
            if (config.category === 'PLANNING') zIndex = 100;
            if (activeLayerId === config.id) zIndex += 50;

            const layer = new TileLayer({ source: source, opacity: Number(config.opacity ?? 1), zIndex: zIndex });
            layer.set('layerId', config.id);
            return layer;
        });
        wmsLayerGroup.current.setLayers(new Collection(olLayers));
    }, [availableLayers, visibleLayerIds, activeLayerId, wmsCacheBust]);

    return (
        <div className="relative w-full h-full bg-slate-950 flex flex-col min-h-0 overflow-hidden font-sans">
            {isInitialLoading && (
                <div className="absolute inset-0 z-[1000] bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={48} />
                    <p className="font-display uppercase tracking-[0.3em] text-[10px] text-blue-400 font-black animate-pulse">GeoMaster Engine Loading...</p>
                </div>
            )}

            {/* Query Loading Indicator */}
            {isQuerying && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 z-[400] bg-slate-900/90 backdrop-blur-md border border-blue-500/30 px-5 py-3 rounded-2xl shadow-[0_0_40px_rgba(37,99,235,0.3)] flex items-center gap-3 animate-in fade-in slide-in-from-bottom-4 duration-300">
                    <div className="relative">
                        <Loader2 className="animate-spin text-blue-500" size={20} />
                        <div className="absolute inset-0 flex items-center justify-center">
                            <div className="w-1.5 h-1.5 bg-white rounded-full animate-ping"></div>
                        </div>
                    </div>
                    <span className="text-[11px] font-black text-white uppercase tracking-[0.2em] whitespace-nowrap">Đang lấy thông tin thửa đất...</span>
                </div>
            )}

            <div className="absolute bottom-6 left-6 z-[400] flex flex-col gap-2 pointer-events-none">
                {mouseCoord && (
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-3 py-1.5 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300">
                        <div className="flex items-center gap-1.5 text-blue-400"><MousePointer2 size={12}/><span className="text-[9px] font-black uppercase tracking-[0.1em]">Tọa độ</span></div>
                        <div className="flex gap-4 font-mono text-[11px] font-bold text-gray-100">
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">X:</span><span>{mouseCoord[0].toFixed(6)}</span></div>
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">Y:</span><span>{mouseCoord[1].toFixed(6)}</span></div>
                        </div>
                    </div>
                )}
                <div className="w-fit bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-2.5 py-1 rounded-lg flex items-center gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Zoom: <span className="text-white ml-1">{Math.round(mapZoom)}</span></span>
                </div>
            </div>
            {isPrinting && ( <div className="absolute inset-0 z-[2000] bg-black/70 backdrop-blur-md flex flex-col items-center justify-center text-white gap-4"> <Printer className="animate-bounce text-orange-500" size={64} /> <div className="text-center"> <p className="font-display font-bold text-xl uppercase tracking-tighter">Đang xuất trích lục đa trang</p> </div> </div> )}
            <div ref={mapElement} className="flex-1 w-full relative" />
            <MeasureTools activeMode={measureMode} onModeChange={setMeasureMode} onClear={handleClearMeasure} />
            <div ref={popupElement} className="absolute bottom-0 left-0 pointer-events-none"> {selectedParcel && ( <div className="pointer-events-auto"> <ParcelPopup parcel={selectedParcel} user={user} onClose={() => { overlayInstance.current?.setPosition(undefined); setSelectedParcel(null); highlightLayer.current?.getSource()?.clear(); }} onPrint={handlePrint} onEdit={handleOpenEdit} /> </div> )} </div>
            <div className="fixed -left-[4000px] top-0 opacity-0 pointer-events-none overflow-hidden"> {printingParcel && <PrintTemplate parcel={printingParcel} user={user} systemSettings={systemSettings} />} </div>
            <div className="absolute bottom-6 right-6 z-[400] flex flex-col gap-3">
                {Math.abs(mapRotation) > 0.01 && ( <button onClick={handleResetRotation} className="p-3 bg-white rounded-full shadow-2xl text-orange-600 hover:bg-orange-50 transition-all"><Compass size={24} style={{ transform: `rotate(${-mapRotation}rad)` }}/></button> )}
                <div className="flex flex-col bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden"> <button onClick={handleZoomIn} className="p-3.5 text-gray-700 hover:bg-gray-50 border-b border-gray-100 transition-colors"><Plus size={20}/></button> <button onClick={handleZoomOut} className="p-3.5 text-gray-700 hover:bg-gray-50 transition-colors"><Minus size={20}/></button> </div>
                <button onClick={handleLocate} className={`p-3.5 rounded-full shadow-2xl text-white transition-all ${isLocating ? 'bg-gray-400' : 'bg-blue-600 hover:bg-blue-700'}`}><Crosshair size={24} className={isLocating ? "animate-spin" : ""}/></button>
            </div>
            <SearchPanel isOpen={isSearchOpen} onToggle={() => setIsSearchOpen(!isSearchOpen)} spatialTables={spatialTables} onSelectResult={p => handleSelectResult(p)} onSearchCoordinate={handleSearchCoordinate} />
            <LayerControl isOpen={isLayerMenuOpen} onToggleMenu={() => setIsLayerMenuOpen(!isLayerMenuOpen)} basemaps={basemaps} activeBasemapId={activeBasemapId} onBaseLayerChange={setActiveBasemapId} availableLayers={availableLayers} visibleLayerIds={visibleLayerIds} activeLayerId={activeLayerId} onToggleWMS={id => setVisibleLayerIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id])} onSetActiveWMS={handleActivateLayer} onOpacityChange={(id, opacity) => setAvailableLayers(prev => prev.map(l => l.id === id ? { ...l, opacity } : l))} />

            {/* Parcel Edit Modal */}
            <ParcelForm isOpen={isEditOpen} onClose={() => setIsEditOpen(false)} editingId={editFormData.gid || null} formData={editFormData} setFormData={setEditFormData} handleSubmit={handleUpdateParcel} loading={editLoading} />

            {/* System Dialog (MapPage specific) */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'info' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}
                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95">OK</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MapPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, LandParcel, WMSLayerConfig, BasemapConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { parcelApi, ParcelDTO } from '../services/parcelApi';
import { Loader2, Crosshair, Map as MapIcon, Layers as LayersIcon, Printer, Plus, Minus, Compass, AlertCircle, RefreshCw, Zap, Search, Fingerprint, MousePointer2, Navigation2, ArrowRight, MapPin, CheckCircle2, AlertTriangle, Info } from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

// Components
import ParcelPopup from '../components/map/ParcelPopup';
import SearchPanel from '../components/map/SearchPanel';
import LayerControl from '../components/map/LayerControl';
import PrintTemplate from '../components/map/PrintTemplate';
import MeasureTools from '../components/map/MeasureTools';
import ParcelForm from '../components/admin/parcel/ParcelForm';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import Overlay from 'ol/Overlay';
import Feature from 'ol/Feature';
import { Tile as TileLayer, Vector as VectorLayer, Group as LayerGroup } from 'ol/layer';
import { OSM, TileWMS, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Point, LineString, Polygon, Circle as GeomCircle } from 'ol/geom';
import GeoJSON from 'ol/format/GeoJSON';
import { defaults as defaultControls } from 'ol/control/defaults';
import Collection from 'ol/Collection';
import { isEmpty as isExtentEmpty, getCenter as getExtentCenter } from 'ol/extent';
import { Coordinate } from 'ol/coordinate';
import Draw from 'ol/interaction/Draw';
import { getArea, getLength } from 'ol/sphere';
import { unByKey } from 'ol/Observable';

proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const MapPage: React.FC<{ user: User | null; systemSettings?: Record<string, string> }> = ({ user, systemSettings }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const popupElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);

    // Refs for Map Events (Anti-stale closures)
    const activeLayerIdRef = useRef<string | null>(null);
    const availableLayersRef = useRef<WMSLayerConfig[]>([]);

    const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const locationLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const measureSource = useRef<VectorSource>(new VectorSource());
    const wmsLayerGroup = useRef<LayerGroup | null>(null);
    const baseLayerRef = useRef<TileLayer<any> | null>(null);
    const overlayInstance = useRef<Overlay | null>(null);

    const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
    const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
    const [activeLayerId, setActiveLayerId] = useState<string | null>(null);

    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState<string>('');

    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);
    const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isQuerying, setIsQuerying] = useState(false);
    const [isLocating, setIsLocating] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [printingParcel, setPrintingParcel] = useState<LandParcel | null>(null);
    const [mapRotation, setMapRotation] = useState(0);
    const [mapZoom, setMapZoom] = useState(0);
    const [mouseCoord, setMouseCoord] = useState<Coordinate | null>(null);
    const [wmsCacheBust, setWmsCacheBust] = useState(Date.now());

    const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);
    const measureModeRef = useRef<'LineString' | 'Polygon' | null>(null);
    const drawInteraction = useRef<Draw | null>(null);

    // Edit State
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [editFormData, setEditFormData] = useState<ParcelDTO>({ sothua: '', sodoto: '' });
    const [editLoading, setEditLoading] = useState(false);
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Sync state to refs for map event usage
    useEffect(() => { availableLayersRef.current = availableLayers; }, [availableLayers]);
    useEffect(() => { activeLayerIdRef.current = activeLayerId; }, [activeLayerId]);
    useEffect(() => { measureModeRef.current = measureMode; }, [measureMode]);

    const highlightStyle = new style.Style({
        stroke: new style.Stroke({ color: '#00ffff', width: 4 }),
        fill: new style.Fill({ color: 'rgba(0, 255, 255, 0.2)' }),
        image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#00ffff' }), stroke: new style.Stroke({color: '#ffffff', width: 2}) })
    });

    const locationStyle = (feature: any) => {
        const type = feature.get('type');
        if (type === 'accuracy') {
            return new style.Style({
                fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }),
                stroke: new style.Stroke({ color: 'rgba(59, 130, 246, 0.3)', width: 1 })
            });
        }
        if (type === 'search_result') {
            return new style.Style({
                image: new style.Icon({ anchor: [0.5, 1], src: 'https://raw.githubusercontent.com/lucide-react/lucide/main/icons/map-pin.svg', color: '#ef4444', scale: 2 }),
                text: new style.Text({ text: '📍', scale: 2, offsetY: -10 })
            });
        }
        return new style.Style({
            image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#3b82f6' }), stroke: new style.Stroke({ color: '#fff', width: 3 }) })
        });
    };

    const measureStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.2)' }),
        stroke: new style.Stroke({ color: '#3b82f6', lineDash: [10, 10], width: 3 }),
        image: new style.Circle({ radius: 5, stroke: new style.Stroke({ color: '#3b82f6', width: 2 }), fill: new style.Fill({ color: '#fff' }) })
    });

    const smartMapProperties = (props: any) => {
        const findVal = (keys: string[]) => {
            for (const k of keys) {
                if (props[k] !== undefined && props[k] !== null && props[k] !== '') return props[k];
                const lower = k.toLowerCase();
                if (props[lower] !== undefined && props[lower] !== null && props[lower] !== '') return props[lower];
            }
            return null;
        };
        return {
            ...props,
            so_to: findVal(['sodoto', 'so_to', 'shbando', 'sh_ban_do', 'tobando', 'tờ']),
            so_thua: findVal(['sothua', 'so_thua', 'shthua', 'sh_thua', 'thửa']),
            ownerName: findVal(['tenchu', 'ten_chu', 'ten_chu_sd', 'owner']),
            area: parseFloat(findVal(['dientich', 'dien_tich', 'area']) || 0),
            landType: findVal(['loaidat', 'kyhieumucd', 'mucdich']) || 'N/A',
            address: findVal(['diachi', 'dia_chi', 'dc']) || ''
        };
    };

    const formatLength = (line: LineString) => {
        const length = getLength(line);
        return length > 100 ? (length / 1000).toFixed(2) + ' km' : length.toFixed(2) + ' m';
    };

    const formatArea = (polygon: Polygon) => {
        const area = getArea(polygon);
        return area > 10000 ? (area / 10000).toFixed(2) + ' ha' : area.toFixed(2) + ' m²';
    };

    const handlePrint = async (parcel: LandParcel) => {
        setIsPrinting(true);
        setPrintingParcel(parcel);
        setTimeout(async () => {
            const element = document.getElementById('print-template');
            if (!element) { setIsPrinting(false); setPrintingParcel(null); return; }
            try {
                const canvas = await html2canvas(element, { scale: 2.5, useCORS: true, logging: false, backgroundColor: '#ffffff' });
                const pdf = new jsPDF('p', 'mm', 'a4');
                const pdfWidth = pdf.internal.pageSize.getWidth();
                const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
                const imgData = canvas.toDataURL('image/jpeg', 1.0);
                pdf.addImage(imgData, 'JPEG', 0, 0, pdfWidth, pdfHeight);
                pdf.save(`TrichLuc_To${parcel.properties.so_to}_Thua${parcel.properties.so_thua}.pdf`);
            } catch (error) { console.error("Print Error:", error); } finally { setIsPrinting(false); setPrintingParcel(null); }
        }, 1200);
    };

    // --- LOGIC CHỈNH SỬA ---
    const handleOpenEdit = (parcel: LandParcel) => {
        const p = parcel.properties;
        setEditFormData({
            gid: parcel.gid,
            sodoto: (p.so_to || '').toString(),
            sothua: (p.so_thua || '').toString(),
            tenchu: p.ownerName || '',
            diachi: p.address || '',
            loaidat: p.landType || '',
            dientich: p.area || 0,
            geometry: parcel.geometry,
            tableName: p.tableName, 
            file: null
        });
        setIsEditOpen(true);
    };

    const handleUpdateParcel = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!editFormData.tableName) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi cấu hình', message: 'Không xác định được lớp dữ liệu gốc để cập nhật.' });
            return;
        }

        setEditLoading(true);
        try {
            if (editFormData.file) {
                await parcelApi.createWithUpload(editFormData.tableName, editFormData);
            } else {
                await parcelApi.update(editFormData.tableName, editFormData.gid!, editFormData);
            }

            setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: 'Thông tin thửa đất đã được cập nhật thành công.' });
            setIsEditOpen(false);

            overlayInstance.current?.setPosition(undefined);
            setSelectedParcel(null);
            highlightLayer.current?.getSource()?.clear();
            setWmsCacheBust(Date.now()); // Refresh WMS
        } catch (err: any) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi cập nhật', message: err.message || 'Đã xảy ra lỗi khi lưu dữ liệu.' });
        } finally {
            setEditLoading(false);
        }
    };

    const handleSelectResult = useCallback((parcel: LandParcel, fallbackCoord?: Coordinate) => {
        if (!mapInstance.current || !highlightLayer.current) return;
        const normalizedParcel = { ...parcel, properties: smartMapProperties(parcel.properties) };
        setSelectedParcel(normalizedParcel);
        const source = highlightLayer.current.getSource();
        source?.clear();
        let popupPos = fallbackCoord;
        if (parcel.geometry) {
            try {
                const format = new GeoJSON();
                let firstCoord: any = null;
                if (parcel.geometry.type === 'Polygon') firstCoord = parcel.geometry.coordinates[0][0];
                else if (parcel.geometry.type === 'MultiPolygon') firstCoord = parcel.geometry.coordinates[0][0][0];
                else if (parcel.geometry.type === 'Point') firstCoord = parcel.geometry.coordinates;

                let dataProj = 'EPSG:4326';
                if (firstCoord) {
                    const x = Math.abs(firstCoord[0]);
                    const y = Math.abs(firstCoord[1]);
                    if (x > 2000000 || y > 2000000) dataProj = 'EPSG:3857';
                    else if (x > 300000 && x < 900000) dataProj = 'EPSG:9210';
                }
                const geometry = format.readGeometry(parcel.geometry, { dataProjection: dataProj, featureProjection: 'EPSG:3857' });
                if (geometry) {
                    const feature = new Feature({ geometry });
                    source?.addFeature(feature);
                    const extent = geometry.getExtent();
                    if (extent && !isExtentEmpty(extent)) {
                        popupPos = getExtentCenter(extent);
                        mapInstance.current.getView().fit(extent, { padding: [120, 120, 120, 120], duration: 800, maxZoom: 21 });
                    }
                }
            } catch (err) {}
        }
        if (popupPos) overlayInstance.current?.setPosition(popupPos);
    }, []);

    const handleActivateLayer = async (id: string) => {
        setActiveLayerId(id);
        if (!visibleLayerIds.includes(id)) setVisibleLayerIds(prev => [...prev, id]);
        const layer = availableLayers.find(l => l.id === id);
        if (layer && layer.type !== 'XYZ') {
            const tableName = layer.layers.includes(':') ? layer.layers.split(':')[1] : layer.layers;
            try {
                const res = await fetch(`${API_URL}/api/data/${tableName}/extent`);
                if (res.ok) {
                    const bounds = await res.json();
                    if (bounds && bounds.xmin !== undefined) {
                        let sourceProj = 'EPSG:4326';
                        if (Math.abs(bounds.xmin) > 100000) sourceProj = 'EPSG:9210';
                        const extent = proj.transformExtent([bounds.xmin, bounds.ymin, bounds.xmax, bounds.ymax], sourceProj, 'EPSG:3857');
                        if (mapInstance.current) mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000, maxZoom: 19 });
                    }
                }
            } catch (e) {}
        }
    };

    const handleSearchCoordinate = (lat: number, lon: number) => {
        const coords = proj.fromLonLat([lon, lat]);
        if (locationLayer.current) {
            const source = locationLayer.current.getSource();
            source?.getFeatures().forEach(f => { if (f.get('type') === 'search_result') source.removeFeature(f); });
            const feature = new Feature({ geometry: new Point(coords) });
            feature.set('type', 'search_result');
            source?.addFeature(feature);
        }
        mapInstance.current?.getView().animate({ center: coords, zoom: 18, duration: 1000 });
    };

    const initData = async () => {
        try {
            const [layers, tables, maps] = await Promise.all([
                gisService.getLayers().catch(() => []), 
                gisService.getSpatialTables().catch(() => []),
                gisService.getBasemaps().catch(() => [])
            ]);

            setAvailableLayers(layers);
            availableLayersRef.current = layers; // Init ref
            setVisibleLayerIds(layers.filter(l => l.visible).map(l => l.id));
            setSpatialTables(tables);
            setBasemaps(maps);
            const defMap = maps.find(m => m.isDefault) || maps[0];
            if (defMap) setActiveBasemapId(defMap.id);
            if (layers.length && !activeLayerId) {
                setActiveLayerId(layers[0].id);
                activeLayerIdRef.current = layers[0].id;
            }
        } catch (e) { console.error(e); } finally { setIsInitialLoading(false); }
    };

    useEffect(() => {
        if (!mapElement.current || mapInstance.current) return;
        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }),
                new LayerGroup({ zIndex: 10 }),
                new VectorLayer({ source: new VectorSource(), zIndex: 10000, style: highlightStyle }),
                new VectorLayer({ source: new VectorSource(), zIndex: 20000, style: locationStyle }),
                new VectorLayer({ source: measureSource.current, zIndex: 30000, style: measureStyle }),
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 13, minZoom: 5, maxZoom: 22 }),
            controls: defaultControls({ attribution: false })
        });
        const layers = map.getLayers().getArray();
        baseLayerRef.current = layers[0] as TileLayer<any>;
        wmsLayerGroup.current = layers[1] as LayerGroup;
        highlightLayer.current = layers[2] as VectorLayer<VectorSource>;
        locationLayer.current = layers[3] as VectorLayer<VectorSource>;
        overlayInstance.current = new Overlay({ element: popupElement.current!, autoPan: { animation: { duration: 250 } }, positioning: 'bottom-center' });
        map.addOverlay(overlayInstance.current);

        map.on('singleclick', async (evt) => {
            // Using REF values to avoid stale closures
            if (measureModeRef.current) return; 

            const view = map.getView();
            const layers = wmsLayerGroup.current?.getLayers().getArray() || [];
            if (layers.length === 0) return;

            const targetConfig = availableLayersRef.current.find(l => l.id === activeLayerIdRef.current);
            if (!targetConfig || targetConfig.type === 'XYZ') return;

            const targetLayer = layers.find(l => l.get('layerId') === activeLayerIdRef.current) as TileLayer<any>;
            if (!targetLayer || !targetLayer.getSource()?.getFeatureInfoUrl) return;

            const url = targetLayer.getSource().getFeatureInfoUrl(evt.coordinate, view.getResolution()!, view.getProjection(), { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 });
            if (url) {
                setIsQuerying(true);
                overlayInstance.current?.setPosition(undefined);
                setSelectedParcel(null);
                highlightLayer.current?.getSource()?.clear();
                try {
                    const res = await fetch(url);
                    const data = await res.json();
                    if (data.features?.length > 0) {
                        const f = data.features[0];
                        // Extract table name correctly
                        const tableName = targetConfig.layers.includes(':') ? targetConfig.layers.split(':').pop() : targetConfig.layers;
                        handleSelectResult({ 
                            id: f.id, 
                            gid: f.properties.gid || parseInt(f.id.split('.').pop()||'0'), 
                            geometry: f.geometry, 
                            properties: { ...f.properties, tableName } 
                        }, evt.coordinate);
                    }
                } catch (e) {} finally { setIsQuerying(false); }
            }
        });

        map.on('pointermove', (evt) => { if (!evt.dragging) setMouseCoord(proj.toLonLat(evt.coordinate)); });
        map.getView().on('change:rotation', () => setMapRotation(map.getView().getRotation()));
        map.getView().on('change:resolution', () => setMapZoom(map.getView().getZoom() || 0));

        const resizeObserver = new ResizeObserver(() => map.updateSize());
        resizeObserver.observe(mapElement.current);
        mapInstance.current = map;
        initData();
        return () => resizeObserver.disconnect();
    }, [handleSelectResult]); // Reducer dependency to minimal

    useEffect(() => {
        if (!mapInstance.current || !measureMode) { if (drawInteraction.current) mapInstance.current?.removeInteraction(drawInteraction.current); return; }
        const map = mapInstance.current;
        drawInteraction.current = new Draw({ source: measureSource.current, type: measureMode, style: measureStyle });
        map.addInteraction(drawInteraction.current);
        let listener: any;
        drawInteraction.current.on('drawstart', (evt) => {
            const feature = evt.feature;
            const tooltipElement = document.createElement('div');
            tooltipElement.className = 'bg-black/80 text-white px-2 py-1 rounded text-[10px] font-bold shadow-xl backdrop-blur-sm border border-white/20 pointer-events-none whitespace-nowrap';
            const tooltip = new Overlay({ element: tooltipElement, offset: [0, -15], positioning: 'bottom-center', stopEvent: false, insertFirst: false });
            map.addOverlay(tooltip);
            listener = feature.getGeometry()?.on('change', (evt: any) => {
                const geom = evt.target;
                let output = '';
                let tooltipCoord: Coordinate | undefined;
                if (geom instanceof Polygon) { output = formatArea(geom); tooltipCoord = geom.getInteriorPoint().getCoordinates(); }
                else if (geom instanceof LineString) { output = formatLength(geom); tooltipCoord = geom.getLastCoordinate(); }
                tooltipElement.innerHTML = output;
                if (tooltipCoord) tooltip.setPosition(tooltipCoord);
            });
        });
        drawInteraction.current.on('drawend', () => { if (listener) unByKey(listener); setMeasureMode(null); });
        return () => { if (drawInteraction.current) map.removeInteraction(drawInteraction.current); };
    }, [measureMode]);

    const handleClearMeasure = () => { measureSource.current.clear(); mapInstance.current?.getOverlays().getArray().filter(o => o !== overlayInstance.current).forEach(o => mapInstance.current?.removeOverlay(o)); };
    const handleZoomIn = () => { const view = mapInstance.current?.getView(); if (view) view.animate({ zoom: (view.getZoom() || 0) + 1, duration: 250 }); };
    const handleZoomOut = () => { const view = mapInstance.current?.getView(); if (view) view.animate({ zoom: (view.getZoom() || 0) - 1, duration: 250 }); };
    const handleResetRotation = () => mapInstance.current?.getView().animate({ rotation: 0, duration: 500 });
    const handleLocate = () => {
        if (!navigator.geolocation) return alert("Không hỗ trợ định vị.");
        setIsLocating(true);
        navigator.geolocation.getCurrentPosition( (pos) => {
                const coords = proj.fromLonLat([pos.coords.longitude, pos.coords.latitude]);
                if (locationLayer.current) {
                    const source = locationLayer.current.getSource();
                    source?.getFeatures().forEach(f => { const type = f.get('type'); if (type === 'accuracy' || type === 'position') source.removeFeature(f); });
                    source?.addFeature(new Feature({ geometry: new GeomCircle(coords, pos.coords.accuracy) }).set('type', 'accuracy') as any);
                    source?.addFeature(new Feature({ geometry: new Point(coords) }).set('type', 'position') as any);
                }
                mapInstance.current?.getView().animate({ center: coords, zoom: Math.max(18, mapInstance.current.getView().getZoom() || 0), duration: 1000 });
                setIsLocating(false);
            }, () => setIsLocating(false), { enableHighAccuracy: true, timeout: 15000, maximumAge: 0 } );
    };

    useEffect(() => {
        if (!baseLayerRef.current || !activeBasemapId || basemaps.length === 0) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') {
            source = new OSM({ crossOrigin: 'anonymous' });
        } else {
            const rawUrl = config.url.startsWith('/') ? `${API_URL}${config.url}` : config.url;
            const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(rawUrl)}`
                .split('%7Bz%7D').join('{z}')
                .split('%7Bx%7D').join('{x}')
                .split('%7By%7D').join('{y}');
            source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
        }
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!wmsLayerGroup.current) return;
        const olLayers = availableLayers.filter(l => visibleLayerIds.includes(l.id)).map(config => {
            let source;
            if (config.type === 'XYZ') {
                const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`
                    .split('%7Bz%7D').join('{z}')
                    .split('%7Bx%7D').join('{x}')
                    .split('%7By%7D').join('{y}');
                source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
            } else {
                source = new TileWMS({ 
                    url: `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`, 
                    params: { 'LAYERS': config.layers, 'TILED': true, 'TRANSPARENT': true, 'FORMAT': 'image/png', 't': wmsCacheBust }, 
                    crossOrigin: 'anonymous' 
                });
            }

            let zIndex = 10;
            if (config.category === 'PLANNING') zIndex = 100;
            if (activeLayerId === config.id) zIndex += 50;

            const layer = new TileLayer({ source: source, opacity: Number(config.opacity ?? 1), zIndex: zIndex });
            layer.set('layerId', config.id);
            return layer;
        });
        wmsLayerGroup.current.setLayers(new Collection(olLayers));
    }, [availableLayers, visibleLayerIds, activeLayerId, wmsCacheBust]);

    return (
        <div className="relative w-full h-full bg-slate-950 flex flex-col min-h-0 overflow-hidden font-sans">
            {isInitialLoading && (
                <div className="absolute inset-0 z-[1000] bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={48} />
                    <p className="font-display uppercase tracking-[0.3em] text-[10px] text-blue-400 font-black animate-pulse">GeoMaster Engine Loading...</p>
                </div>
            )}

            {isQuerying && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 z-[400] bg-slate-900/90 backdrop-blur-md border border-blue-500/30 px-5 py-3 rounded-2xl shadow-[0_0_40px_rgba(37,99,235,0.3)] flex items-center gap-3 animate-in fade-in slide-in-from-bottom-4 duration-300">
                    <div className="relative">
                        <Loader2 className="animate-spin text-blue-500" size={20} />
                        <div className="absolute inset-0 flex items-center justify-center">
                            <div className="w-1.5 h-1.5 bg-white rounded-full animate-ping"></div>
                        </div>
                    </div>
                    <span className="text-[11px] font-black text-white uppercase tracking-[0.2em] whitespace-nowrap">Đang lấy thông tin thửa đất...</span>
                </div>
            )}

            <div className="absolute bottom-6 left-6 z-[400] flex flex-col gap-2 pointer-events-none">
                {mouseCoord && (
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-3 py-1.5 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300">
                        <div className="flex items-center gap-1.5 text-blue-400"><MousePointer2 size={12}/><span className="text-[9px] font-black uppercase tracking-[0.1em]">Tọa độ</span></div>
                        <div className="flex gap-4 font-mono text-[11px] font-bold text-gray-100">
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">X:</span><span>{mouseCoord[0].toFixed(6)}</span></div>
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">Y:</span><span>{mouseCoord[1].toFixed(6)}</span></div>
                        </div>
                    </div>
                )}
                <div className="w-fit bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-2.5 py-1 rounded-lg flex items-center gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Zoom: <span className="text-white ml-1">{Math.round(mapZoom)}</span></span>
                </div>
            </div>
            {isPrinting && ( <div className="absolute inset-0 z-[2000] bg-black/70 backdrop-blur-md flex flex-col items-center justify-center text-white gap-4"> <Printer className="animate-bounce text-orange-500" size={64} /> <div className="text-center"> <p className="font-display font-bold text-xl uppercase tracking-tighter">Đang xuất trích lục đa trang</p> </div> </div> )}
            <div ref={mapElement} className="flex-1 w-full relative" />
            <MeasureTools activeMode={measureMode} onModeChange={setMeasureMode} onClear={handleClearMeasure} />
            <div ref={popupElement} className="absolute bottom-0 left-0 pointer-events-none"> {selectedParcel && ( <div className="pointer-events-auto"> <ParcelPopup parcel={selectedParcel} user={user} onClose={() => { overlayInstance.current?.setPosition(undefined); setSelectedParcel(null); highlightLayer.current?.getSource()?.clear(); }} onPrint={handlePrint} onEdit={handleOpenEdit} /> </div> )} </div>
            <div className="fixed -left-[4000px] top-0 opacity-0 pointer-events-none overflow-hidden"> {printingParcel && <PrintTemplate parcel={printingParcel} user={user} systemSettings={systemSettings} />} </div>
            <div className="absolute bottom-6 right-6 z-[400] flex flex-col gap-3">
                {Math.abs(mapRotation) > 0.01 && ( <button onClick={handleResetRotation} className="p-3 bg-white rounded-full shadow-2xl text-orange-600 hover:bg-orange-50 transition-all"><Compass size={24} style={{ transform: `rotate(${-mapRotation}rad)` }}/></button> )}
                <div className="flex flex-col bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden"> <button onClick={handleZoomIn} className="p-3.5 text-gray-700 hover:bg-gray-50 border-b border-gray-100 transition-colors"><Plus size={20}/></button> <button onClick={handleZoomOut} className="p-3.5 text-gray-700 hover:bg-gray-50 transition-colors"><Minus size={20}/></button> </div>
                <button onClick={handleLocate} className={`p-3.5 rounded-full shadow-2xl text-white transition-all ${isLocating ? 'bg-gray-400' : 'bg-blue-600 hover:bg-blue-700'}`}><Crosshair size={24} className={isLocating ? "animate-spin" : ""}/></button>
            </div>
            <SearchPanel isOpen={isSearchOpen} onToggle={() => setIsSearchOpen(!isSearchOpen)} spatialTables={spatialTables} onSelectResult={p => handleSelectResult(p)} onSearchCoordinate={handleSearchCoordinate} />
            <LayerControl isOpen={isLayerMenuOpen} onToggleMenu={() => setIsLayerMenuOpen(!isLayerMenuOpen)} basemaps={basemaps} activeBasemapId={activeBasemapId} onBaseLayerChange={setActiveBasemapId} availableLayers={availableLayers} visibleLayerIds={visibleLayerIds} activeLayerId={activeLayerId} onToggleWMS={id => setVisibleLayerIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id])} onSetActiveWMS={handleActivateLayer} onOpacityChange={(id, opacity) => setAvailableLayers(prev => prev.map(l => l.id === id ? { ...l, opacity } : l))} />

            {/* Parcel Edit Modal */}
            <ParcelForm isOpen={isEditOpen} onClose={() => setIsEditOpen(false)} editingId={editFormData.gid || null} formData={editFormData} setFormData={setEditFormData} handleSubmit={handleUpdateParcel} loading={editLoading} />

            {/* System Dialog (MapPage specific) */}
            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'info' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}
                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95">OK</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MapPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, LandParcel, WMSLayerConfig, BasemapConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { parcelApi, ParcelDTO } from '../services/parcelApi';
import { Loader2, Crosshair, Map as MapIcon, Layers as LayersIcon, Printer, Plus, Minus, Compass, AlertCircle, RefreshCw, Zap, Search, Fingerprint, MousePointer2, Navigation2, ArrowRight, MapPin, CheckCircle2, AlertTriangle, Info } from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

// Components
import ParcelPopup from '../components/map/ParcelPopup';
import SearchPanel from '../components/map/SearchPanel';
import LayerControl from '../components/map/LayerControl';
import PrintTemplate from '../components/map/PrintTemplate';
import MeasureTools from '../components/map/MeasureTools';
import ParcelForm from '../components/admin/parcel/ParcelForm';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import Overlay from 'ol/Overlay';
import Feature from 'ol/Feature';
import { Tile as TileLayer, Vector as VectorLayer, Group as LayerGroup } from 'ol/layer';
import { OSM, TileWMS, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Point, LineString, Polygon, Circle as GeomCircle } from 'ol/geom';
import GeoJSON from 'ol/format/GeoJSON';
import { defaults as defaultControls } from 'ol/control/defaults';
import Collection from 'ol/Collection';
import { isEmpty as isExtentEmpty, getCenter as getExtentCenter } from 'ol/extent';
import { Coordinate } from 'ol/coordinate';
import Draw from 'ol/interaction/Draw';
import { getArea, getLength } from 'ol/sphere';
import { unByKey } from 'ol/Observable';

// Đăng ký VN-2000 (Kinh tuyến trục 105.75 cho Bình Dương/HCM)
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const MapPage: React.FC<{ user: User | null; systemSettings?: Record<string, string> }> = ({ user, systemSettings }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const popupElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);

    // Refs for Map Events
    const activeLayerIdRef = useRef<string | null>(null);
    const availableLayersRef = useRef<WMSLayerConfig[]>([]);
    const visibleLayerIdsRef = useRef<string[]>([]);

    const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const locationLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const measureSource = useRef<VectorSource>(new VectorSource());
    const wmsLayerGroup = useRef<LayerGroup | null>(null);
    const baseLayerRef = useRef<TileLayer<any> | null>(null);
    const overlayInstance = useRef<Overlay | null>(null);

    const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
    const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
    const [activeLayerId, setActiveLayerId] = useState<string | null>(null);

    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState<string>('');

    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);
    const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isQuerying, setIsQuerying] = useState(false);
    const [isLocating, setIsLocating] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [printingParcel, setPrintingParcel] = useState<LandParcel | null>(null);
    const [mapRotation, setMapRotation] = useState(0);
    const [mapZoom, setMapZoom] = useState(0);
    const [mouseCoord, setMouseCoord] = useState<Coordinate | null>(null);
    const [wmsCacheBust, setWmsCacheBust] = useState(Date.now());

    const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);
    const measureModeRef = useRef<'LineString' | 'Polygon' | null>(null);
    const drawInteraction = useRef<Draw | null>(null);

    // Edit State
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [editFormData, setEditFormData] = useState<ParcelDTO>({ sothua: '', sodoto: '' });
    const [editLoading, setEditLoading] = useState(false);
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Sync state to refs
    useEffect(() => { availableLayersRef.current = availableLayers; }, [availableLayers]);
    useEffect(() => { activeLayerIdRef.current = activeLayerId; }, [activeLayerId]);
    useEffect(() => { visibleLayerIdsRef.current = visibleLayerIds; }, [visibleLayerIds]);
    useEffect(() => { measureModeRef.current = measureMode; }, [measureMode]);

    const highlightStyle = new style.Style({
        stroke: new style.Stroke({ color: '#00ffff', width: 4 }),
        fill: new style.Fill({ color: 'rgba(0, 255, 255, 0.2)' }),
        image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#00ffff' }), stroke: new style.Stroke({color: '#ffffff', width: 2}) })
    });

    const locationStyle = (feature: any) => {
        const type = feature.get('type');
        if (type === 'accuracy') return new style.Style({ fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }), stroke: new style.Stroke({ color: 'rgba(59, 130, 246, 0.3)', width: 1 }) });
        if (type === 'search_result') return new style.Style({ image: new style.Icon({ anchor: [0.5, 1], src: 'https://raw.githubusercontent.com/lucide-react/lucide/main/icons/map-pin.svg', color: '#ef4444', scale: 2 }), text: new style.Text({ text: '📍', scale: 2, offsetY: -10 }) });
        return new style.Style({ image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#3b82f6' }), stroke: new style.Stroke({ color: '#fff', width: 3 }) }) });
    };

    const measureStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.2)' }),
        stroke: new style.Stroke({ color: '#3b82f6', lineDash: [10, 10], width: 3 }),
        image: new style.Circle({ radius: 5, stroke: new style.Stroke({ color: '#3b82f6', width: 2 }), fill: new style.Fill({ color: '#fff' }) })
    });

    const smartMapProperties = (props: any) => {
        const findVal = (keys: string[]) => {
            for (const k of keys) {
                if (props[k] !== undefined && props[k] !== null && props[k] !== '') return props[k];
                const lower = k.toLowerCase();
                if (props[lower] !== undefined && props[lower] !== null && props[lower] !== '') return props[lower];
            }
            return null;
        };
        return {
            ...props,
            so_to: findVal(['sodoto', 'so_to', 'shbando', 'sh_ban_do', 'tobando', 'tờ', 'số tờ']),
            so_thua: findVal(['sothua', 'so_thua', 'shthua', 'sh_thua', 'thửa', 'số thửa']),
            ownerName: findVal(['tenchu', 'ten_chu', 'ten_chu_sd', 'owner', 'chủ sở hữu']),
            area: parseFloat(findVal(['dientich', 'dien_tich', 'area', 'diện tích']) || 0),
            landType: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'loại đất']) || 'N/A',
            address: findVal(['diachi', 'dia_chi', 'dc', 'địa chỉ']) || ''
        };
    };

    const handleSelectResult = useCallback((parcel: LandParcel, fallbackCoord?: Coordinate) => {
        if (!mapInstance.current || !highlightLayer.current) return;
        const normalizedParcel = { ...parcel, properties: smartMapProperties(parcel.properties) };
        setSelectedParcel(normalizedParcel);
        const source = highlightLayer.current.getSource();
        source?.clear();
        let popupPos = fallbackCoord;
        if (parcel.geometry) {
            try {
                const format = new GeoJSON();
                // Phán đoán Projection: VN-2000 Bình Dương x thường từ 550k-650k, y 1.2M-1.3M
                let dataProj = 'EPSG:4326';
                let rawCoords: any = null;
                if (parcel.geometry.type === 'Polygon') rawCoords = parcel.geometry.coordinates[0][0];
                else if (parcel.geometry.type === 'MultiPolygon') rawCoords = parcel.geometry.coordinates[0][0][0];
                else if (parcel.geometry.type === 'Point') rawCoords = parcel.geometry.coordinates;

                if (rawCoords) {
                    const x = Math.abs(rawCoords[0]);
                    const y = Math.abs(rawCoords[1]);
                    if (x > 2000000 || y > 2000000) dataProj = 'EPSG:3857';
                    else if ((x > 300000 && x < 900000) || (y > 1000000 && y < 2000000)) dataProj = 'EPSG:9210';
                }

                const geometry = format.readGeometry(parcel.geometry, { dataProjection: dataProj, featureProjection: 'EPSG:3857' });
                if (geometry) {
                    source?.addFeature(new Feature({ geometry }));
                    const extent = geometry.getExtent();
                    if (extent && !isExtentEmpty(extent)) {
                        popupPos = getExtentCenter(extent);
                        mapInstance.current.getView().fit(extent, { padding: [120, 120, 120, 120], duration: 800, maxZoom: 21 });
                    }
                }
            } catch (err) { console.error("Geom error:", err); }
        }
        if (popupPos) overlayInstance.current?.setPosition(popupPos);
    }, []);

    const handleOpenEdit = (parcel: LandParcel) => {
        const p = parcel.properties;
        setEditFormData({
            gid: parcel.gid,
            sodoto: (p.so_to || '').toString(),
            sothua: (p.so_thua || '').toString(),
            tenchu: p.ownerName || '',
            diachi: p.address || '',
            loaidat: p.landType || '',
            dientich: p.area || 0,
            geometry: parcel.geometry,
            tableName: p.tableName, 
            file: null
        });
        setIsEditOpen(true);
    };

    const handleUpdateParcel = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!editFormData.tableName) { setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Không xác định được bảng dữ liệu.' }); return; }
        setEditLoading(true);
        try {
            if (editFormData.file) await parcelApi.createWithUpload(editFormData.tableName, editFormData);
            else await parcelApi.update(editFormData.tableName, editFormData.gid!, editFormData);
            setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: 'Thông tin đã được cập nhật.' });
            setIsEditOpen(false);
            setSelectedParcel(null);
            overlayInstance.current?.setPosition(undefined);
            highlightLayer.current?.getSource()?.clear();
            setWmsCacheBust(Date.now());
        } catch (err: any) { setDialog({ isOpen: true, type: 'error', title: 'Thất bại', message: err.message }); }
        finally { setEditLoading(false); }
    };

    const handleActivateLayer = async (id: string) => {
        setActiveLayerId(id);
        if (!visibleLayerIds.includes(id)) setVisibleLayerIds(prev => [...prev, id]);
        const layer = availableLayers.find(l => l.id === id);
        if (layer && layer.type !== 'XYZ') {
            const tableName = layer.layers.includes(':') ? layer.layers.split(':')[1] : layer.layers;
            try {
                const res = await fetch(`${API_URL}/api/data/${tableName}/extent`);
                if (res.ok) {
                    const bounds = await res.json();
                    if (bounds && bounds.xmin !== undefined) {
                        let sourceProj = 'EPSG:4326';
                        if (Math.abs(bounds.xmin) > 100000) sourceProj = 'EPSG:9210';
                        const extent = proj.transformExtent([bounds.xmin, bounds.ymin, bounds.xmax, bounds.ymax], sourceProj, 'EPSG:3857');
                        if (mapInstance.current) mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000, maxZoom: 19 });
                    }
                }
            } catch (e) {}
        }
    };

    const initData = async () => {
        try {
            const [layers, tables, maps] = await Promise.all([
                gisService.getLayers().catch(() => []), 
                gisService.getSpatialTables().catch(() => []),
                gisService.getBasemaps().catch(() => [])
            ]);
            setAvailableLayers(layers);
            setVisibleLayerIds(layers.filter(l => l.visible).map(l => l.id));
            setSpatialTables(tables);
            setBasemaps(maps);
            const defMap = maps.find(m => m.isDefault) || maps[0];
            if (defMap) setActiveBasemapId(defMap.id);
            if (layers.length && !activeLayerId) setActiveLayerId(layers[0].id);
        } catch (e) { console.error(e); } finally { setIsInitialLoading(false); }
    };

    useEffect(() => {
        if (!mapElement.current || mapInstance.current) return;
        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }),
                new LayerGroup({ zIndex: 10 }),
                new VectorLayer({ source: new VectorSource(), zIndex: 10000, style: highlightStyle }),
                new VectorLayer({ source: new VectorSource(), zIndex: 20000, style: locationStyle }),
                new VectorLayer({ source: measureSource.current, zIndex: 30000, style: measureStyle }),
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 13, minZoom: 5, maxZoom: 22 }),
            controls: defaultControls({ attribution: false })
        });

        baseLayerRef.current = map.getLayers().getArray()[0] as TileLayer<any>;
        wmsLayerGroup.current = map.getLayers().getArray()[1] as LayerGroup;
        highlightLayer.current = map.getLayers().getArray()[2] as VectorLayer<VectorSource>;
        locationLayer.current = map.getLayers().getArray()[3] as VectorLayer<VectorSource>;
        overlayInstance.current = new Overlay({ element: popupElement.current!, autoPan: { animation: { duration: 250 } }, positioning: 'bottom-center' });
        map.addOverlay(overlayInstance.current);

        map.on('singleclick', async (evt) => {
            if (measureModeRef.current) return;
            const view = map.getView();
            const resolution = view.getResolution();
            const projection = view.getProjection();

            // Tìm các lớp WMS đang hiển thị
            const currentOlLayers = wmsLayerGroup.current?.getLayers().getArray() || [];
            if (currentOlLayers.length === 0) return;

            // Xác định lớp ưu tiên query: Lớp đang active, hoặc lớp trên cùng đang hiện
            let targetLayerIds = [];
            if (activeLayerIdRef.current) targetLayerIds.push(activeLayerIdRef.current);
            visibleLayerIdsRef.current.forEach(id => { if (id !== activeLayerIdRef.current) targetLayerIds.push(id); });

            let foundParcel = false;
            setIsQuerying(true);
            overlayInstance.current?.setPosition(undefined);
            setSelectedParcel(null);
            highlightLayer.current?.getSource()?.clear();

            for (const lid of targetLayerIds) {
                if (foundParcel) break;
                const config = availableLayersRef.current.find(c => c.id === lid);
                if (!config || config.type === 'XYZ') continue;

                const olLayer = currentOlLayers.find(l => l.get('layerId') === lid) as TileLayer<any>;
                if (!olLayer || !olLayer.getSource()?.getFeatureInfoUrl) continue;

                const url = olLayer.getSource().getFeatureInfoUrl(evt.coordinate, resolution!, projection, { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 });
                if (!url) continue;

                try {
                    const res = await fetch(url);
                    const data = await res.json();
                    if (data.features?.length > 0) {
                        const f = data.features[0];
                        const tableName = config.layers.includes(':') ? config.layers.split(':').pop() : config.layers;
                        handleSelectResult({ 
                            id: f.id, 
                            gid: f.properties.gid || parseInt(f.id.split('.').pop()||'0'), 
                            geometry: f.geometry, 
                            properties: { ...f.properties, tableName } 
                        }, evt.coordinate);
                        foundParcel = true;
                    }
                } catch (e) { console.error("Query fail:", lid, e); }
            }
            setIsQuerying(false);
        });

        map.on('pointermove', (evt) => { if (!evt.dragging) setMouseCoord(proj.toLonLat(evt.coordinate)); });
        map.getView().on('change:rotation', () => setMapRotation(map.getView().getRotation()));
        map.getView().on('change:resolution', () => setMapZoom(map.getView().getZoom() || 0));

        const resizeObserver = new ResizeObserver(() => map.updateSize());
        resizeObserver.observe(mapElement.current);
        mapInstance.current = map;
        initData();
        return () => resizeObserver.disconnect();
    }, [handleSelectResult]);

    useEffect(() => {
        if (!mapInstance.current || !measureMode) { if (drawInteraction.current) mapInstance.current?.removeInteraction(drawInteraction.current); return; }
        const map = mapInstance.current;
        drawInteraction.current = new Draw({ source: measureSource.current, type: measureMode, style: measureStyle });
        map.addInteraction(drawInteraction.current);
        let listener: any;
        drawInteraction.current.on('drawstart', (evt) => {
            const feature = evt.feature;
            const tooltipElement = document.createElement('div');
            tooltipElement.className = 'bg-black/80 text-white px-2 py-1 rounded text-[10px] font-bold shadow-xl backdrop-blur-sm border border-white/20 pointer-events-none whitespace-nowrap';
            const tooltip = new Overlay({ element: tooltipElement, offset: [0, -15], positioning: 'bottom-center', stopEvent: false, insertFirst: false });
            map.addOverlay(tooltip);
            listener = feature.getGeometry()?.on('change', (evt: any) => {
                const geom = evt.target;
                let output = ''; let tooltipCoord: Coordinate | undefined;
                if (geom instanceof Polygon) { output = (getArea(geom) > 10000 ? (getArea(geom)/10000).toFixed(2) + ' ha' : getArea(geom).toFixed(2) + ' m²'); tooltipCoord = geom.getInteriorPoint().getCoordinates(); }
                else if (geom instanceof LineString) { output = (getLength(geom) > 1000 ? (getLength(geom)/1000).toFixed(2) + ' km' : getLength(geom).toFixed(2) + ' m'); tooltipCoord = geom.getLastCoordinate(); }
                tooltipElement.innerHTML = output; if (tooltipCoord) tooltip.setPosition(tooltipCoord);
            });
        });
        drawInteraction.current.on('drawend', () => { if (listener) unByKey(listener); setMeasureMode(null); });
        return () => { if (drawInteraction.current) map.removeInteraction(drawInteraction.current); };
    }, [measureMode]);

    useEffect(() => {
        if (!baseLayerRef.current || !activeBasemapId || basemaps.length === 0) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM({ crossOrigin: 'anonymous' });
        else {
            const rawUrl = config.url.startsWith('/') ? `${API_URL}${config.url}` : config.url;
            const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(rawUrl)}`.split('%7Bz%7D').join('{z}').split('%7Bx%7D').join('{x}').split('%7By%7D').join('{y}');
            source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
        }
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!wmsLayerGroup.current) return;
        const olLayers = availableLayers.filter(l => visibleLayerIds.includes(l.id)).map(config => {
            let source;
            if (config.type === 'XYZ') {
                const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`.split('%7Bz%7D').join('{z}').split('%7Bx%7D').join('{x}').split('%7By%7D').join('{y}');
                source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
            } else {
                source = new TileWMS({ 
                    url: `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`, 
                    params: { 'LAYERS': config.layers, 'TILED': true, 'TRANSPARENT': true, 'FORMAT': 'image/png', 't': wmsCacheBust }, 
                    crossOrigin: 'anonymous' 
                });
            }
            let zIndex = config.category === 'PLANNING' ? 100 : 10;
            if (activeLayerId === config.id) zIndex += 50;
            const layer = new TileLayer({ source: source, opacity: Number(config.opacity ?? 1), zIndex: zIndex });
            layer.set('layerId', config.id);
            return layer;
        });
        wmsLayerGroup.current.setLayers(new Collection(olLayers));
    }, [availableLayers, visibleLayerIds, activeLayerId, wmsCacheBust]);

    return (
        <div className="relative w-full h-full bg-slate-950 flex flex-col min-h-0 overflow-hidden font-sans">
            {isInitialLoading && (
                <div className="absolute inset-0 z-[1000] bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={48} />
                    <p className="font-display uppercase tracking-[0.3em] text-[10px] text-blue-400 font-black animate-pulse">GeoMaster Engine Loading...</p>
                </div>
            )}

            {isQuerying && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 z-[400] bg-slate-900/90 backdrop-blur-md border border-blue-500/30 px-5 py-3 rounded-2xl shadow-[0_0_40px_rgba(37,99,235,0.3)] flex items-center gap-3 animate-in fade-in slide-in-from-bottom-4 duration-300">
                    <div className="relative">
                        <Loader2 className="animate-spin text-blue-500" size={20} />
                        <div className="absolute inset-0 flex items-center justify-center">
                            <div className="w-1.5 h-1.5 bg-white rounded-full animate-ping"></div>
                        </div>
                    </div>
                    <span className="text-[11px] font-black text-white uppercase tracking-[0.2em] whitespace-nowrap">Đang lấy thông tin thửa đất...</span>
                </div>
            )}

            <div className="absolute bottom-6 left-6 z-[400] flex flex-col gap-2 pointer-events-none">
                {mouseCoord && (
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-3 py-1.5 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300">
                        <div className="flex items-center gap-1.5 text-blue-400"><MousePointer2 size={12}/><span className="text-[9px] font-black uppercase tracking-[0.1em]">Tọa độ</span></div>
                        <div className="flex gap-4 font-mono text-[11px] font-bold text-gray-100">
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">X:</span><span>{mouseCoord[0].toFixed(6)}</span></div>
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">Y:</span><span>{mouseCoord[1].toFixed(6)}</span></div>
                        </div>
                    </div>
                )}
                <div className="w-fit bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-2.5 py-1 rounded-lg flex items-center gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Zoom: <span className="text-white ml-1">{Math.round(mapZoom)}</span></span>
                </div>
            </div>
            {isPrinting && ( <div className="absolute inset-0 z-[2000] bg-black/70 backdrop-blur-md flex flex-col items-center justify-center text-white gap-4"> <Printer className="animate-bounce text-orange-500" size={64} /> <div className="text-center"> <p className="font-display font-bold text-xl uppercase tracking-tighter">Đang xuất trích lục đa trang</p> </div> </div> )}
            <div ref={mapElement} className="flex-1 w-full relative" />
            <MeasureTools activeMode={measureMode} onModeChange={setMeasureMode} onClear={() => measureSource.current.clear()} />
            <div ref={popupElement} className="absolute bottom-0 left-0 pointer-events-none"> {selectedParcel && ( <div className="pointer-events-auto"> <ParcelPopup parcel={selectedParcel} user={user} onClose={() => { overlayInstance.current?.setPosition(undefined); setSelectedParcel(null); highlightLayer.current?.getSource()?.clear(); }} onPrint={p => { setPrintingParcel(p); setIsPrinting(true); setTimeout(()=>setIsPrinting(false), 2000); }} onEdit={handleOpenEdit} /> </div> )} </div>
            <div className="fixed -left-[4000px] top-0 opacity-0 pointer-events-none overflow-hidden"> {printingParcel && <PrintTemplate parcel={printingParcel} user={user} systemSettings={systemSettings} />} </div>
            <div className="absolute bottom-6 right-6 z-[400] flex flex-col gap-3">
                {Math.abs(mapRotation) > 0.01 && ( <button onClick={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 500 })} className="p-3 bg-white rounded-full shadow-2xl text-orange-600 hover:bg-orange-50 transition-all"><Compass size={24} style={{ transform: `rotate(${-mapRotation}rad)` }}/></button> )}
                <div className="flex flex-col bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden"> <button onClick={() => mapInstance.current?.getView().animate({ zoom: (mapInstance.current?.getView().getZoom() || 0) + 1, duration: 250 })} className="p-3.5 text-gray-700 hover:bg-gray-50 border-b border-gray-100 transition-colors"><Plus size={20}/></button> <button onClick={() => mapInstance.current?.getView().animate({ zoom: (mapInstance.current?.getView().getZoom() || 0) - 1, duration: 250 })} className="p-3.5 text-gray-700 hover:bg-gray-50 transition-colors"><Minus size={20}/></button> </div>
                <button onClick={() => {}} className={`p-3.5 rounded-full shadow-2xl text-white bg-blue-600 hover:bg-blue-700 transition-all`}><Crosshair size={24}/></button>
            </div>
            <SearchPanel isOpen={isSearchOpen} onToggle={() => setIsSearchOpen(!isSearchOpen)} spatialTables={spatialTables} onSelectResult={p => handleSelectResult(p)} onSearchCoordinate={(lat, lon) => mapInstance.current?.getView().animate({ center: proj.fromLonLat([lon, lat]), zoom: 18, duration: 1000 })} />
            <LayerControl isOpen={isLayerMenuOpen} onToggleMenu={() => setIsLayerMenuOpen(!isLayerMenuOpen)} basemaps={basemaps} activeBasemapId={activeBasemapId} onBaseLayerChange={setActiveBasemapId} availableLayers={availableLayers} visibleLayerIds={visibleLayerIds} activeLayerId={activeLayerId} onToggleWMS={id => setVisibleLayerIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id])} onSetActiveWMS={handleActivateLayer} onOpacityChange={(id, opacity) => setAvailableLayers(prev => prev.map(l => l.id === id ? { ...l, opacity } : l))} />

            <ParcelForm isOpen={isEditOpen} onClose={() => setIsEditOpen(false)} editingId={editFormData.gid || null} formData={editFormData} setFormData={setEditFormData} handleSubmit={handleUpdateParcel} loading={editLoading} />

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'info' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}
                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95">OK</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MapPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, LandParcel, WMSLayerConfig, BasemapConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { parcelApi, ParcelDTO } from '../services/parcelApi';
import { Loader2, Crosshair, Map as MapIcon, Layers as LayersIcon, Printer, Plus, Minus, Compass, AlertCircle, RefreshCw, Zap, Search, Fingerprint, MousePointer2, Navigation2, ArrowRight, MapPin, CheckCircle2, AlertTriangle, Info, Save } from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

// Components
import ParcelPopup from '../components/map/ParcelPopup';
import SearchPanel from '../components/map/SearchPanel';
import LayerControl from '../components/map/LayerControl';
import PrintTemplate from '../components/map/PrintTemplate';
import MeasureTools from '../components/map/MeasureTools';
import ParcelForm from '../components/admin/parcel/ParcelForm';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import Overlay from 'ol/Overlay';
import Feature from 'ol/Feature';
import { Tile as TileLayer, Vector as VectorLayer, Group as LayerGroup } from 'ol/layer';
import { OSM, TileWMS, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Point, LineString, Polygon, Circle as GeomCircle } from 'ol/geom';
import GeoJSON from 'ol/format/GeoJSON';
import { defaults as defaultControls } from 'ol/control/defaults';
import Collection from 'ol/Collection';
import { isEmpty as isExtentEmpty, getCenter as getExtentCenter } from 'ol/extent';
import { Coordinate } from 'ol/coordinate';
import Draw from 'ol/interaction/Draw';
import { getArea, getLength } from 'ol/sphere';
import { unByKey } from 'ol/Observable';

// Đăng ký VN-2000 (Kinh tuyến trục 105.75 cho Bình Dương/HCM)
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const MapPage: React.FC<{ user: User | null; systemSettings?: Record<string, string> }> = ({ user, systemSettings }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const popupElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);

    // Refs for Map Events
    const activeLayerIdRef = useRef<string | null>(null);
    const availableLayersRef = useRef<WMSLayerConfig[]>([]);
    const visibleLayerIdsRef = useRef<string[]>([]);

    const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const locationLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const measureSource = useRef<VectorSource>(new VectorSource());
    const wmsLayerGroup = useRef<LayerGroup | null>(null);
    const baseLayerRef = useRef<TileLayer<any> | null>(null);
    const overlayInstance = useRef<Overlay | null>(null);

    const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
    const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
    const [activeLayerId, setActiveLayerId] = useState<string | null>(null);

    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState<string>('');

    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);
    const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isQuerying, setIsQuerying] = useState(false);
    const [isLocating, setIsLocating] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [printingParcel, setPrintingParcel] = useState<LandParcel | null>(null);
    const [mapRotation, setMapRotation] = useState(0);
    const [mapZoom, setMapZoom] = useState(0);
    const [mouseCoord, setMouseCoord] = useState<Coordinate | null>(null);
    const [wmsCacheBust, setWmsCacheBust] = useState(Date.now());

    const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);
    const measureModeRef = useRef<'LineString' | 'Polygon' | null>(null);
    const drawInteraction = useRef<Draw | null>(null);

    // Edit State
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [editFormData, setEditFormData] = useState<ParcelDTO>({ sothua: '', sodoto: '' });
    const [editLoading, setEditLoading] = useState(false);
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Sync state to refs
    useEffect(() => { availableLayersRef.current = availableLayers; }, [availableLayers]);
    useEffect(() => { activeLayerIdRef.current = activeLayerId; }, [activeLayerId]);
    useEffect(() => { visibleLayerIdsRef.current = visibleLayerIds; }, [visibleLayerIds]);
    useEffect(() => { measureModeRef.current = measureMode; }, [measureMode]);

    const highlightStyle = new style.Style({
        stroke: new style.Stroke({ color: '#00ffff', width: 4 }),
        fill: new style.Fill({ color: 'rgba(0, 255, 255, 0.2)' }),
        image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#00ffff' }), stroke: new style.Stroke({color: '#ffffff', width: 2}) })
    });

    const locationStyle = (feature: any) => {
        const type = feature.get('type');
        if (type === 'accuracy') return new style.Style({ fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }), stroke: new style.Stroke({ color: 'rgba(59, 130, 246, 0.3)', width: 1 }) });
        if (type === 'search_result') return new style.Style({ image: new style.Icon({ anchor: [0.5, 1], src: 'https://raw.githubusercontent.com/lucide-react/lucide/main/icons/map-pin.svg', color: '#ef4444', scale: 2 }), text: new style.Text({ text: '📍', scale: 2, offsetY: -10 }) });
        return new style.Style({ image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#3b82f6' }), stroke: new style.Stroke({ color: '#fff', width: 3 }) }) });
    };

    const measureStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.2)' }),
        stroke: new style.Stroke({ color: '#3b82f6', lineDash: [10, 10], width: 3 }),
        image: new style.Circle({ radius: 5, stroke: new style.Stroke({ color: '#3b82f6', width: 2 }), fill: new style.Fill({ color: '#fff' }) })
    });

    const smartMapProperties = (props: any) => {
        const findVal = (keys: string[]) => {
            for (const k of keys) {
                if (props[k] !== undefined && props[k] !== null && props[k] !== '') return props[k];
                const lower = k.toLowerCase();
                if (props[lower] !== undefined && props[lower] !== null && props[lower] !== '') return props[lower];
            }
            return null;
        };
        return {
            ...props,
            so_to: findVal(['sodoto', 'so_to', 'shbando', 'sh_ban_do', 'tobando', 'tờ', 'số tờ', 'so_to_ban_do']),
            so_thua: findVal(['sothua', 'so_thua', 'shthua', 'sh_thua', 'thửa', 'số thửa', 'so_thu_tu_thua']),
            ownerName: findVal(['tenchu', 'ten_chu', 'ten_chu_sd', 'owner', 'chủ sở hữu', 'chusudung']),
            area: parseFloat(findVal(['dientich', 'dien_tich', 'area', 'diện tích', 'shape_area', 'dt_phaply']) || 0),
            landType: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'loại đất', 'mdsd']) || 'N/A',
            address: findVal(['diachi', 'dia_chi', 'dc', 'địa chỉ', 'vitri']) || ''
        };
    };

    const handleSelectResult = useCallback((parcel: LandParcel, fallbackCoord?: Coordinate) => {
        if (!mapInstance.current || !highlightLayer.current) return;
        const normalizedParcel = { ...parcel, properties: smartMapProperties(parcel.properties) };
        setSelectedParcel(normalizedParcel);
        const source = highlightLayer.current.getSource();
        source?.clear();
        let popupPos = fallbackCoord;
        if (parcel.geometry) {
            try {
                const format = new GeoJSON();
                let dataProj = 'EPSG:4326';
                let rawCoords: any = null;
                if (parcel.geometry.type === 'Polygon') rawCoords = parcel.geometry.coordinates[0][0];
                else if (parcel.geometry.type === 'MultiPolygon') rawCoords = parcel.geometry.coordinates[0][0][0];
                else if (parcel.geometry.type === 'Point') rawCoords = parcel.geometry.coordinates;

                if (rawCoords) {
                    const x = Math.abs(rawCoords[0]);
                    const y = Math.abs(rawCoords[1]);
                    if (x > 2000000 || y > 2000000) dataProj = 'EPSG:3857';
                    else if ((x > 300000 && x < 900000) || (y > 1000000 && y < 2000000)) dataProj = 'EPSG:9210';
                }

                const geometry = format.readGeometry(parcel.geometry, { dataProjection: dataProj, featureProjection: 'EPSG:3857' });
                if (geometry) {
                    source?.addFeature(new Feature({ geometry }));
                    const extent = geometry.getExtent();
                    if (extent && !isExtentEmpty(extent)) {
                        popupPos = getExtentCenter(extent);
                        mapInstance.current.getView().fit(extent, { padding: [120, 120, 120, 120], duration: 800, maxZoom: 21 });
                    }
                }
            } catch (err) { console.error("Geom error:", err); }
        }
        if (popupPos) overlayInstance.current?.setPosition(popupPos);
    }, []);

    const handleOpenEdit = (parcel: LandParcel) => {
        const p = parcel.properties;
        setEditFormData({
            gid: parcel.gid,
            sodoto: (p.so_to || '').toString(),
            sothua: (p.so_thua || '').toString(),
            tenchu: p.ownerName || '',
            diachi: p.address || '',
            loaidat: p.landType || '',
            dientich: p.area || 0,
            geometry: parcel.geometry,
            tableName: p.tableName, 
            file: null
        });
        setIsEditOpen(true);
    };

    const handleUpdateParcel = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!editFormData.tableName) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi cấu hình', message: 'Không xác định được bảng dữ liệu gốc để cập nhật.' });
            return;
        }

        setEditLoading(true);
        try {
            if (editFormData.file) {
                await parcelApi.createWithUpload(editFormData.tableName, editFormData);
            } else {
                await parcelApi.update(editFormData.tableName, editFormData.gid!, editFormData);
            }

            // --- CẬP NHẬT UI TỨC THÌ (Optimistic UI) ---
            if (selectedParcel) {
                // Giữ lại Popup và Highlight, chỉ thay đổi thông tin thuộc tính hiển thị
                const updatedProperties = {
                    ...selectedParcel.properties,
                    so_to: editFormData.sodoto,
                    so_thua: editFormData.sothua,
                    ownerName: editFormData.tenchu,
                    address: editFormData.diachi,
                    landType: editFormData.loaidat,
                    area: editFormData.dientich
                };
                setSelectedParcel({ ...selectedParcel, properties: updatedProperties });
            }

            setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: 'Thông tin thửa đất đã được lưu. Bản đồ sẽ được làm mới trong giây lát.' });
            setIsEditOpen(false);

            // Làm mới lớp WMS mà không đóng Popup ngay
            setWmsCacheBust(Date.now());

        } catch (err: any) {
            setDialog({ isOpen: true, type: 'error', title: 'Thất bại', message: err.message || 'Đã xảy ra lỗi khi lưu dữ liệu.' });
        } finally {
            setEditLoading(false);
        }
    };

    const handleActivateLayer = async (id: string) => {
        setActiveLayerId(id);
        if (!visibleLayerIds.includes(id)) setVisibleLayerIds(prev => [...prev, id]);
        const layer = availableLayers.find(l => l.id === id);
        if (layer && layer.type !== 'XYZ') {
            const tableName = layer.layers.includes(':') ? layer.layers.split(':')[1] : layer.layers;
            try {
                const res = await fetch(`${API_URL}/api/data/${tableName}/extent`);
                if (res.ok) {
                    const bounds = await res.json();
                    if (bounds && bounds.xmin !== undefined) {
                        let sourceProj = 'EPSG:4326';
                        if (Math.abs(bounds.xmin) > 100000) sourceProj = 'EPSG:9210';
                        const extent = proj.transformExtent([bounds.xmin, bounds.ymin, bounds.xmax, bounds.ymax], sourceProj, 'EPSG:3857');
                        if (mapInstance.current) mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000, maxZoom: 19 });
                    }
                }
            } catch (e) {}
        }
    };

    const initData = async () => {
        try {
            const [layers, tables, maps] = await Promise.all([
                gisService.getLayers().catch(() => []), 
                gisService.getSpatialTables().catch(() => []),
                gisService.getBasemaps().catch(() => [])
            ]);
            setAvailableLayers(layers);
            setVisibleLayerIds(layers.filter(l => l.visible).map(l => l.id));
            setSpatialTables(tables);
            setBasemaps(maps);
            const defMap = maps.find(m => m.isDefault) || maps[0];
            if (defMap) setActiveBasemapId(defMap.id);
            if (layers.length && !activeLayerId) setActiveLayerId(layers[0].id);
        } catch (e) { console.error(e); } finally { setIsInitialLoading(false); }
    };

    useEffect(() => {
        if (!mapElement.current || mapInstance.current) return;
        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }),
                new LayerGroup({ zIndex: 10 }),
                new VectorLayer({ source: new VectorSource(), zIndex: 10000, style: highlightStyle }),
                new VectorLayer({ source: new VectorSource(), zIndex: 20000, style: locationStyle }),
                new VectorLayer({ source: measureSource.current, zIndex: 30000, style: measureStyle }),
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 13, minZoom: 5, maxZoom: 22 }),
            controls: defaultControls({ attribution: false })
        });

        baseLayerRef.current = map.getLayers().getArray()[0] as TileLayer<any>;
        wmsLayerGroup.current = map.getLayers().getArray()[1] as LayerGroup;
        highlightLayer.current = map.getLayers().getArray()[2] as VectorLayer<VectorSource>;
        locationLayer.current = map.getLayers().getArray()[3] as VectorLayer<VectorSource>;
        overlayInstance.current = new Overlay({ element: popupElement.current!, autoPan: { animation: { duration: 250 } }, positioning: 'bottom-center' });
        map.addOverlay(overlayInstance.current);

        map.on('singleclick', async (evt) => {
            if (measureModeRef.current) return;
            const view = map.getView();
            const resolution = view.getResolution();
            const projection = view.getProjection();

            const currentOlLayers = wmsLayerGroup.current?.getLayers().getArray() || [];
            if (currentOlLayers.length === 0) return;

            let targetLayerIds = [];
            if (activeLayerIdRef.current) targetLayerIds.push(activeLayerIdRef.current);
            visibleLayerIdsRef.current.forEach(id => { if (id !== activeLayerIdRef.current) targetLayerIds.push(id); });

            let foundParcel = false;
            setIsQuerying(true);

            // Xóa lựa chọn cũ trước khi tìm mới
            overlayInstance.current?.setPosition(undefined);
            setSelectedParcel(null);
            highlightLayer.current?.getSource()?.clear();

            for (const lid of targetLayerIds) {
                if (foundParcel) break;
                const config = availableLayersRef.current.find(c => c.id === lid);
                if (!config || config.type === 'XYZ') continue;

                const olLayer = currentOlLayers.find(l => l.get('layerId') === lid) as TileLayer<any>;
                if (!olLayer || !olLayer.getSource()?.getFeatureInfoUrl) continue;

                const url = olLayer.getSource().getFeatureInfoUrl(evt.coordinate, resolution!, projection, { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 });
                if (!url) continue;

                try {
                    const res = await fetch(url);
                    const data = await res.json();
                    if (data.features?.length > 0) {
                        const f = data.features[0];
                        const tableName = config.layers.includes(':') ? config.layers.split(':').pop() : config.layers;
                        handleSelectResult({ 
                            id: f.id, 
                            gid: f.properties.gid || parseInt(f.id.split('.').pop()||'0'), 
                            geometry: f.geometry, 
                            properties: { ...f.properties, tableName } 
                        }, evt.coordinate);
                        foundParcel = true;
                    }
                } catch (e) { console.error("Query fail:", lid, e); }
            }
            setIsQuerying(false);
        });

        map.on('pointermove', (evt) => { if (!evt.dragging) setMouseCoord(proj.toLonLat(evt.coordinate)); });
        map.getView().on('change:rotation', () => setMapRotation(map.getView().getRotation()));
        map.getView().on('change:resolution', () => setMapZoom(map.getView().getZoom() || 0));

        const resizeObserver = new ResizeObserver(() => map.updateSize());
        resizeObserver.observe(mapElement.current);
        mapInstance.current = map;
        initData();
        return () => resizeObserver.disconnect();
    }, [handleSelectResult]);

    useEffect(() => {
        if (!mapInstance.current || !measureMode) { if (drawInteraction.current) mapInstance.current?.removeInteraction(drawInteraction.current); return; }
        const map = mapInstance.current;
        drawInteraction.current = new Draw({ source: measureSource.current, type: measureMode, style: measureStyle });
        map.addInteraction(drawInteraction.current);
        let listener: any;
        drawInteraction.current.on('drawstart', (evt) => {
            const feature = evt.feature;
            const tooltipElement = document.createElement('div');
            tooltipElement.className = 'bg-black/80 text-white px-2 py-1 rounded text-[10px] font-bold shadow-xl backdrop-blur-sm border border-white/20 pointer-events-none whitespace-nowrap';
            const tooltip = new Overlay({ element: tooltipElement, offset: [0, -15], positioning: 'bottom-center', stopEvent: false, insertFirst: false });
            map.addOverlay(tooltip);
            listener = feature.getGeometry()?.on('change', (evt: any) => {
                const geom = evt.target;
                let output = ''; let tooltipCoord: Coordinate | undefined;
                if (geom instanceof Polygon) { output = (getArea(geom) > 10000 ? (getArea(geom)/10000).toFixed(2) + ' ha' : getArea(geom).toFixed(2) + ' m²'); tooltipCoord = geom.getInteriorPoint().getCoordinates(); }
                else if (geom instanceof LineString) { output = (getLength(geom) > 1000 ? (getLength(geom)/1000).toFixed(2) + ' km' : getLength(geom).toFixed(2) + ' m'); tooltipCoord = geom.getLastCoordinate(); }
                tooltipElement.innerHTML = output; if (tooltipCoord) tooltip.setPosition(tooltipCoord);
            });
        });
        drawInteraction.current.on('drawend', () => { if (listener) unByKey(listener); setMeasureMode(null); });
        return () => { if (drawInteraction.current) map.removeInteraction(drawInteraction.current); };
    }, [measureMode]);

    useEffect(() => {
        if (!baseLayerRef.current || !activeBasemapId || basemaps.length === 0) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM({ crossOrigin: 'anonymous' });
        else {
            const rawUrl = config.url.startsWith('/') ? `${API_URL}${config.url}` : config.url;
            const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(rawUrl)}`.split('%7Bz%7D').join('{z}').split('%7Bx%7D').join('{x}').split('%7By%7D').join('{y}');
            source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
        }
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!wmsLayerGroup.current) return;
        const olLayers = availableLayers.filter(l => visibleLayerIds.includes(l.id)).map(config => {
            let source;
            if (config.type === 'XYZ') {
                const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`.split('%7Bz%7D').join('{z}').split('%7Bx%7D').join('{x}').split('%7By%7D').join('{y}');
                source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
            } else {
                source = new TileWMS({ 
                    url: `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`, 
                    params: { 'LAYERS': config.layers, 'TILED': true, 'TRANSPARENT': true, 'FORMAT': 'image/png', 't': wmsCacheBust }, 
                    crossOrigin: 'anonymous' 
                });
            }
            let zIndex = config.category === 'PLANNING' ? 100 : 10;
            if (activeLayerId === config.id) zIndex += 50;
            const layer = new TileLayer({ source: source, opacity: Number(config.opacity ?? 1), zIndex: zIndex });
            layer.set('layerId', config.id);
            return layer;
        });
        wmsLayerGroup.current.setLayers(new Collection(olLayers));
    }, [availableLayers, visibleLayerIds, activeLayerId, wmsCacheBust]);

    return (
        <div className="relative w-full h-full bg-slate-950 flex flex-col min-h-0 overflow-hidden font-sans">
            {isInitialLoading && (
                <div className="absolute inset-0 z-[1000] bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={48} />
                    <p className="font-display uppercase tracking-[0.3em] text-[10px] text-blue-400 font-black animate-pulse">GeoMaster Engine Loading...</p>
                </div>
            )}

            {isQuerying && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 z-[400] bg-slate-900/90 backdrop-blur-md border border-blue-500/30 px-5 py-3 rounded-2xl shadow-[0_0_40px_rgba(37,99,235,0.3)] flex items-center gap-3 animate-in fade-in slide-in-from-bottom-4 duration-300">
                    <div className="relative">
                        <Loader2 className="animate-spin text-blue-500" size={20} />
                        <div className="absolute inset-0 flex items-center justify-center">
                            <div className="w-1.5 h-1.5 bg-white rounded-full animate-ping"></div>
                        </div>
                    </div>
                    <span className="text-[11px] font-black text-white uppercase tracking-[0.2em] whitespace-nowrap">Đang lấy thông tin thửa đất...</span>
                </div>
            )}

            <div className="absolute bottom-6 left-6 z-[400] flex flex-col gap-2 pointer-events-none">
                {mouseCoord && (
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-3 py-1.5 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300">
                        <div className="flex items-center gap-1.5 text-blue-400"><MousePointer2 size={12}/><span className="text-[9px] font-black uppercase tracking-[0.1em]">Tọa độ</span></div>
                        <div className="flex gap-4 font-mono text-[11px] font-bold text-gray-100">
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">X:</span><span>{mouseCoord[0].toFixed(6)}</span></div>
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">Y:</span><span>{mouseCoord[1].toFixed(6)}</span></div>
                        </div>
                    </div>
                )}
                <div className="w-fit bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-2.5 py-1 rounded-lg flex items-center gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Zoom: <span className="text-white ml-1">{Math.round(mapZoom)}</span></span>
                </div>
            </div>
            {isPrinting && ( <div className="absolute inset-0 z-[2000] bg-black/70 backdrop-blur-md flex flex-col items-center justify-center text-white gap-4"> <Printer className="animate-bounce text-orange-500" size={64} /> <div className="text-center"> <p className="font-display font-bold text-xl uppercase tracking-tighter">Đang xuất trích lục đa trang</p> </div> </div> )}
            <div ref={mapElement} className="flex-1 w-full relative" />
            <MeasureTools activeMode={measureMode} onModeChange={setMeasureMode} onClear={() => measureSource.current.clear()} />
            <div ref={popupElement} className="absolute bottom-0 left-0 pointer-events-none"> {selectedParcel && ( <div className="pointer-events-auto"> <ParcelPopup parcel={selectedParcel} user={user} onClose={() => { overlayInstance.current?.setPosition(undefined); setSelectedParcel(null); highlightLayer.current?.getSource()?.clear(); }} onPrint={p => { setPrintingParcel(p); setIsPrinting(true); setTimeout(()=>setIsPrinting(false), 2000); }} onEdit={handleOpenEdit} /> </div> )} </div>
            <div className="fixed -left-[4000px] top-0 opacity-0 pointer-events-none overflow-hidden"> {printingParcel && <PrintTemplate parcel={printingParcel} user={user} systemSettings={systemSettings} />} </div>
            <div className="absolute bottom-6 right-6 z-[400] flex flex-col gap-3">
                {Math.abs(mapRotation) > 0.01 && ( <button onClick={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 500 })} className="p-3 bg-white rounded-full shadow-2xl text-orange-600 hover:bg-orange-50 transition-all"><Compass size={24} style={{ transform: `rotate(${-mapRotation}rad)` }}/></button> )}
                <div className="flex flex-col bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden"> <button onClick={() => mapInstance.current?.getView().animate({ zoom: (mapInstance.current?.getView().getZoom() || 0) + 1, duration: 250 })} className="p-3.5 text-gray-700 hover:bg-gray-50 border-b border-gray-100 transition-colors"><Plus size={20}/></button> <button onClick={() => mapInstance.current?.getView().animate({ zoom: (mapInstance.current?.getView().getZoom() || 0) - 1, duration: 250 })} className="p-3.5 text-gray-700 hover:bg-gray-50 transition-colors"><Minus size={20}/></button> </div>
                <button onClick={() => {}} className={`p-3.5 rounded-full shadow-2xl text-white bg-blue-600 hover:bg-blue-700 transition-all`}><Crosshair size={24}/></button>
            </div>
            <SearchPanel isOpen={isSearchOpen} onToggle={() => setIsSearchOpen(!isSearchOpen)} spatialTables={spatialTables} onSelectResult={p => handleSelectResult(p)} onSearchCoordinate={(lat, lon) => mapInstance.current?.getView().animate({ center: proj.fromLonLat([lon, lat]), zoom: 18, duration: 1000 })} />
            <LayerControl isOpen={isLayerMenuOpen} onToggleMenu={() => setIsLayerMenuOpen(!isLayerMenuOpen)} basemaps={basemaps} activeBasemapId={activeBasemapId} onBaseLayerChange={setActiveBasemapId} availableLayers={availableLayers} visibleLayerIds={visibleLayerIds} activeLayerId={activeLayerId} onToggleWMS={id => setVisibleLayerIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id])} onSetActiveWMS={handleActivateLayer} onOpacityChange={(id, opacity) => setAvailableLayers(prev => prev.map(l => l.id === id ? { ...l, opacity } : l))} />

            <ParcelForm isOpen={isEditOpen} onClose={() => setIsEditOpen(false)} editingId={editFormData.gid || null} formData={editFormData} setFormData={setEditFormData} handleSubmit={handleUpdateParcel} loading={editLoading} />

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'info' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}
                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95">OK</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MapPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, LandParcel, WMSLayerConfig, BasemapConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { parcelApi, ParcelDTO } from '../services/parcelApi';
import { Loader2, Crosshair, Map as MapIcon, Layers as LayersIcon, Printer, Plus, Minus, Compass, AlertCircle, RefreshCw, Zap, Search, Fingerprint, MousePointer2, Navigation2, ArrowRight, MapPin, CheckCircle2, AlertTriangle, Info, Save } from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

// Components
import ParcelPopup from '../components/map/ParcelPopup';
import SearchPanel from '../components/map/SearchPanel';
import LayerControl from '../components/map/LayerControl';
import PrintTemplate from '../components/map/PrintTemplate';
import MeasureTools from '../components/map/MeasureTools';
import ParcelForm from '../components/admin/parcel/ParcelForm';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import Overlay from 'ol/Overlay';
import Feature from 'ol/Feature';
import { Tile as TileLayer, Vector as VectorLayer, Group as LayerGroup } from 'ol/layer';
import { OSM, TileWMS, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Point, LineString, Polygon, Circle as GeomCircle } from 'ol/geom';
import GeoJSON from 'ol/format/GeoJSON';
import { defaults as defaultControls } from 'ol/control/defaults';
import Collection from 'ol/Collection';
import { isEmpty as isExtentEmpty, getCenter as getExtentCenter } from 'ol/extent';
import { Coordinate } from 'ol/coordinate';
import Draw from 'ol/interaction/Draw';
import { getArea, getLength } from 'ol/sphere';
import { unByKey } from 'ol/Observable';

// Đăng ký VN-2000 (Kinh tuyến trục 105.75 cho Bình Dương/HCM)
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const MapPage: React.FC<{ user: User | null; systemSettings?: Record<string, string> }> = ({ user, systemSettings }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const popupElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);

    // Refs for Map Events (Anti-stale closures)
    const activeLayerIdRef = useRef<string | null>(null);
    const availableLayersRef = useRef<WMSLayerConfig[]>([]);
    const visibleLayerIdsRef = useRef<string[]>([]);

    const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const locationLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const measureSource = useRef<VectorSource>(new VectorSource());
    const wmsLayerGroup = useRef<LayerGroup | null>(null);
    const baseLayerRef = useRef<TileLayer<any> | null>(null);
    const overlayInstance = useRef<Overlay | null>(null);

    const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
    const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
    const [activeLayerId, setActiveLayerId] = useState<string | null>(null);

    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState<string>('');

    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);
    const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isQuerying, setIsQuerying] = useState(false);
    const [isLocating, setIsLocating] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [printingParcel, setPrintingParcel] = useState<LandParcel | null>(null);
    const [mapRotation, setMapRotation] = useState(0);
    const [mapZoom, setMapZoom] = useState(0);
    const [mouseCoord, setMouseCoord] = useState<Coordinate | null>(null);
    const [wmsCacheBust, setWmsCacheBust] = useState(Date.now());

    const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);
    const measureModeRef = useRef<'LineString' | 'Polygon' | null>(null);
    const drawInteraction = useRef<Draw | null>(null);

    // Edit State
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [editFormData, setEditFormData] = useState<ParcelDTO>({ sothua: '', sodoto: '' });
    const [editLoading, setEditLoading] = useState(false);
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Sync state to refs
    useEffect(() => { availableLayersRef.current = availableLayers; }, [availableLayers]);
    useEffect(() => { activeLayerIdRef.current = activeLayerId; }, [activeLayerId]);
    useEffect(() => { visibleLayerIdsRef.current = visibleLayerIds; }, [visibleLayerIds]);
    useEffect(() => { measureModeRef.current = measureMode; }, [measureMode]);

    const highlightStyle = new style.Style({
        stroke: new style.Stroke({ color: '#00ffff', width: 4 }),
        fill: new style.Fill({ color: 'rgba(0, 255, 255, 0.2)' }),
        image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#00ffff' }), stroke: new style.Stroke({color: '#ffffff', width: 2}) })
    });

    const locationStyle = (feature: any) => {
        const type = feature.get('type');
        if (type === 'accuracy') return new style.Style({ fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }), stroke: new style.Stroke({ color: 'rgba(59, 130, 246, 0.3)', width: 1 }) });
        if (type === 'search_result') return new style.Style({ image: new style.Icon({ anchor: [0.5, 1], src: 'https://raw.githubusercontent.com/lucide-react/lucide/main/icons/map-pin.svg', color: '#ef4444', scale: 2 }), text: new style.Text({ text: '📍', scale: 2, offsetY: -10 }) });
        return new style.Style({ image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#3b82f6' }), stroke: new style.Stroke({ color: '#fff', width: 3 }) }) });
    };

    const measureStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.2)' }),
        stroke: new style.Stroke({ color: '#3b82f6', lineDash: [10, 10], width: 3 }),
        image: new style.Circle({ radius: 5, stroke: new style.Stroke({ color: '#3b82f6', width: 2 }), fill: new style.Fill({ color: '#fff' }) })
    });

    const smartMapProperties = (props: any) => {
        const findVal = (keys: string[]) => {
            for (const k of keys) {
                if (props[k] !== undefined && props[k] !== null && props[k] !== '') return props[k];
                const lower = k.toLowerCase();
                if (props[lower] !== undefined && props[lower] !== null && props[lower] !== '') return props[lower];
            }
            return null;
        };
        return {
            ...props,
            so_to: findVal(['sodoto', 'so_to', 'shbando', 'sh_ban_do', 'tobando', 'tờ', 'số tờ', 'so_to_ban_do']),
            so_thua: findVal(['sothua', 'so_thua', 'shthua', 'sh_thua', 'thửa', 'số thửa', 'so_thu_tu_thua']),
            ownerName: findVal(['tenchu', 'ten_chu', 'ten_chu_sd', 'owner', 'chủ sở hữu', 'chusudung']),
            area: parseFloat(findVal(['dientich', 'dien_tich', 'area', 'diện tích', 'shape_area', 'dt_phaply']) || 0),
            landType: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'loại đất', 'mdsd']) || 'N/A',
            address: findVal(['diachi', 'dia_chi', 'dc', 'địa chỉ', 'vitri']) || ''
        };
    };

    const handleSelectResult = useCallback((parcel: LandParcel, fallbackCoord?: Coordinate) => {
        if (!mapInstance.current || !highlightLayer.current) return;
        const normalizedParcel = { ...parcel, properties: smartMapProperties(parcel.properties) };
        setSelectedParcel(normalizedParcel);
        const source = highlightLayer.current.getSource();
        source?.clear();
        let popupPos = fallbackCoord;
        if (parcel.geometry) {
            try {
                const format = new GeoJSON();
                let dataProj = 'EPSG:4326';
                let rawCoords: any = null;
                if (parcel.geometry.type === 'Polygon') rawCoords = parcel.geometry.coordinates[0][0];
                else if (parcel.geometry.type === 'MultiPolygon') rawCoords = parcel.geometry.coordinates[0][0][0];
                else if (parcel.geometry.type === 'Point') rawCoords = parcel.geometry.coordinates;

                if (rawCoords) {
                    const x = Math.abs(rawCoords[0]);
                    const y = Math.abs(rawCoords[1]);
                    if (x > 2000000 || y > 2000000) dataProj = 'EPSG:3857';
                    else if ((x > 300000 && x < 900000) || (y > 1000000 && y < 2000000)) dataProj = 'EPSG:9210';
                }

                const geometry = format.readGeometry(parcel.geometry, { dataProjection: dataProj, featureProjection: 'EPSG:3857' });
                if (geometry) {
                    source?.addFeature(new Feature({ geometry }));
                    const extent = geometry.getExtent();
                    if (extent && !isExtentEmpty(extent)) {
                        popupPos = getExtentCenter(extent);
                        mapInstance.current.getView().fit(extent, { padding: [120, 120, 120, 120], duration: 800, maxZoom: 21 });
                    }
                }
            } catch (err) { console.error("Geom error:", err); }
        }
        if (popupPos) overlayInstance.current?.setPosition(popupPos);
    }, []);

    const handleOpenEdit = (parcel: LandParcel) => {
        const p = parcel.properties;
        setEditFormData({
            gid: parcel.gid,
            sodoto: (p.so_to || '').toString(),
            sothua: (p.so_thua || '').toString(),
            tenchu: p.ownerName || '',
            diachi: p.address || '',
            loaidat: p.landType || '',
            dientich: p.area || 0,
            geometry: parcel.geometry,
            tableName: p.tableName, 
            file: null
        });
        setIsEditOpen(true);
    };

    const handleUpdateParcel = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!editFormData.tableName) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi cấu hình', message: 'Không xác định được bảng dữ liệu gốc để cập nhật.' });
            return;
        }

        setEditLoading(true);
        try {
            if (editFormData.file) {
                // Nếu tải file lên: Cập nhật cả hình học và thuộc tính
                await parcelApi.createWithUpload(editFormData.tableName, editFormData);
            } else {
                // QUAN TRỌNG: Nếu chỉ sửa chữ, LOẠI BỎ geometry khỏi request gửi đi
                // để tránh làm hỏng hình học do sai lệch hệ tọa độ client/server
                const { geometry, ...dataOnlyAttrs } = editFormData;
                await parcelApi.update(editFormData.tableName, editFormData.gid!, dataOnlyAttrs);
            }

            // Cập nhật giao diện tạm thời để người dùng thấy kết quả ngay
            if (selectedParcel) {
                const updatedProperties = {
                    ...selectedParcel.properties,
                    so_to: editFormData.sodoto,
                    so_thua: editFormData.sothua,
                    ownerName: editFormData.tenchu,
                    address: editFormData.diachi,
                    landType: editFormData.loaidat,
                    area: editFormData.dientich
                };
                setSelectedParcel({ ...selectedParcel, properties: updatedProperties });
            }

            setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: 'Thông tin thửa đất đã được lưu thành công.' });
            setIsEditOpen(false);

            // Buộc lớp bản đồ WMS nạp lại ảnh mới từ Server
            setWmsCacheBust(Date.now());

        } catch (err: any) {
            setDialog({ isOpen: true, type: 'error', title: 'Thất bại', message: err.message || 'Đã xảy ra lỗi khi lưu dữ liệu.' });
        } finally {
            setEditLoading(false);
        }
    };

    const handleActivateLayer = async (id: string) => {
        setActiveLayerId(id);
        if (!visibleLayerIds.includes(id)) setVisibleLayerIds(prev => [...prev, id]);
        const layer = availableLayers.find(l => l.id === id);
        if (layer && layer.type !== 'XYZ') {
            const tableName = layer.layers.includes(':') ? layer.layers.split(':')[1] : layer.layers;
            try {
                const res = await fetch(`${API_URL}/api/data/${tableName}/extent`);
                if (res.ok) {
                    const bounds = await res.json();
                    if (bounds && bounds.xmin !== undefined) {
                        let sourceProj = 'EPSG:4326';
                        if (Math.abs(bounds.xmin) > 100000) sourceProj = 'EPSG:9210';
                        const extent = proj.transformExtent([bounds.xmin, bounds.ymin, bounds.xmax, bounds.ymax], sourceProj, 'EPSG:3857');
                        if (mapInstance.current) mapInstance.current.getView().fit(extent, { padding: [50, 50, 50, 50], duration: 1000, maxZoom: 19 });
                    }
                }
            } catch (e) {}
        }
    };

    const initData = async () => {
        try {
            const [layers, tables, maps] = await Promise.all([
                gisService.getLayers().catch(() => []), 
                gisService.getSpatialTables().catch(() => []),
                gisService.getBasemaps().catch(() => [])
            ]);
            setAvailableLayers(layers);
            setVisibleLayerIds(layers.filter(l => l.visible).map(l => l.id));
            setSpatialTables(tables);
            setBasemaps(maps);
            const defMap = maps.find(m => m.isDefault) || maps[0];
            if (defMap) setActiveBasemapId(defMap.id);
            if (layers.length && !activeLayerId) setActiveLayerId(layers[0].id);
        } catch (e) { console.error(e); } finally { setIsInitialLoading(false); }
    };

    useEffect(() => {
        if (!mapElement.current || mapInstance.current) return;
        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }),
                new LayerGroup({ zIndex: 10 }),
                new VectorLayer({ source: new VectorSource(), zIndex: 10000, style: highlightStyle }),
                new VectorLayer({ source: new VectorSource(), zIndex: 20000, style: locationStyle }),
                new VectorLayer({ source: measureSource.current, zIndex: 30000, style: measureStyle }),
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 13, minZoom: 5, maxZoom: 22 }),
            controls: defaultControls({ attribution: false })
        });

        baseLayerRef.current = map.getLayers().getArray()[0] as TileLayer<any>;
        wmsLayerGroup.current = map.getLayers().getArray()[1] as LayerGroup;
        highlightLayer.current = map.getLayers().getArray()[2] as VectorLayer<VectorSource>;
        locationLayer.current = map.getLayers().getArray()[3] as VectorLayer<VectorSource>;
        overlayInstance.current = new Overlay({ element: popupElement.current!, autoPan: { animation: { duration: 250 } }, positioning: 'bottom-center' });
        map.addOverlay(overlayInstance.current);

        map.on('singleclick', async (evt) => {
            if (measureModeRef.current) return;
            const view = map.getView();
            const resolution = view.getResolution();
            const projection = view.getProjection();

            const currentOlLayers = wmsLayerGroup.current?.getLayers().getArray() || [];
            if (currentOlLayers.length === 0) return;

            let targetLayerIds = [];
            if (activeLayerIdRef.current) targetLayerIds.push(activeLayerIdRef.current);
            visibleLayerIdsRef.current.forEach(id => { if (id !== activeLayerIdRef.current) targetLayerIds.push(id); });

            let foundParcel = false;
            setIsQuerying(true);

            overlayInstance.current?.setPosition(undefined);
            setSelectedParcel(null);
            highlightLayer.current?.getSource()?.clear();

            for (const lid of targetLayerIds) {
                if (foundParcel) break;
                const config = availableLayersRef.current.find(c => c.id === lid);
                if (!config || config.type === 'XYZ') continue;

                const olLayer = currentOlLayers.find(l => l.get('layerId') === lid) as TileLayer<any>;
                if (!olLayer || !olLayer.getSource()?.getFeatureInfoUrl) continue;

                const url = olLayer.getSource().getFeatureInfoUrl(evt.coordinate, resolution!, projection, { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 });
                if (!url) continue;

                try {
                    const res = await fetch(url);
                    const data = await res.json();
                    if (data.features?.length > 0) {
                        const f = data.features[0];
                        const tableName = config.layers.includes(':') ? config.layers.split(':').pop() : config.layers;
                        handleSelectResult({ 
                            id: f.id, 
                            gid: f.properties.gid || parseInt(f.id.split('.').pop()||'0'), 
                            geometry: f.geometry, 
                            properties: { ...f.properties, tableName } 
                        }, evt.coordinate);
                        foundParcel = true;
                    }
                } catch (e) { console.error("Query fail:", lid, e); }
            }
            setIsQuerying(false);
        });

        map.on('pointermove', (evt) => { if (!evt.dragging) setMouseCoord(proj.toLonLat(evt.coordinate)); });
        map.getView().on('change:rotation', () => setMapRotation(map.getView().getRotation()));
        map.getView().on('change:resolution', () => setMapZoom(map.getView().getZoom() || 0));

        const resizeObserver = new ResizeObserver(() => map.updateSize());
        resizeObserver.observe(mapElement.current);
        mapInstance.current = map;
        initData();
        return () => resizeObserver.disconnect();
    }, [handleSelectResult]);

    useEffect(() => {
        if (!mapInstance.current || !measureMode) { if (drawInteraction.current) mapInstance.current?.removeInteraction(drawInteraction.current); return; }
        const map = mapInstance.current;
        drawInteraction.current = new Draw({ source: measureSource.current, type: measureMode, style: measureStyle });
        map.addInteraction(drawInteraction.current);
        let listener: any;
        drawInteraction.current.on('drawstart', (evt) => {
            const feature = evt.feature;
            const tooltipElement = document.createElement('div');
            tooltipElement.className = 'bg-black/80 text-white px-2 py-1 rounded text-[10px] font-bold shadow-xl backdrop-blur-sm border border-white/20 pointer-events-none whitespace-nowrap';
            const tooltip = new Overlay({ element: tooltipElement, offset: [0, -15], positioning: 'bottom-center', stopEvent: false, insertFirst: false });
            map.addOverlay(tooltip);
            listener = feature.getGeometry()?.on('change', (evt: any) => {
                const geom = evt.target;
                let output = ''; let tooltipCoord: Coordinate | undefined;
                if (geom instanceof Polygon) { output = (getArea(geom) > 10000 ? (getArea(geom)/10000).toFixed(2) + ' ha' : getArea(geom).toFixed(2) + ' m²'); tooltipCoord = geom.getInteriorPoint().getCoordinates(); }
                else if (geom instanceof LineString) { output = (getLength(geom) > 1000 ? (getLength(geom)/1000).toFixed(2) + ' km' : getLength(geom).toFixed(2) + ' m'); tooltipCoord = geom.getLastCoordinate(); }
                tooltipElement.innerHTML = output; if (tooltipCoord) tooltip.setPosition(tooltipCoord);
            });
        });
        drawInteraction.current.on('drawend', () => { if (listener) unByKey(listener); setMeasureMode(null); });
        return () => { if (drawInteraction.current) map.removeInteraction(drawInteraction.current); };
    }, [measureMode]);

    useEffect(() => {
        if (!baseLayerRef.current || !activeBasemapId || basemaps.length === 0) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM({ crossOrigin: 'anonymous' });
        else {
            const rawUrl = config.url.startsWith('/') ? `${API_URL}${config.url}` : config.url;
            const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(rawUrl)}`.split('%7Bz%7D').join('{z}').split('%7Bx%7D').join('{x}').split('%7By%7D').join('{y}');
            source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
        }
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!wmsLayerGroup.current) return;
        const olLayers = availableLayers.filter(l => visibleLayerIds.includes(l.id)).map(config => {
            let source;
            if (config.type === 'XYZ') {
                const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`.split('%7Bz%7D').join('{z}').split('%7Bx%7D').join('{x}').split('%7By%7D').join('{y}');
                source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
            } else {
                source = new TileWMS({ 
                    url: `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`, 
                    params: { 'LAYERS': config.layers, 'TILED': true, 'TRANSPARENT': true, 'FORMAT': 'image/png', 't': wmsCacheBust }, 
                    crossOrigin: 'anonymous' 
                });
            }
            let zIndex = config.category === 'PLANNING' ? 100 : 10;
            if (activeLayerId === config.id) zIndex += 50;
            const layer = new TileLayer({ source: source, opacity: Number(config.opacity ?? 1), zIndex: zIndex });
            layer.set('layerId', config.id);
            return layer;
        });
        wmsLayerGroup.current.setLayers(new Collection(olLayers));
    }, [availableLayers, visibleLayerIds, activeLayerId, wmsCacheBust]);

    return (
        <div className="relative w-full h-full bg-slate-950 flex flex-col min-h-0 overflow-hidden font-sans">
            {isInitialLoading && (
                <div className="absolute inset-0 z-[1000] bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={48} />
                    <p className="font-display uppercase tracking-[0.3em] text-[10px] text-blue-400 font-black animate-pulse">GeoMaster Engine Loading...</p>
                </div>
            )}

            {isQuerying && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 z-[400] bg-slate-900/90 backdrop-blur-md border border-blue-500/30 px-5 py-3 rounded-2xl shadow-[0_0_40px_rgba(37,99,235,0.3)] flex items-center gap-3 animate-in fade-in slide-in-from-bottom-4 duration-300">
                    <div className="relative">
                        <Loader2 className="animate-spin text-blue-500" size={20} />
                        <div className="absolute inset-0 flex items-center justify-center">
                            <div className="w-1.5 h-1.5 bg-white rounded-full animate-ping"></div>
                        </div>
                    </div>
                    <span className="text-[11px] font-black text-white uppercase tracking-[0.2em] whitespace-nowrap">Đang lấy thông tin thửa đất...</span>
                </div>
            )}

            <div className="absolute bottom-6 left-6 z-[400] flex flex-col gap-2 pointer-events-none">
                {mouseCoord && (
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-3 py-1.5 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300">
                        <div className="flex items-center gap-1.5 text-blue-400"><MousePointer2 size={12}/><span className="text-[9px] font-black uppercase tracking-[0.1em]">Tọa độ</span></div>
                        <div className="flex gap-4 font-mono text-[11px] font-bold text-gray-100">
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">X:</span><span>{mouseCoord[0].toFixed(6)}</span></div>
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">Y:</span><span>{mouseCoord[1].toFixed(6)}</span></div>
                        </div>
                    </div>
                )}
                <div className="w-fit bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-2.5 py-1 rounded-lg flex items-center gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Zoom: <span className="text-white ml-1">{Math.round(mapZoom)}</span></span>
                </div>
            </div>
            {isPrinting && ( <div className="absolute inset-0 z-[2000] bg-black/70 backdrop-blur-md flex flex-col items-center justify-center text-white gap-4"> <RefreshCw className="animate-spin text-blue-500" size={64} /> <div className="text-center"> <p className="font-display font-bold text-xl uppercase tracking-tighter">Đang nạp dữ liệu trích lục</p> </div> </div> )}
            <div ref={mapElement} className="flex-1 w-full relative" />
            <MeasureTools activeMode={measureMode} onModeChange={setMeasureMode} onClear={() => measureSource.current.clear()} />
            <div ref={popupElement} className="absolute bottom-0 left-0 pointer-events-none"> {selectedParcel && ( <div className="pointer-events-auto"> <ParcelPopup parcel={selectedParcel} user={user} onClose={() => { overlayInstance.current?.setPosition(undefined); setSelectedParcel(null); highlightLayer.current?.getSource()?.clear(); }} onPrint={p => { setPrintingParcel(p); setIsPrinting(true); setTimeout(()=>setIsPrinting(false), 2000); }} onEdit={handleOpenEdit} /> </div> )} </div>
            <div className="fixed -left-[4000px] top-0 opacity-0 pointer-events-none overflow-hidden"> {printingParcel && <PrintTemplate parcel={printingParcel} user={user} systemSettings={systemSettings} />} </div>
            <div className="absolute bottom-6 right-6 z-[400] flex flex-col gap-3">
                {Math.abs(mapRotation) > 0.01 && ( <button onClick={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 500 })} className="p-3 bg-white rounded-full shadow-2xl text-orange-600 hover:bg-orange-50 transition-all"><Compass size={24} style={{ transform: `rotate(${-mapRotation}rad)` }}/></button> )}
                <div className="flex flex-col bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden"> <button onClick={() => mapInstance.current?.getView().animate({ zoom: (mapInstance.current?.getView().getZoom() || 0) + 1, duration: 250 })} className="p-3.5 text-gray-700 hover:bg-gray-50 border-b border-gray-100 transition-colors"><Plus size={20}/></button> <button onClick={() => mapInstance.current?.getView().animate({ zoom: (mapInstance.current?.getView().getZoom() || 0) - 1, duration: 250 })} className="p-3.5 text-gray-700 hover:bg-gray-50 transition-colors"><Minus size={20}/></button> </div>
                <button onClick={() => {}} className={`p-3.5 rounded-full shadow-2xl text-white bg-blue-600 hover:bg-blue-700 transition-all`}><Crosshair size={24}/></button>
            </div>
            <SearchPanel isOpen={isSearchOpen} onToggle={() => setIsSearchOpen(!isSearchOpen)} spatialTables={spatialTables} onSelectResult={p => handleSelectResult(p)} onSearchCoordinate={(lat, lon) => mapInstance.current?.getView().animate({ center: proj.fromLonLat([lon, lat]), zoom: 18, duration: 1000 })} />
            <LayerControl isOpen={isLayerMenuOpen} onToggleMenu={() => setIsLayerMenuOpen(!isLayerMenuOpen)} basemaps={basemaps} activeBasemapId={activeBasemapId} onBaseLayerChange={setActiveBasemapId} availableLayers={availableLayers} visibleLayerIds={visibleLayerIds} activeLayerId={activeLayerId} onToggleWMS={id => setVisibleLayerIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id])} onSetActiveWMS={handleActivateLayer} onOpacityChange={(id, opacity) => setAvailableLayers(prev => prev.map(l => l.id === id ? { ...l, opacity } : l))} />

            <ParcelForm isOpen={isEditOpen} onClose={() => setIsEditOpen(false)} editingId={editFormData.gid || null} formData={editFormData} setFormData={setEditFormData} handleSubmit={handleUpdateParcel} loading={editLoading} />

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[2000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'info' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}
                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95">OK</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MapPage;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, LandParcel, WMSLayerConfig, BasemapConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { parcelApi, ParcelDTO } from '../services/parcelApi';
import { Loader2, Crosshair, Map as MapIcon, Layers as LayersIcon, Printer, Plus, Minus, Compass, AlertCircle, RefreshCw, Zap, Search, Fingerprint, MousePointer2, Navigation2, ArrowRight, MapPin, CheckCircle2, AlertTriangle, Info, Save, FileDown } from 'lucide-react';
import proj4 from "proj4";
import { register } from 'ol/proj/proj4';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

// Components
import ParcelPopup from '../components/map/ParcelPopup';
import SearchPanel from '../components/map/SearchPanel';
import LayerControl from '../components/map/LayerControl';
import PrintTemplate from '../components/map/PrintTemplate';
import MeasureTools from '../components/map/MeasureTools';
import ParcelForm from '../components/admin/parcel/ParcelForm';

// OpenLayers
import Map from 'ol/Map';
import View from 'ol/View';
import Overlay from 'ol/Overlay';
import Feature from 'ol/Feature';
import { Tile as TileLayer, Vector as VectorLayer, Group as LayerGroup } from 'ol/layer';
import { OSM, TileWMS, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import { Point, LineString, Polygon, Circle as GeomCircle } from 'ol/geom';
import GeoJSON from 'ol/format/GeoJSON';
import { defaults as defaultControls } from 'ol/control/defaults';
import Collection from 'ol/Collection';
import { isEmpty as isExtentEmpty, getCenter as getExtentCenter } from 'ol/extent';
import { Coordinate } from 'ol/coordinate';
import Draw from 'ol/interaction/Draw';
import { getArea, getLength } from 'ol/sphere';
import { unByKey } from 'ol/Observable';

// Đăng ký VN-2000 (Kinh tuyến trục 105.75 cho Bình Dương/HCM)
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const MapPage: React.FC<{ user: User | null; systemSettings?: Record<string, string> }> = ({ user, systemSettings }) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const popupElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);

    // Refs for Map Events
    const activeLayerIdRef = useRef<string | null>(null);
    const availableLayersRef = useRef<WMSLayerConfig[]>([]);
    const visibleLayerIdsRef = useRef<string[]>([]);

    const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const locationLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const measureSource = useRef<VectorSource>(new VectorSource());
    const wmsLayerGroup = useRef<LayerGroup | null>(null);
    const baseLayerRef = useRef<TileLayer<any> | null>(null);
    const overlayInstance = useRef<Overlay | null>(null);

    const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
    const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
    const [activeLayerId, setActiveLayerId] = useState<string | null>(null);

    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState<string>('');

    const [spatialTables, setSpatialTables] = useState<any[]>([]);
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);
    const [selectedParcel, setSelectedParcel] = useState<LandParcel | null>(null);
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isQuerying, setIsQuerying] = useState(false);
    const [isLocating, setIsLocating] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [printingParcel, setPrintingParcel] = useState<LandParcel | null>(null);
    const [mapRotation, setMapRotation] = useState(0);
    const [mapZoom, setMapZoom] = useState(0);
    const [mouseCoord, setMouseCoord] = useState<Coordinate | null>(null);
    const [wmsCacheBust, setWmsCacheBust] = useState(Date.now());

    const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);
    const measureModeRef = useRef<'LineString' | 'Polygon' | null>(null);
    const drawInteraction = useRef<Draw | null>(null);

    // Edit State
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [editFormData, setEditFormData] = useState<ParcelDTO>({ sothua: '', sodoto: '' });
    const [editLoading, setEditLoading] = useState(false);
    const [dialog, setDialog] = useState<{ isOpen: boolean; type: 'success' | 'error' | 'info'; title: string; message: string; }>({ isOpen: false, type: 'info', title: '', message: '' });

    // Sync state to refs
    useEffect(() => { availableLayersRef.current = availableLayers; }, [availableLayers]);
    useEffect(() => { activeLayerIdRef.current = activeLayerId; }, [activeLayerId]);
    useEffect(() => { visibleLayerIdsRef.current = visibleLayerIds; }, [visibleLayerIds]);
    useEffect(() => { measureModeRef.current = measureMode; }, [measureMode]);

    const highlightStyle = new style.Style({
        stroke: new style.Stroke({ color: '#00ffff', width: 4 }),
        fill: new style.Fill({ color: 'rgba(0, 255, 255, 0.2)' }),
        image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#00ffff' }), stroke: new style.Stroke({color: '#ffffff', width: 2}) })
    });

    const locationStyle = (feature: any) => {
        const type = feature.get('type');
        if (type === 'accuracy') return new style.Style({ fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.1)' }), stroke: new style.Stroke({ color: 'rgba(59, 130, 246, 0.3)', width: 1 }) });
        if (type === 'search_result') return new style.Style({ image: new style.Icon({ anchor: [0.5, 1], src: 'https://raw.githubusercontent.com/lucide-react/lucide/main/icons/map-pin.svg', color: '#ef4444', scale: 2 }), text: new style.Text({ text: '📍', scale: 2, offsetY: -10 }) });
        return new style.Style({ image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#3b82f6' }), stroke: new style.Stroke({ color: '#fff', width: 3 }) }) });
    };

    const measureStyle = new style.Style({
        fill: new style.Fill({ color: 'rgba(59, 130, 246, 0.2)' }),
        stroke: new style.Stroke({ color: '#3b82f6', lineDash: [10, 10], width: 3 }),
        image: new style.Circle({ radius: 5, stroke: new style.Stroke({ color: '#3b82f6', width: 2 }), fill: new style.Fill({ color: '#fff' }) })
    });

    const smartMapProperties = (props: any) => {
        const findVal = (keys: string[]) => {
            for (const k of keys) {
                if (props[k] !== undefined && props[k] !== null && props[k] !== '') return props[k];
                const lower = k.toLowerCase();
                if (props[lower] !== undefined && props[lower] !== null && props[lower] !== '') return props[lower];
            }
            return null;
        };
        return {
            ...props,
            so_to: findVal(['sodoto', 'so_to', 'shbando', 'sh_ban_do', 'tobando', 'tờ', 'số tờ', 'so_to_ban_do']),
            so_thua: findVal(['sothua', 'so_thua', 'shthua', 'sh_thua', 'thửa', 'số thửa', 'so_thu_tu_thua']),
            ownerName: findVal(['tenchu', 'ten_chu', 'ten_chu_sd', 'owner', 'chủ sở hữu', 'chusudung']),
            area: parseFloat(findVal(['dientich', 'dien_tich', 'area', 'diện tích', 'shape_area', 'dt_phaply']) || 0),
            landType: findVal(['loaidat', 'kyhieumucd', 'mucdich', 'loại đất', 'mdsd']) || 'N/A',
            address: findVal(['diachi', 'dia_chi', 'dc', 'địa chỉ', 'vitri']) || ''
        };
    };

    const handleSelectResult = useCallback((parcel: LandParcel, fallbackCoord?: Coordinate) => {
        if (!mapInstance.current || !highlightLayer.current) return;
        const normalizedParcel = { ...parcel, properties: smartMapProperties(parcel.properties) };
        setSelectedParcel(normalizedParcel);
        const source = highlightLayer.current.getSource();
        source?.clear();
        let popupPos = fallbackCoord;
        if (parcel.geometry) {
            try {
                const format = new GeoJSON();
                let dataProj = 'EPSG:4326';
                let rawCoords: any = null;
                if (parcel.geometry.type === 'Polygon') rawCoords = parcel.geometry.coordinates[0][0];
                else if (parcel.geometry.type === 'MultiPolygon') rawCoords = parcel.geometry.coordinates[0][0][0];
                else if (parcel.geometry.type === 'Point') rawCoords = parcel.geometry.coordinates;

                if (rawCoords) {
                    const x = Math.abs(rawCoords[0]);
                    const y = Math.abs(rawCoords[1]);
                    if (x > 2000000 || y > 2000000) dataProj = 'EPSG:3857';
                    else if ((x > 300000 && x < 900000) || (y > 1000000 && y < 2000000)) dataProj = 'EPSG:9210';
                }

                const geometry = format.readGeometry(parcel.geometry, { dataProjection: dataProj, featureProjection: 'EPSG:3857' });
                if (geometry) {
                    source?.addFeature(new Feature({ geometry }));
                    const extent = geometry.getExtent();
                    if (extent && !isExtentEmpty(extent)) {
                        popupPos = getExtentCenter(extent);
                        mapInstance.current.getView().fit(extent, { padding: [120, 120, 120, 120], duration: 800, maxZoom: 21 });
                    }
                }
            } catch (err) { console.error("Geom error:", err); }
        }
        if (popupPos) overlayInstance.current?.setPosition(popupPos);
    }, []);

    const handleOpenEdit = (parcel: LandParcel) => {
        const p = parcel.properties;
        setEditFormData({
            gid: parcel.gid,
            sodoto: (p.so_to || '').toString(),
            sothua: (p.so_thua || '').toString(),
            tenchu: p.ownerName || '',
            diachi: p.address || '',
            loaidat: p.landType || '',
            dientich: p.area || 0,
            geometry: parcel.geometry,
            tableName: p.tableName, 
            file: null
        });
        setIsEditOpen(true);
    };

    const handlePrintParcel = async (parcel: LandParcel) => {
        setIsPrinting(true);
        setPrintingParcel(parcel);

        // Chờ React render PrintTemplate off-screen và Canvas vẽ xong
        setTimeout(async () => {
            const element = document.getElementById('print-template');
            if (!element) {
                setIsPrinting(false);
                setDialog({ isOpen: true, type: 'error', title: 'Lỗi kết xuất', message: 'Không tìm thấy mẫu in trong hệ thống.' });
                return;
            }

            try {
                const canvas = await html2canvas(element, {
                    scale: 2.5,
                    useCORS: true,
                    logging: false,
                    backgroundColor: '#ffffff'
                });

                const imgData = canvas.toDataURL('image/png');
                const pdf = new jsPDF('p', 'mm', 'a4');
                const pdfWidth = pdf.internal.pageSize.getWidth();
                const pdfHeight = (canvas.height * pdfWidth) / canvas.width;

                pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight, undefined, 'FAST');
                pdf.save(`TrichLuc_To${parcel.properties.so_to}_Thua${parcel.properties.so_thua}.pdf`);
            } catch (err) {
                console.error("PDF Export Error:", err);
                setDialog({ isOpen: true, type: 'error', title: 'Lỗi PDF', message: 'Có lỗi xảy ra khi tạo tệp trích lục.' });
            } finally {
                setIsPrinting(false);
                setPrintingParcel(null);
            }
        }, 1800); // 1.8s đủ cho QR code và Canvas hình học vẽ xong
    };

    const handleUpdateParcel = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!editFormData.tableName) {
            setDialog({ isOpen: true, type: 'error', title: 'Lỗi', message: 'Không xác định được bảng dữ liệu.' });
            return;
        }
        setEditLoading(true);
        try {
            if (editFormData.file) {
                await parcelApi.createWithUpload(editFormData.tableName, editFormData);
            } else {
                const { geometry, ...dataOnlyAttrs } = editFormData;
                await parcelApi.update(editFormData.tableName, editFormData.gid!, dataOnlyAttrs);
            }

            if (selectedParcel) {
                const updatedProperties = {
                    ...selectedParcel.properties,
                    so_to: editFormData.sodoto,
                    so_thua: editFormData.sothua,
                    ownerName: editFormData.tenchu,
                    address: editFormData.diachi,
                    landType: editFormData.loaidat,
                    area: editFormData.dientich
                };
                setSelectedParcel({ ...selectedParcel, properties: updatedProperties });
            }

            setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: 'Thông tin thửa đất đã được lưu.' });
            setIsEditOpen(false);
            setWmsCacheBust(Date.now());
        } catch (err: any) {
            setDialog({ isOpen: true, type: 'error', title: 'Thất bại', message: err.message });
        } finally {
            setEditLoading(false);
        }
    };

    const handleActivateLayer = async (id: string) => {
        setActiveLayerId(id);
        if (!visibleLayerIds.includes(id)) setVisibleLayerIds(prev => [...prev, id]);
    };

    const initData = async () => {
        try {
            const [layers, tables, maps] = await Promise.all([
                gisService.getLayers().catch(() => []), 
                gisService.getSpatialTables().catch(() => []),
                gisService.getBasemaps().catch(() => [])
            ]);
            setAvailableLayers(layers);
            setVisibleLayerIds(layers.filter(l => l.visible).map(l => l.id));
            setSpatialTables(tables);
            setBasemaps(maps);
            const defMap = maps.find(m => m.isDefault) || maps[0];
            if (defMap) setActiveBasemapId(defMap.id);
            if (layers.length && !activeLayerId) setActiveLayerId(layers[0].id);
        } catch (e) { console.error(e); } finally { setIsInitialLoading(false); }
    };

    useEffect(() => {
        if (!mapElement.current || mapInstance.current) return;
        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }),
                new LayerGroup({ zIndex: 10 }),
                new VectorLayer({ source: new VectorSource(), zIndex: 10000, style: highlightStyle }),
                new VectorLayer({ source: new VectorSource(), zIndex: 20000, style: locationStyle }),
                new VectorLayer({ source: measureSource.current, zIndex: 30000, style: measureStyle }),
            ],
            view: new View({ center: proj.fromLonLat([106.619, 11.284]), zoom: 13, minZoom: 5, maxZoom: 22 }),
            controls: defaultControls({ attribution: false })
        });

        baseLayerRef.current = map.getLayers().getArray()[0] as TileLayer<any>;
        wmsLayerGroup.current = map.getLayers().getArray()[1] as LayerGroup;
        highlightLayer.current = map.getLayers().getArray()[2] as VectorLayer<VectorSource>;
        locationLayer.current = map.getLayers().getArray()[3] as VectorLayer<VectorSource>;
        overlayInstance.current = new Overlay({ element: popupElement.current!, autoPan: { animation: { duration: 250 } }, positioning: 'bottom-center' });
        map.addOverlay(overlayInstance.current);

        map.on('singleclick', async (evt) => {
            if (measureModeRef.current) return;
            const view = map.getView();
            const resolution = view.getResolution();
            const projection = view.getProjection();
            const currentOlLayers = wmsLayerGroup.current?.getLayers().getArray() || [];
            if (currentOlLayers.length === 0) return;
            let targetLayerIds = [];
            if (activeLayerIdRef.current) targetLayerIds.push(activeLayerIdRef.current);
            visibleLayerIdsRef.current.forEach(id => { if (id !== activeLayerIdRef.current) targetLayerIds.push(id); });
            let foundParcel = false;
            setIsQuerying(true);
            overlayInstance.current?.setPosition(undefined);
            setSelectedParcel(null);
            highlightLayer.current?.getSource()?.clear();
            for (const lid of targetLayerIds) {
                if (foundParcel) break;
                const config = availableLayersRef.current.find(c => c.id === lid);
                if (!config || config.type === 'XYZ') continue;
                const olLayer = currentOlLayers.find(l => l.get('layerId') === lid) as TileLayer<any>;
                if (!olLayer || !olLayer.getSource()?.getFeatureInfoUrl) continue;
                const url = olLayer.getSource().getFeatureInfoUrl(evt.coordinate, resolution!, projection, { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 });
                if (!url) continue;
                try {
                    const res = await fetch(url);
                    const data = await res.json();
                    if (data.features?.length > 0) {
                        const f = data.features[0];
                        const tableName = config.layers.includes(':') ? config.layers.split(':').pop() : config.layers;
                        handleSelectResult({ 
                            id: f.id, 
                            gid: f.properties.gid || parseInt(f.id.split('.').pop()||'0'), 
                            geometry: f.geometry, 
                            properties: { ...f.properties, tableName } 
                        }, evt.coordinate);
                        foundParcel = true;
                    }
                } catch (e) {}
            }
            setIsQuerying(false);
        });

        map.on('pointermove', (evt) => { if (!evt.dragging) setMouseCoord(proj.toLonLat(evt.coordinate)); });
        map.getView().on('change:rotation', () => setMapRotation(map.getView().getRotation()));
        map.getView().on('change:resolution', () => setMapZoom(map.getView().getZoom() || 0));

        const resizeObserver = new ResizeObserver(() => map.updateSize());
        resizeObserver.observe(mapElement.current);
        mapInstance.current = map;
        initData();
        return () => resizeObserver.disconnect();
    }, [handleSelectResult]);

    useEffect(() => {
        if (!mapInstance.current || !measureMode) { if (drawInteraction.current) mapInstance.current?.removeInteraction(drawInteraction.current); return; }
        const map = mapInstance.current;
        drawInteraction.current = new Draw({ source: measureSource.current, type: measureMode, style: measureStyle });
        map.addInteraction(drawInteraction.current);
        let listener: any;
        drawInteraction.current.on('drawstart', (evt) => {
            const feature = evt.feature;
            const tooltipElement = document.createElement('div');
            tooltipElement.className = 'bg-black/80 text-white px-2 py-1 rounded text-[10px] font-bold shadow-xl backdrop-blur-sm border border-white/20 pointer-events-none whitespace-nowrap';
            const tooltip = new Overlay({ element: tooltipElement, offset: [0, -15], positioning: 'bottom-center', stopEvent: false, insertFirst: false });
            map.addOverlay(tooltip);
            listener = feature.getGeometry()?.on('change', (evt: any) => {
                const geom = evt.target;
                let output = ''; let tooltipCoord: Coordinate | undefined;
                if (geom instanceof Polygon) { output = (getArea(geom) > 10000 ? (getArea(geom)/10000).toFixed(2) + ' ha' : getArea(geom).toFixed(2) + ' m²'); tooltipCoord = geom.getInteriorPoint().getCoordinates(); }
                else if (geom instanceof LineString) { output = (getLength(geom) > 1000 ? (getLength(geom)/1000).toFixed(2) + ' km' : getLength(geom).toFixed(2) + ' m'); tooltipCoord = geom.getLastCoordinate(); }
                tooltipElement.innerHTML = output; if (tooltipCoord) tooltip.setPosition(tooltipCoord);
            });
        });
        drawInteraction.current.on('drawend', () => { if (listener) unByKey(listener); setMeasureMode(null); });
        return () => { if (drawInteraction.current) map.removeInteraction(drawInteraction.current); };
    }, [measureMode]);

    useEffect(() => {
        if (!baseLayerRef.current || !activeBasemapId || basemaps.length === 0) return;
        const config = basemaps.find(m => m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM({ crossOrigin: 'anonymous' });
        else {
            const rawUrl = config.url.startsWith('/') ? `${API_URL}${config.url}` : config.url;
            const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(rawUrl)}`.split('%7Bz%7D').join('{z}').split('%7Bx%7D').join('{x}').split('%7By%7D').join('{y}');
            source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
        }
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    useEffect(() => {
        if (!wmsLayerGroup.current) return;
        const olLayers = availableLayers.filter(l => visibleLayerIds.includes(l.id)).map(config => {
            let source;
            if (config.type === 'XYZ') {
                const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`.split('%7Bz%7D').join('{z}').split('%7Bx%7D').join('{x}').split('%7By%7D').join('{y}');
                source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
            } else {
                source = new TileWMS({ 
                    url: `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`, 
                    params: { 'LAYERS': config.layers, 'TILED': true, 'TRANSPARENT': true, 'FORMAT': 'image/png', 't': wmsCacheBust }, 
                    crossOrigin: 'anonymous' 
                });
            }
            let zIndex = config.category === 'PLANNING' ? 100 : 10;
            if (activeLayerId === config.id) zIndex += 50;
            const layer = new TileLayer({ source: source, opacity: Number(config.opacity ?? 1), zIndex: zIndex });
            layer.set('layerId', config.id);
            return layer;
        });
        wmsLayerGroup.current.setLayers(new Collection(olLayers));
    }, [availableLayers, visibleLayerIds, activeLayerId, wmsCacheBust]);

    return (
        <div className="relative w-full h-full bg-slate-950 flex flex-col min-h-0 overflow-hidden font-sans">
            {isInitialLoading && (
                <div className="absolute inset-0 z-[1000] bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={48} />
                    <p className="font-display uppercase tracking-[0.3em] text-[10px] text-blue-400 font-black animate-pulse">GeoMaster Engine Loading...</p>
                </div>
            )}

            {isQuerying && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 z-[400] bg-slate-900/90 backdrop-blur-md border border-blue-500/30 px-5 py-3 rounded-2xl shadow-[0_0_40px_rgba(37,99,235,0.3)] flex items-center gap-3 animate-in fade-in slide-in-from-bottom-4 duration-300">
                    <Loader2 className="animate-spin text-blue-500" size={20} />
                    <span className="text-[11px] font-black text-white uppercase tracking-[0.2em] whitespace-nowrap">Đang lấy thông tin thửa đất...</span>
                </div>
            )}

            {isPrinting && (
                <div className="absolute inset-0 z-[2000] bg-black/80 backdrop-blur-xl flex flex-col items-center justify-center text-white gap-6 animate-in fade-in duration-500">
                    <div className="relative">
                        <Printer className="animate-bounce text-blue-500" size={64} />
                        <div className="absolute -top-2 -right-2">
                            <Zap className="text-yellow-400 animate-pulse" size={24}/>
                        </div>
                    </div>
                    <div className="text-center space-y-2">
                        <p className="font-display font-black text-2xl uppercase tracking-tighter">Đang kết xuất trích lục</p>
                        <p className="text-blue-400 text-xs font-bold uppercase tracking-[0.2em] animate-pulse">Vui lòng không đóng trình duyệt...</p>
                    </div>
                </div>
            )}

            <div className="absolute bottom-6 left-6 z-[400] flex flex-col gap-2 pointer-events-none">
                {mouseCoord && (
                    <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-3 py-1.5 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300">
                        <div className="flex items-center gap-1.5 text-blue-400"><MousePointer2 size={12}/><span className="text-[9px] font-black uppercase tracking-[0.1em]">Tọa độ</span></div>
                        <div className="flex gap-4 font-mono text-[11px] font-bold text-gray-100">
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">X:</span><span>{mouseCoord[0].toFixed(6)}</span></div>
                            <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">Y:</span><span>{mouseCoord[1].toFixed(6)}</span></div>
                        </div>
                    </div>
                )}
                <div className="w-fit bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-2.5 py-1 rounded-lg flex items-center gap-2">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div>
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Zoom: <span className="text-white ml-1">{Math.round(mapZoom)}</span></span>
                </div>
            </div>

            <div ref={mapElement} className="flex-1 w-full relative" />
            <MeasureTools activeMode={measureMode} onModeChange={setMeasureMode} onClear={() => measureSource.current.clear()} />

            <div ref={popupElement} className="absolute bottom-0 left-0 pointer-events-none">
                {selectedParcel && (
                    <div className="pointer-events-auto">
                        <ParcelPopup 
                            parcel={selectedParcel} 
                            user={user} 
                            onClose={() => { overlayInstance.current?.setPosition(undefined); setSelectedParcel(null); highlightLayer.current?.getSource()?.clear(); }} 
                            onPrint={handlePrintParcel} 
                            onEdit={handleOpenEdit} 
                        />
                    </div>
                )}
            </div>

            {/* Vùng Render Mẫu In Ẩn */}
            <div className="fixed -left-[4000px] top-0 opacity-0 pointer-events-none overflow-hidden">
                {printingParcel && <PrintTemplate parcel={printingParcel} user={user} systemSettings={systemSettings} />}
            </div>

            <div className="absolute bottom-6 right-6 z-[400] flex flex-col gap-3">
                {Math.abs(mapRotation) > 0.01 && ( <button onClick={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 500 })} className="p-3 bg-white rounded-full shadow-2xl text-orange-600 hover:bg-orange-50 transition-all"><Compass size={24} style={{ transform: `rotate(${-mapRotation}rad)` }}/></button> )}
                <div className="flex flex-col bg-white rounded-2xl shadow-2xl border border-gray-100 overflow-hidden"> <button onClick={() => mapInstance.current?.getView().animate({ zoom: (mapInstance.current?.getView().getZoom() || 0) + 1, duration: 250 })} className="p-3.5 text-gray-700 hover:bg-gray-50 border-b border-gray-100 transition-colors"><Plus size={20}/></button> <button onClick={() => mapInstance.current?.getView().animate({ zoom: (mapInstance.current?.getView().getZoom() || 0) - 1, duration: 250 })} className="p-3.5 text-gray-700 hover:bg-gray-50 transition-colors"><Minus size={20}/></button> </div>
                <button onClick={() => {}} className={`p-3.5 rounded-full shadow-2xl text-white bg-blue-600 hover:bg-blue-700 transition-all`}><Crosshair size={24}/></button>
            </div>

            <SearchPanel isOpen={isSearchOpen} onToggle={() => setIsSearchOpen(!isSearchOpen)} spatialTables={spatialTables} onSelectResult={handleSelectResult} onSearchCoordinate={(lat, lon) => mapInstance.current?.getView().animate({ center: proj.fromLonLat([lon, lat]), zoom: 18, duration: 1000 })} />

            <LayerControl isOpen={isLayerMenuOpen} onToggleMenu={() => setIsLayerMenuOpen(!isLayerMenuOpen)} basemaps={basemaps} activeBasemapId={activeBasemapId} onBaseLayerChange={setActiveBasemapId} availableLayers={availableLayers} visibleLayerIds={visibleLayerIds} activeLayerId={activeLayerId} onToggleWMS={id => setVisibleLayerIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id])} onSetActiveWMS={handleActivateLayer} onOpacityChange={(id, opacity) => setAvailableLayers(prev => prev.map(l => l.id === id ? { ...l, opacity } : l))} />

            <ParcelForm isOpen={isEditOpen} onClose={() => setIsEditOpen(false)} editingId={editFormData.gid || null} formData={editFormData} setFormData={setEditFormData} handleSubmit={handleUpdateParcel} loading={editLoading} />

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[3000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden">
                        <div className="p-8 text-center flex flex-col items-center">
                            {dialog.type === 'success' && <div className="w-14 h-14 bg-emerald-500/20 text-emerald-500 rounded-full flex items-center justify-center mb-4"><CheckCircle2 size={28}/></div>}
                            {dialog.type === 'error' && <div className="w-14 h-14 bg-red-500/20 text-red-500 rounded-full flex items-center justify-center mb-4"><AlertTriangle size={28}/></div>}
                            {dialog.type === 'info' && <div className="w-14 h-14 bg-blue-500/20 text-blue-500 rounded-full flex items-center justify-center mb-4"><Info size={28}/></div>}
                            <h3 className="text-lg font-black text-white uppercase tracking-tight mb-2">{dialog.title}</h3>
                            <p className="text-gray-400 text-xs leading-relaxed mb-6">{dialog.message}</p>
                            <button onClick={() => setDialog({ ...dialog, isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all active:scale-95">OK</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MapPage;

import React, { useEffect, useRef, useState } from 'react';
import { LandParcel, User } from '../../types';
import QRCode from 'qrcode';

interface PrintTemplateProps {
    parcel: LandParcel;
    user?: User | null;
    systemSettings?: Record<string, string>;
}

interface GeometryPoint {
    id: number;
    x: number;
    y: number;
    distanceNext?: string;
}

const PrintTemplate: React.FC<PrintTemplateProps> = ({ parcel, user, systemSettings }) => {
    const formData = parcel.properties;
    const parcelCanvasRef = useRef<HTMLCanvasElement>(null);
    const [geometryPoints, setGeometryPoints] = useState<GeometryPoint[]>([]);
    const [qrCodeUrl, setQrCodeUrl] = useState<string>('');

    const getAttribute = (data: any, keys: string[]) => {
        for (const key of keys) {
            if (data[key] !== undefined && data[key] !== null && data[key] !== '') return data[key];
        }
        return "";
    };

    useEffect(() => {
        // Generate QR Code for Print Verification
        const generateQR = async () => {
            try {
                const verificationContent = `VERIFY: ${parcel.id}\nPARCEL: ${formData.so_to}/${formData.so_thua}\nWEBGIS GEOMASTER AUTHENTICATED`;
                const url = await QRCode.toDataURL(verificationContent, {
                    width: 120,
                    margin: 0,
                    color: { dark: '#000000', light: '#ffffff' }
                });
                setQrCodeUrl(url);
            } catch (err) {
                console.error("QR Print Error:", err);
            }
        };
        generateQR();

        if (!parcel.geometry || !parcel.geometry.coordinates) return;

        let rawCoords: any[] = [];
        if (parcel.geometry.type === 'Polygon') {
            rawCoords = parcel.geometry.coordinates[0];
        } else if (parcel.geometry.type === 'MultiPolygon') {
            rawCoords = parcel.geometry.coordinates[0][0];
        }

        if (rawCoords.length > 0) {
            const isClosed = JSON.stringify(rawCoords[0]) === JSON.stringify(rawCoords[rawCoords.length - 1]);
            const filteredCoords = (isClosed && rawCoords.length > 1) ? rawCoords.slice(0, -1) : rawCoords;

            const points: GeometryPoint[] = filteredCoords.map((c: any, i: number) => ({
                id: i + 1,
                x: c[0],
                y: c[1]
            }));

            const isWGS84 = points[0].x > 100 && points[0].x < 110;

            for (let i = 0; i < points.length; i++) {
                const p1 = points[i];
                const p2 = points[i + 1] || points[0]; 

                let dist = 0;
                if (isWGS84) {
                    const avgLat = (p1.y + p2.y) / 2;
                    const cosLat = Math.cos(avgLat * Math.PI / 180);
                    const dx = (p2.x - p1.x) * 111319.9 * cosLat;
                    const dy = (p2.y - p1.y) * 111319.9;
                    dist = Math.sqrt(dx * dx + dy * dy);
                } else {
                    const dx = p2.x - p1.x;
                    const dy = p2.y - p1.y;
                    dist = Math.sqrt(dx * dx + dy * dy);
                }
                p1.distanceNext = dist.toFixed(2);
            }
            setGeometryPoints(points);

            const canvas = parcelCanvasRef.current;
            if (canvas) {
                const ctx = canvas.getContext('2d');
                if (ctx) {
                    ctx.clearRect(0, 0, canvas.width, canvas.height);

                    const xs = points.map(p => p.x);
                    const ys = points.map(p => p.y);
                    const minX = Math.min(...xs), maxX = Math.max(...xs);
                    const minY = Math.min(...ys), maxY = Math.max(...ys);
                    const rangeX = maxX - minX || 0.000001;
                    const rangeY = maxY - minY || 0.000001;

                    const padding = 40; // Giảm padding để hình vẽ to hơn
                    const availableW = canvas.width - padding * 2;
                    const availableH = canvas.height - padding * 2;
                    const scale = Math.min(availableW / rangeX, availableH / rangeY);

                    const offsetX = (canvas.width - rangeX * scale) / 2;
                    const offsetY = (canvas.height - rangeY * scale) / 2;

                    const tx = (x: number) => offsetX + (x - minX) * scale;
                    const ty = (y: number) => canvas.height - (offsetY + (y - minY) * scale);

                    ctx.beginPath();
                    ctx.lineWidth = 2.5;
                    ctx.strokeStyle = "#000000";
                    ctx.lineJoin = "round";
                    points.forEach((pt, idx) => {
                        const px = tx(pt.x);
                        const py = ty(pt.y);
                        if (idx === 0) ctx.moveTo(px, py);
                        else ctx.lineTo(px, py);
                    });
                    ctx.closePath();
                    ctx.stroke();

                    points.forEach((pt, idx) => {
                        const pNext = points[idx + 1] || points[0];
                        const x1 = tx(pt.x), y1 = ty(pt.y);
                        const x2 = tx(pNext.x), y2 = ty(pNext.y);

                        ctx.beginPath();
                        ctx.arc(x1, y1, 2.5, 0, Math.PI * 2);
                        ctx.fillStyle = "#000000";
                        ctx.fill();

                        ctx.font = "bold 12px Arial";
                        ctx.fillStyle = "#000000";
                        const anglePoint = Math.atan2(y1 - (canvas.height/2), x1 - (canvas.width/2));
                        ctx.fillText(pt.id.toString(), x1 + Math.cos(anglePoint) * 15 - 4, y1 + Math.sin(anglePoint) * 15 + 4);

                        if (pt.distanceNext) {
                            const midX = (x1 + x2) / 2;
                            const midY = (y1 + y2) / 2;
                            ctx.save();
                            ctx.translate(midX, midY);
                            let angle = Math.atan2(y2 - y1, x2 - x1);
                            if (angle > Math.PI/2 || angle < -Math.PI/2) angle += Math.PI;
                            ctx.rotate(angle);
                            ctx.font = "italic bold 10px Arial";
                            ctx.textAlign = "center";
                            ctx.fillStyle = "#000000";
                            ctx.fillText(pt.distanceNext, 0, -5);
                            ctx.restore();
                        }
                    });
                }
            }
        }
    }, [parcel, formData.so_to, formData.so_thua]);

