const MapPage: React.FC<{ user: User | null; systemSettings?: Record<string, string> }> = ({ user, systemSettings }) => {
    const popupElement = useRef<HTMLDivElement>(null);
    const overlayInstance = useRef<Overlay | null>(null);

    // State quản lý danh sách lớp
    const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
    const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
    const [activeLayerId, setActiveLayerId] = useState<string | null>(null);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState<string>('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);

    // UI State
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);
    const [isQuerying, setIsQuerying] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [printingParcel, setPrintingParcel] = useState<LandParcel | null>(null);
    const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);
    const [dialog, setDialog] = useState<any>({ isOpen: false });

    // Khởi tạo Hook lõi
    const { 
        mapElement, 
        mapInstance, 
        highlightLayer, 
        measureSource, 
        mapRotation, 
        mapZoom, 
        mouseCoord, 
        zoomToLayer, 
        getFeatureInfoUrl,
        refreshWMS 
    } = useMapCore(availableLayers, basemaps, activeBasemapId, visibleLayerIds, activeLayerId);

    // Khởi tạo Hook nghiệp vụ
    useEffect(() => {
        if (!overlayInstance.current && popupElement.current) {
            overlayInstance.current = new Overlay({ 
                element: popupElement.current, 
                autoPan: { animation: { duration: 250 } }, 
                positioning: 'bottom-center' 
            });
            mapInstance.current?.addOverlay(overlayInstance.current);
        }
    }, [mapInstance.current]);

    const { 
        selectedParcel, 
        setSelectedParcel, 
        handleSelectResult, 
        isEditOpen, 
        setIsEditOpen, 
        editFormData, 
        setEditFormData, 
        editLoading, 
        setEditLoading, 
        openEdit 
    } = useParcelLogic(mapInstance.current, highlightLayer.current, overlayInstance.current);

    // Xử lý Sự kiện Click Bản đồ
    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;

        const clickHandler = async (evt: any) => {
            if (measureMode) return;

            // Tìm trong các lớp đang hiện, ưu tiên lớp Active
            let targetIds = activeLayerId ? [activeLayerId, ...visibleLayerIds.filter(id => id !== activeLayerId)] : visibleLayerIds;
            if (targetIds.length === 0) return;

            setIsQuerying(true);
            overlayInstance.current?.setPosition(undefined);
            setSelectedParcel(null);
            highlightLayer.current?.getSource()?.clear();

            let found = false;
            for (const lid of targetIds) {
                if (found) break;

                const infoUrl = getFeatureInfoUrl(evt.coordinate, lid);
                if (!infoUrl) continue;

                try {
                    const res = await fetch(infoUrl);
                    const data = await res.json();
                    if (data.features?.length > 0) {
                        const f = data.features[0];
                        const config = availableLayers.find(c => c.id === lid);
                        const tableName = config?.layers.includes(':') ? config.layers.split(':').pop() : config?.layers;

                        handleSelectResult({ 
                            id: f.id, 
                            gid: f.properties.gid || parseInt(f.id.split('.').pop() || '0'), 
                            geometry: f.geometry, 
                            properties: { ...f.properties, tableName } 
                        }, evt.coordinate);
                        found = true;
                    }
                } catch (e) {
                    console.error("Feature info fetch error:", e);
                }
            }
            setIsQuerying(false);
        };

        map.on('singleclick', clickHandler);
        return () => map.un('singleclick', clickHandler);
    }, [mapInstance.current, measureMode, activeLayerId, visibleLayerIds, availableLayers, handleSelectResult, getFeatureInfoUrl]);

    // Đo đạc Tools
    useEffect(() => {
        if (!mapInstance.current || !measureMode) return;
        const draw = new Draw({ source: measureSource.current, type: measureMode });
        mapInstance.current.addInteraction(draw);
        draw.on('drawend', () => setMeasureMode(null));
        return () => {
            if (mapInstance.current) {
                mapInstance.current.removeInteraction(draw);
            }
        };
    }, [measureMode]);

    // Tải dữ liệu ban đầu
    const initData = async () => {
        try {
            const [layers, tables, maps] = await Promise.all([
                gisService.getLayers().catch(() => []), 
                gisService.getSpatialTables().catch(() => []), 
                gisService.getBasemaps().catch(() => [])
            ]);
            setAvailableLayers(layers);
            setVisibleLayerIds(layers.filter(l => l.visible).map(l => l.id));
            setSpatialTables(tables);
            setBasemaps(maps);
            const defMap = maps.find(m => m.isDefault) || maps[0];
            if (defMap) setActiveBasemapId(defMap.id);
            if (layers.length && !activeLayerId) setActiveLayerId(layers[0].id);
        } catch (e) {} finally { setIsInitialLoading(false); }
    };
    useEffect(() => { initData(); }, []);

    // Action: In ấn
    const handlePrint = async (parcel: LandParcel) => {
        setIsPrinting(true); setPrintingParcel(parcel);
        setTimeout(async () => {
            const el = document.getElementById('print-template');
            if (el) {
                try {
                    const canvas = await html2canvas(el, { scale: 3, useCORS: true, backgroundColor: '#ffffff' });
                    const pdf = new jsPDF('p', 'mm', 'a4');
                    pdf.addImage(canvas.toDataURL('image/png'), 'PNG', 0, 0, 210, (canvas.height * 210) / canvas.width);
                    pdf.save(`Parcel_${parcel.properties.so_thua}.pdf`);
                } catch (err) {
                    console.error("PDF Export Error:", err);
                }
            }
            setIsPrinting(false); setPrintingParcel(null);
        }, 2000);
    };

    // Action: Lưu cập nhật
    const handleUpdateParcel = async (e: React.FormEvent) => {
        e.preventDefault();
        setEditLoading(true);
        try {
            await parcelApi.update(editFormData.tableName!, editFormData.gid!, editFormData);
            setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: 'Dữ liệu đã được cập nhật.' });
            setIsEditOpen(false); refreshWMS();
        } catch (err: any) {
            setDialog({ isOpen: true, type: 'error', title: 'Thất bại', message: err.message });
        } finally { setEditLoading(false); }
    };

    return (
        <div className="relative w-full h-full bg-slate-950 flex flex-col overflow-hidden font-sans">
            {isInitialLoading && (
                <div className="absolute inset-0 z-[1000] bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={48} />
                    <p className="font-display uppercase tracking-[0.3em] text-[10px] text-blue-400 font-black animate-pulse">GeoMaster Engine Loading...</p>
                </div>
            )}

            {isQuerying && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 z-[400] bg-slate-900/90 backdrop-blur-md border border-blue-500/30 px-5 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300">
                    <Loader2 className="animate-spin text-blue-500" size={20} />
                    <span className="text-[11px] font-black text-white uppercase tracking-[0.2em]">Đang lấy thông tin...</span>
                </div>
            )}

            <div ref={mapElement} className="flex-1 w-full relative" />

            {/* Overlay Components */}
            <MeasureTools activeMode={measureMode} onModeChange={setMeasureMode} onClear={() => measureSource.current.clear()} />

            {mouseCoord && (
                <div className="absolute bottom-6 left-6 z-[400] bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-3 py-1.5 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300 pointer-events-none">
                    <div className="flex items-center gap-1.5 text-blue-400"><MousePointer2 size={12}/><span className="text-[9px] font-black uppercase tracking-[0.1em]">Tọa độ</span></div>
                    <div className="flex gap-4 font-mono text-[11px] font-bold text-gray-100">
                        <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">X:</span><span>{mouseCoord[0].toFixed(6)}</span></div>
                        <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">Y:</span><span>{mouseCoord[1].toFixed(6)}</span></div>
                    </div>
                </div>
            )}

            <SearchPanel isOpen={isSearchOpen} onToggle={() => setIsSearchOpen(!isSearchOpen)} spatialTables={spatialTables} onSelectResult={handleSelectResult} onSearchCoordinate={(lat, lon) => mapInstance.current?.getView().animate({ center: proj.fromLonLat([lon, lat]), zoom: 18, duration: 1000 })} />

            <LayerControl 
                isOpen={isLayerMenuOpen} 
                onToggleMenu={() => setIsLayerMenuOpen(!isLayerMenuOpen)} 
                basemaps={basemaps} 
                activeBasemapId={activeBasemapId} 
                onBaseLayerChange={setActiveBasemapId} 
                availableLayers={availableLayers} 
                visibleLayerIds={visibleLayerIds} 
                activeLayerId={activeLayerId} 
                onToggleWMS={id => setVisibleLayerIds(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id])} 
                onSetActiveWMS={id => { 
                    setActiveLayerId(id); 
                    if (!visibleLayerIds.includes(id)) setVisibleLayerIds(p => [...p, id]); 
                    const tbl = availableLayers.find(l=>l.id===id)?.layers.split(':').pop(); 
                    if(tbl) zoomToLayer(tbl); 
                }} 
                onOpacityChange={(id, opacity) => setAvailableLayers(prev => prev.map(l => l.id === id ? { ...l, opacity } : l))} 
            />

            <div ref={popupElement} className="absolute bottom-0 left-0 pointer-events-none">
                {selectedParcel && (
                    <div className="pointer-events-auto">
                        <ParcelPopup parcel={selectedParcel} user={user} onClose={() => { overlayInstance.current?.setPosition(undefined); setSelectedParcel(null); highlightLayer.current?.getSource()?.clear(); }} onPrint={handlePrint} onEdit={openEdit} />
                    </div>
                )}
            </div>

            {/* Print Template Off-screen */}
            <div className="fixed -left-[4000px] top-0 opacity-0 pointer-events-none">
                {printingParcel && <PrintTemplate parcel={printingParcel} user={user} systemSettings={systemSettings} />}
            </div>

            {/* Float Controls */}
            <div className="absolute bottom-6 right-6 z-[400] flex flex-col gap-3">
                {Math.abs(mapRotation) > 0.01 && ( <button onClick={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 500 })} className="p-3 bg-white rounded-full shadow-2xl text-orange-600 hover:bg-orange-50 transition-all"><Compass size={24} style={{ transform: `rotate(${-mapRotation}rad)` }}/></button> )}
                <div className="flex flex-col bg-white rounded-2xl shadow-2xl overflow-hidden border border-gray-100"> 
                    <button onClick={() => mapInstance.current?.getView().animate({ zoom: (mapInstance.current?.getView().getZoom() || 0) + 1, duration: 250 })} className="p-3.5 text-gray-700 hover:bg-gray-50 border-b border-gray-100"><Plus size={20}/></button> 
                    <button onClick={() => mapInstance.current?.getView().animate({ zoom: (mapInstance.current?.getView().getZoom() || 0) - 1, duration: 250 })} className="p-3.5 text-gray-700 hover:bg-gray-50"><Minus size={20}/></button> 
                </div>
            </div>

            <ParcelForm isOpen={isEditOpen} onClose={() => setIsEditOpen(false)} editingId={editFormData.gid || null} formData={editFormData} setFormData={setEditFormData} handleSubmit={handleUpdateParcel} loading={editLoading} />

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[3000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden p-8 text-center">
                        {dialog.type === 'success' ? <CheckCircle2 className="mx-auto text-emerald-500 mb-4" size={48}/> : <AlertTriangle className="mx-auto text-red-500 mb-4" size={48}/>}
                        <h3 className="text-lg font-black text-white uppercase mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">OK</button>
                    </div>
                </div>
            )}
        </div>
    );
};

