interface AdminPageProps {
    systemName?: string;
    logoUrl?: string;
}

const AdminPage: React.FC<AdminPageProps> = ({ systemName, logoUrl }) => {
    const [activeTab, setActiveTab] = useState('PARCEL_MANAGER');
    const [dbStatus, setDbStatus] = useState<any>({ status: 'checking' });
    const [isRefreshing, setIsRefreshing] = useState(false);

    const checkDB = async () => {
        setIsRefreshing(true);
        try {
            const status = await adminService.checkDbConnection();
            setDbStatus(status || { status: 'error', message: 'Không nhận được phản hồi từ server' });
        } catch (e: any) { 
            setDbStatus({ status: 'error', message: e.message || 'Lỗi kết nối API' }); 
        } finally {
            setIsRefreshing(false);
        }
    };

    useEffect(() => {
        checkDB();
    }, []);

    const renderModule = () => {
        switch (activeTab) {
            case 'PARCEL_MANAGER': return <ParcelManager />;
            case 'MENU_MANAGER': return <MenuManager />;
            case 'USERS': return <UserManager />;
            case 'NOTIFICATIONS': return <NotificationManager />;
            case 'PERMISSIONS': return <PermissionManager />;
            case 'BRANCHES': return <BranchManager />;
            case 'PRICES': return <PriceManager />;
            case 'DATA_LAYERS': return <LayerManager dbStatus={dbStatus} />;
            case 'SETTINGS': return <SystemSettingsManager />;
            case 'LOGS': return <LogViewer />;
            default: return <div className="p-8 text-gray-500 italic text-center">Module đang được cập nhật...</div>;
        }
    };

    return (
        <div className="flex h-full bg-gray-900 text-white overflow-hidden font-sans">
            <AdminMenu 
                activeTab={activeTab} 
                onSelect={(tab) => tab && setActiveTab(tab)} 
                systemName={systemName} 
                logoUrl={logoUrl} 
            />

            <div className="flex-1 flex flex-col h-full overflow-hidden bg-gray-900">
                <div className="bg-gray-800 p-4 border-b border-gray-700 flex justify-between items-center shadow-md z-10">
                    <div className="flex flex-col">
                        <h2 className="text-xl font-bold text-gray-100 tracking-tight uppercase">
                            {(activeTab || '').replace('_', ' ')}
                        </h2>
                    </div>

                    <div className="flex items-center gap-3">
                        {dbStatus?.status === 'connected' ? (
                            <div className="text-green-400 text-[10px] md:text-xs flex items-center gap-2 bg-green-900/20 px-3 py-1.5 rounded-full border border-green-800/50">
                                <CheckCircle size={14}/> 
                                <span className="font-mono">{dbStatus?.host || 'localhost'}</span>
                                <span className="text-gray-500">|</span>
                                <span>{dbStatus?.dbName || 'Database'}</span>
                            </div>
                        ) : (
                            <div className="text-red-400 text-[10px] md:text-xs flex flex-col items-end gap-1">
                                <div className="flex items-center gap-1 bg-red-900/20 px-3 py-1 rounded-full border border-red-800/50">
                                    <AlertCircle size={14} className={dbStatus?.status === 'checking' ? 'animate-spin' : 'animate-pulse'}/> 
                                    {dbStatus?.status === 'checking' ? 'Đang kiểm tra...' : 'Mất kết nối Database'}
                                </div>
                                {dbStatus?.message && (
                                    <span className="text-[9px] text-red-500 italic max-w-[200px] truncate" title={dbStatus.message}>
                                        {dbStatus.message}
                                    </span>
                                )}
                            </div>
                        )}
                        <button 
                            onClick={checkDB} 
                            disabled={isRefreshing}
                            className={`p-2 rounded-full hover:bg-gray-700 transition-colors ${isRefreshing ? 'animate-spin text-blue-400' : 'text-gray-400'}`}
                            title="Làm mới trạng thái kết nối"
                        >
                            <RefreshCw size={18}/>
                        </button>
                    </div>
                </div>

                <div className="flex-1 overflow-auto bg-gray-900 relative custom-scrollbar">
                    {renderModule()}
                </div>
            </div>
        </div>
    );
};

