};

export default LayerManager;

import React from 'react';
import { Layers, Eye, EyeOff, MapPin, MousePointerClick, Info, Map as MapIcon, Landmark } from 'lucide-react';
import { WMSLayerConfig, BasemapConfig } from '../../types';

interface LayerControlProps {
    isOpen: boolean;
    onToggleMenu: () => void;
    basemaps: BasemapConfig[];
    activeBasemapId: string;
    onBaseLayerChange: (id: string) => void;
    availableLayers: WMSLayerConfig[];
    visibleLayerIds: string[];
    activeLayerId: string | null;
    onToggleWMS: (id: string) => void;
    onSetActiveWMS: (id: string) => void;
    onOpacityChange: (id: string, opacity: number) => void;
}

const LayerControl: React.FC<LayerControlProps> = ({ 
    isOpen, onToggleMenu, basemaps, activeBasemapId, onBaseLayerChange, 
    availableLayers, visibleLayerIds, activeLayerId, onToggleWMS, onSetActiveWMS, onOpacityChange 
}) => {

    // Đảm bảo dữ liệu đầu vào luôn là mảng để tránh lỗi .filter is not a function
    const safeLayers = Array.isArray(availableLayers) ? availableLayers : [];
    const safeBasemaps = Array.isArray(basemaps) ? basemaps : [];
    const safeVisibleIds = Array.isArray(visibleLayerIds) ? visibleLayerIds : [];

    // Phân nhóm lớp dữ liệu
    const standardLayers = safeLayers.filter(l => l && (!l.category || l.category === 'STANDARD'));
    const planningLayers = safeLayers.filter(l => l && l.category === 'PLANNING');

    const renderLayerItem = (l: WMSLayerConfig) => {
        if (!l || !l.id) return null;
        const isVisible = safeVisibleIds.includes(l.id);
        const isActive = activeLayerId === l.id;
        const opacityValue = Number(l.opacity ?? 1);

        return (
            <div key={l.id} className={`p-2 rounded border transition-all ${isActive ? 'bg-blue-50 border-blue-200 shadow-sm' : 'border-transparent hover:bg-gray-50'}`}>
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2 cursor-pointer flex-1 min-w-0" onClick={() => onSetActiveWMS(l.id)}>
                        {isActive ? <MousePointerClick size={14} className="text-blue-600 shrink-0"/> : <MapPin size={14} className="text-gray-400 shrink-0"/>}
                        <span className={`text-sm font-bold truncate ${isActive ? 'text-blue-700' : 'text-gray-700'}`}>{l.name}</span>
                    </div>
                    <button onClick={() => onToggleWMS(l.id)} className={`shrink-0 transition-colors ${isVisible ? 'text-blue-600' : 'text-gray-300 hover:text-gray-400'}`}>
                        {isVisible ? <Eye size={18}/> : <EyeOff size={18}/>}
                    </button>
                </div>
                {isVisible && (
                    <div className="mt-2 flex items-center gap-2 animate-in fade-in duration-300">
                        <input 
                            type="range" min="0" max="1" step="0.1" 
                            value={opacityValue} 
                            onChange={e => onOpacityChange(l.id, parseFloat(e.target.value))} 
                            className="flex-1 h-1 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600" 
                        />
                        <span className="text-[9px] text-gray-400 font-mono w-6 text-right">{Math.round(opacityValue * 100)}%</span>
                    </div>
                )}
            </div>
        );
    };

    if (!isOpen) return (
        <button 
            onClick={onToggleMenu} 
            className="absolute top-4 right-4 z-[450] p-3 bg-white rounded-xl shadow-2xl text-slate-700 hover:text-blue-600 transition-all border border-gray-100 active:scale-95 group"
            title="Quản lý lớp bản đồ"
        >
            <Layers size={24} className="group-hover:scale-110 transition-transform" />
        </button>
    );

    return (
        <div className="absolute top-4 right-4 z-[500] bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.2)] border border-gray-200 w-80 animate-in slide-in-from-right-10 max-h-[90vh] flex flex-col overflow-hidden">
            <div className="flex justify-between items-center mb-4">
                <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] flex items-center gap-1.5">
                    <MapIcon size={12}/> Bản đồ nền
                </h4>
                <button onClick={onToggleMenu} className="p-1 hover:bg-gray-100 rounded-full text-gray-400 hover:text-gray-600 transition-all">
                    <Info size={14}/>
                </button>
            </div>

            <div className="grid grid-cols-2 gap-2 mb-4">
                {safeBasemaps.length === 0 ? (
                    <div className="col-span-2 text-[10px] text-gray-400 italic py-2 text-center bg-gray-50 rounded-lg border border-dashed border-gray-200">Không có bản đồ nền</div>
                ) : (
                    safeBasemaps.filter(bm => bm && bm.visible).map(bm => (
                        <button 
                            key={bm.id} 
                            onClick={() => onBaseLayerChange(bm.id)} 
                            className={`text-[10px] font-black py-2.5 px-2 rounded-xl border transition-all truncate uppercase tracking-tighter ${activeBasemapId === bm.id ? 'bg-blue-600 text-white border-blue-600 shadow-lg shadow-blue-900/20' : 'bg-gray-50 text-gray-500 border-gray-200 hover:bg-gray-100 hover:border-gray-300'}`}
                            title={bm.name}
                        >
                            {bm.name}
                        </button>
                    ))
                )}
            </div>

            <div className="border-t border-gray-100 my-3" />

            <div className="flex-1 overflow-y-auto pr-1 custom-scrollbar space-y-6">
                {/* Section 1: Quy hoạch */}
                <div>
                    <h4 className="text-[10px] font-black text-purple-600 uppercase mb-2 flex items-center gap-2 tracking-widest ml-1">
                        <Landmark size={12}/> Lớp Quy hoạch
                    </h4>
                    <div className="space-y-1">
                        {planningLayers.length === 0 ? (
                            <p className="text-[10px] text-gray-400 italic px-3 py-2 bg-gray-50 rounded-lg">Chưa cấu hình</p>
                        ) : planningLayers.map(l => renderLayerItem(l))}
                    </div>
                </div>

                {/* Section 2: Chuyên đề */}
                <div>
                    <h4 className="text-[10px] font-black text-blue-600 uppercase mb-2 flex items-center gap-2 tracking-widest ml-1">
                        <Layers size={12}/> Lớp Chuyên đề
                    </h4>
                    <div className="space-y-1">
                        {standardLayers.length === 0 ? (
                            <p className="text-[10px] text-gray-400 italic px-3 py-2 bg-gray-50 rounded-lg">Trống</p>
                        ) : standardLayers.map(l => renderLayerItem(l))}
                    </div>
                </div>
            </div>

            <button 
                onClick={onToggleMenu} 
                className="mt-6 w-full py-3 bg-slate-900 hover:bg-black text-white rounded-xl text-[10px] font-black transition-all uppercase tracking-[0.2em] shadow-lg active:scale-95"
            >
                Đóng danh sách
            </button>
        </div>
    );
};

export default LayerControl;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { User, LandParcel, WMSLayerConfig, BasemapConfig } from '../types';
import { gisService, API_URL } from '../services/mockBackend';
import { parcelApi, ParcelDTO } from '../services/parcelApi';
import { Loader2, Crosshair, Printer, Plus, Minus, Compass, Zap, Search, MousePointer2, Info, CheckCircle2, AlertTriangle } from 'lucide-react';
import * as proj from 'ol/proj';
import Overlay from 'ol/Overlay';
import Draw from 'ol/interaction/Draw';
import { getArea, getLength } from 'ol/sphere';
import { unByKey } from 'ol/Observable';
import { Polygon, LineString } from 'ol/geom';
import { Coordinate } from 'ol/coordinate';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

// Components & Hooks
import ParcelPopup from '../components/map/ParcelPopup';
import SearchPanel from '../components/map/SearchPanel';
import LayerControl from '../components/map/LayerControl';
import PrintTemplate from '../components/map/PrintTemplate';
import MeasureTools from '../components/map/MeasureTools';
import ParcelForm from '../components/admin/parcel/ParcelForm';
import { useMapCore } from '../hooks/useMapCore';
import { useParcelLogic } from '../hooks/useParcelLogic';

const MapPage: React.FC<{ user: User | null; systemSettings?: Record<string, string> }> = ({ user, systemSettings }) => {
    const popupElement = useRef<HTMLDivElement>(null);
    const overlayInstance = useRef<Overlay | null>(null);

    // State quản lý danh sách lớp
    const [availableLayers, setAvailableLayers] = useState<WMSLayerConfig[]>([]);
    const [visibleLayerIds, setVisibleLayerIds] = useState<string[]>([]);
    const [activeLayerId, setActiveLayerId] = useState<string | null>(null);
    const [basemaps, setBasemaps] = useState<BasemapConfig[]>([]);
    const [activeBasemapId, setActiveBasemapId] = useState<string>('');
    const [spatialTables, setSpatialTables] = useState<any[]>([]);

    // UI State
    const [isInitialLoading, setIsInitialLoading] = useState(true);
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);
    const [isQuerying, setIsQuerying] = useState(false);
    const [isPrinting, setIsPrinting] = useState(false);
    const [printingParcel, setPrintingParcel] = useState<LandParcel | null>(null);
    const [measureMode, setMeasureMode] = useState<'LineString' | 'Polygon' | null>(null);
    const [dialog, setDialog] = useState<any>({ isOpen: false });

    // Khởi tạo Hook lõi
    const { 
        mapElement, 
        mapInstance, 
        highlightLayer, 
        measureSource, 
        mapRotation, 
        mapZoom, 
        mouseCoord, 
        zoomToLayer, 
        getFeatureInfoUrl,
        refreshWMS 
    } = useMapCore(availableLayers, basemaps, activeBasemapId, visibleLayerIds, activeLayerId);

    // Khởi tạo Hook nghiệp vụ
    useEffect(() => {
        if (!overlayInstance.current && popupElement.current) {
            overlayInstance.current = new Overlay({ 
                element: popupElement.current, 
                autoPan: { animation: { duration: 250 } }, 
                positioning: 'bottom-center' 
            });
            mapInstance.current?.addOverlay(overlayInstance.current);
        }
    }, [mapInstance.current]);

    const { 
        selectedParcel, 
        setSelectedParcel, 
        handleSelectResult, 
        isEditOpen, 
        setIsEditOpen, 
        editFormData, 
        setEditFormData, 
        editLoading, 
        setEditLoading, 
        openEdit 
    } = useParcelLogic(mapInstance.current, highlightLayer.current, overlayInstance.current);

    // Xử lý Sự kiện Click Bản đồ
    useEffect(() => {
        if (!mapInstance.current) return;
        const map = mapInstance.current;

        const clickHandler = async (evt: any) => {
            if (measureMode) return;

            // Tìm trong các lớp đang hiện, ưu tiên lớp Active
            const safeVisibleIds = Array.isArray(visibleLayerIds) ? visibleLayerIds : [];
            let targetIds = activeLayerId ? [activeLayerId, ...safeVisibleIds.filter(id => id !== activeLayerId)] : safeVisibleIds;
            if (targetIds.length === 0) return;

            setIsQuerying(true);
            overlayInstance.current?.setPosition(undefined);
            setSelectedParcel(null);
            highlightLayer.current?.getSource()?.clear();

            let found = false;
            for (const lid of targetIds) {
                if (found) break;

                const infoUrl = getFeatureInfoUrl(evt.coordinate, lid);
                if (!infoUrl) continue;

                try {
                    const res = await fetch(infoUrl);
                    const data = await res.json();
                    if (data.features?.length > 0) {
                        const f = data.features[0];
                        const config = availableLayers.find(c => c.id === lid);
                        const tableName = config?.layers?.includes(':') ? config.layers.split(':').pop() : config?.layers;

                        handleSelectResult({ 
                            id: f.id, 
                            gid: f.properties.gid || parseInt(f.id.split('.').pop() || '0'), 
                            geometry: f.geometry, 
                            properties: { ...f.properties, tableName } 
                        }, evt.coordinate);
                        found = true;
                    }
                } catch (e) {
                    console.error("Feature info fetch error:", e);
                }
            }
            setIsQuerying(false);
        };

        map.on('singleclick', clickHandler);
        return () => map.un('singleclick', clickHandler);
    }, [mapInstance.current, measureMode, activeLayerId, visibleLayerIds, availableLayers, handleSelectResult, getFeatureInfoUrl]);

    // Đo đạc Tools
    useEffect(() => {
        if (!mapInstance.current || !measureMode) return;
        const draw = new Draw({ source: measureSource.current, type: measureMode });
        mapInstance.current.addInteraction(draw);
        draw.on('drawend', () => setMeasureMode(null));
        return () => {
            if (mapInstance.current) {
                mapInstance.current.removeInteraction(draw);
            }
        };
    }, [measureMode]);

    // Tải dữ liệu ban đầu
    const initData = async () => {
        try {
            const [layers, tables, maps] = await Promise.all([
                gisService.getLayers().catch(() => []), 
                gisService.getSpatialTables().catch(() => []), 
                gisService.getBasemaps().catch(() => [])
            ]);

            const safeLayers = Array.isArray(layers) ? layers : [];
            const safeMaps = Array.isArray(maps) ? maps : [];
            const safeTables = Array.isArray(tables) ? tables : [];

            setAvailableLayers(safeLayers);
            setVisibleLayerIds(safeLayers.filter(l => l && l.visible).map(l => l.id));
            setSpatialTables(safeTables);
            setBasemaps(safeMaps);

            const defMap = safeMaps.find(m => m && m.isDefault) || safeMaps[0];
            if (defMap) setActiveBasemapId(defMap.id);
            if (safeLayers.length && !activeLayerId) setActiveLayerId(safeLayers[0].id);
        } catch (e) {
            console.error("Init Map Data Error:", e);
        } finally { 
            setIsInitialLoading(false); 
        }
    };
    useEffect(() => { initData(); }, []);

    // Action: In ấn
    const handlePrint = async (parcel: LandParcel) => {
        setIsPrinting(true); setPrintingParcel(parcel);
        setTimeout(async () => {
            const el = document.getElementById('print-template');
            if (el) {
                try {
                    const canvas = await html2canvas(el, { scale: 3, useCORS: true, backgroundColor: '#ffffff' });
                    const pdf = new jsPDF('p', 'mm', 'a4');
                    pdf.addImage(canvas.toDataURL('image/png'), 'PNG', 0, 0, 210, (canvas.height * 210) / canvas.width);
                    pdf.save(`Parcel_${parcel.properties.so_thua}.pdf`);
                } catch (err) {
                    console.error("PDF Export Error:", err);
                }
            }
            setIsPrinting(false); setPrintingParcel(null);
        }, 2000);
    };

    // Action: Lưu cập nhật
    const handleUpdateParcel = async (e: React.FormEvent) => {
        e.preventDefault();
        setEditLoading(true);
        try {
            await parcelApi.update(editFormData.tableName!, editFormData.gid!, editFormData);
            setDialog({ isOpen: true, type: 'success', title: 'Thành công', message: 'Dữ liệu đã được cập nhật.' });
            setIsEditOpen(false); refreshWMS();
        } catch (err: any) {
            setDialog({ isOpen: true, type: 'error', title: 'Thất bại', message: err.message });
        } finally { setEditLoading(false); }
    };

    return (
        <div className="relative w-full h-full bg-slate-950 flex flex-col overflow-hidden font-sans">
            {isInitialLoading && (
                <div className="absolute inset-0 z-[1000] bg-slate-900 flex flex-col items-center justify-center text-white gap-4">
                    <Loader2 className="animate-spin text-blue-500" size={48} />
                    <p className="font-display uppercase tracking-[0.3em] text-[10px] text-blue-400 font-black animate-pulse">GeoMaster Engine Loading...</p>
                </div>
            )}

            {isQuerying && (
                <div className="absolute bottom-24 left-1/2 -translate-x-1/2 z-[400] bg-slate-900/90 backdrop-blur-md border border-blue-500/30 px-5 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300">
                    <Loader2 className="animate-spin text-blue-500" size={20} />
                    <span className="text-[11px] font-black text-white uppercase tracking-[0.2em]">Đang lấy thông tin...</span>
                </div>
            )}

            <div ref={mapElement} className="flex-1 w-full relative" />

            {/* Overlay Components */}
            <MeasureTools activeMode={measureMode} onModeChange={setMeasureMode} onClear={() => measureSource.current.clear()} />

            {mouseCoord && (
                <div className="absolute bottom-6 left-6 z-[400] bg-slate-900/80 backdrop-blur-md border border-slate-700/50 px-3 py-1.5 rounded-xl shadow-2xl flex items-center gap-3 animate-in fade-in duration-300 pointer-events-none">
                    <div className="flex items-center gap-1.5 text-blue-400"><MousePointer2 size={12}/><span className="text-[9px] font-black uppercase tracking-[0.1em]">Tọa độ</span></div>
                    <div className="flex gap-4 font-mono text-[11px] font-bold text-gray-100">
                        <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">X:</span><span>{mouseCoord[0].toFixed(6)}</span></div>
                        <div className="flex items-baseline gap-1"><span className="text-gray-500 text-[9px]">Y:</span><span>{mouseCoord[1].toFixed(6)}</span></div>
                    </div>
                </div>
            )}

            <SearchPanel isOpen={isSearchOpen} onToggle={() => setIsSearchOpen(!isSearchOpen)} spatialTables={spatialTables} onSelectResult={handleSelectResult} onSearchCoordinate={(lat, lon) => mapInstance.current?.getView().animate({ center: proj.fromLonLat([lon, lat]), zoom: 18, duration: 1000 })} />

            <LayerControl 
                isOpen={isLayerMenuOpen} 
                onToggleMenu={() => setIsLayerMenuOpen(!isLayerMenuOpen)} 
                basemaps={basemaps} 
                activeBasemapId={activeBasemapId} 
                onBaseLayerChange={setActiveBasemapId} 
                availableLayers={availableLayers} 
                visibleLayerIds={visibleLayerIds} 
                activeLayerId={activeLayerId} 
                onToggleWMS={id => {
                    const safeIds = Array.isArray(visibleLayerIds) ? visibleLayerIds : [];
                    setVisibleLayerIds(safeIds.includes(id) ? safeIds.filter(x => x !== id) : [...safeIds, id]);
                }} 
                onSetActiveWMS={id => { 
                    const safeIds = Array.isArray(visibleLayerIds) ? visibleLayerIds : [];
                    const safeLayers = Array.isArray(availableLayers) ? availableLayers : [];
                    setActiveLayerId(id); 
                    if (!safeIds.includes(id)) setVisibleLayerIds([...safeIds, id]); 
                    const config = safeLayers.find(l=>l && l.id === id);
                    const tbl = config?.layers?.split(':').pop(); 
                    if(tbl) zoomToLayer(tbl); 
                }} 
                onOpacityChange={(id, opacity) => setAvailableLayers(prev => Array.isArray(prev) ? prev.map(l => l.id === id ? { ...l, opacity } : l) : [])} 
            />

            <div ref={popupElement} className="absolute bottom-0 left-0 pointer-events-none">
                {selectedParcel && (
                    <div className="pointer-events-auto">
                        <ParcelPopup parcel={selectedParcel} user={user} onClose={() => { overlayInstance.current?.setPosition(undefined); setSelectedParcel(null); highlightLayer.current?.getSource()?.clear(); }} onPrint={handlePrint} onEdit={openEdit} />
                    </div>
                )}
            </div>

            {/* Print Template Off-screen */}
            <div className="fixed -left-[4000px] top-0 opacity-0 pointer-events-none">
                {printingParcel && <PrintTemplate parcel={printingParcel} user={user} systemSettings={systemSettings} />}
            </div>

            {/* Float Controls */}
            <div className="absolute bottom-6 right-6 z-[400] flex flex-col gap-3">
                {Math.abs(mapRotation) > 0.01 && ( <button onClick={() => mapInstance.current?.getView().animate({ rotation: 0, duration: 500 })} className="p-3 bg-white rounded-full shadow-2xl text-orange-600 hover:bg-orange-50 transition-all"><Compass size={24} style={{ transform: `rotate(${-mapRotation}rad)` }}/></button> )}
                <div className="flex flex-col bg-white rounded-2xl shadow-2xl overflow-hidden border border-gray-100"> 
                    <button onClick={() => mapInstance.current?.getView().animate({ zoom: (mapInstance.current?.getView().getZoom() || 0) + 1, duration: 250 })} className="p-3.5 text-gray-700 hover:bg-gray-50 border-b border-gray-100"><Plus size={20}/></button> 
                    <button onClick={() => mapInstance.current?.getView().animate({ zoom: (mapInstance.current?.getView().getZoom() || 0) - 1, duration: 250 })} className="p-3.5 text-gray-700 hover:bg-gray-50"><Minus size={20}/></button> 
                </div>
            </div>

            <ParcelForm isOpen={isEditOpen} onClose={() => setIsEditOpen(false)} editingId={editFormData.gid || null} formData={editFormData} setFormData={setEditFormData} handleSubmit={handleUpdateParcel} loading={editLoading} />

            {dialog.isOpen && (
                <div className="fixed inset-0 z-[3000] bg-black/90 backdrop-blur-md flex items-center justify-center p-4 animate-in fade-in duration-200">
                    <div className="bg-gray-900 rounded-[2rem] w-full max-w-sm border border-gray-800 shadow-2xl overflow-hidden p-8 text-center">
                        {dialog.type === 'success' ? <CheckCircle2 className="mx-auto text-emerald-500 mb-4" size={48}/> : <AlertTriangle className="mx-auto text-red-500 mb-4" size={48}/>}
                        <h3 className="text-lg font-black text-white uppercase mb-2">{dialog.title}</h3>
                        <p className="text-gray-400 text-xs mb-6">{dialog.message}</p>
                        <button onClick={() => setDialog({ isOpen: false })} className="w-full py-3 bg-blue-600 hover:bg-blue-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">OK</button>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MapPage;

import { useRef, useState, useEffect, useCallback } from 'react';
import Map from 'ol/Map';
import View from 'ol/View';
import { Tile as TileLayer, Vector as VectorLayer, Group as LayerGroup } from 'ol/layer';
import { OSM, TileWMS, Vector as VectorSource, XYZ } from 'ol/source';
import * as proj from 'ol/proj';
import * as style from 'ol/style';
import proj4 from 'proj4';
import { register } from 'ol/proj/proj4';
import Collection from 'ol/Collection';
import { defaults as defaultControls } from 'ol/control/defaults';
import { Coordinate } from 'ol/coordinate';
import { API_URL } from '../services/mockBackend';
import { parcelApi } from '../services/parcelApi';
import { WMSLayerConfig, BasemapConfig } from '../types';

// Register VN-2000 Projection
proj4.defs("EPSG:9210", "+proj=tmerc +lat_0=0 +lon_0=105.75 +k=0.9999 +x_0=500000 +y_0=0 +ellps=WGS84 +towgs84=-191.904,-39.303,-111.450,0,0,0,0 +units=m +no_defs");
register(proj4);

const isSafeExtent = (extent: number[]) => extent.every(val => Number.isFinite(val));
const isSafeCoordinate = (coord: Coordinate) => coord.every(val => Number.isFinite(val));

export const useMapCore = (availableLayers: WMSLayerConfig[], basemaps: BasemapConfig[], activeBasemapId: string, visibleLayerIds: string[], activeLayerId: string | null) => {
    const mapElement = useRef<HTMLDivElement>(null);
    const mapInstance = useRef<Map | null>(null);
    const wmsLayerGroup = useRef<LayerGroup | null>(null);
    const baseLayerRef = useRef<TileLayer<any> | null>(null);
    const highlightLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const locationLayer = useRef<VectorLayer<VectorSource> | null>(null);
    const measureSource = useRef<VectorSource>(new VectorSource());

    const [mapRotation, setMapRotation] = useState(0);
    const [mapZoom, setMapZoom] = useState(0);
    const [mouseCoord, setMouseCoord] = useState<Coordinate | null>(null);
    const [wmsCacheBust, setWmsCacheBust] = useState(Date.now());

    // Styles
    const highlightStyle = new style.Style({
        stroke: new style.Stroke({ color: '#00ffff', width: 4 }),
        fill: new style.Fill({ color: 'rgba(0, 255, 255, 0.2)' }),
        image: new style.Circle({ radius: 8, fill: new style.Fill({ color: '#00ffff' }), stroke: new style.Stroke({color: '#ffffff', width: 2}) })
    });

    // Initialize Map
    useEffect(() => {
        if (!mapElement.current || mapInstance.current) return;

        const map = new Map({
            target: mapElement.current,
            layers: [
                new TileLayer({ zIndex: 0 }), // Basemap
                new LayerGroup({ zIndex: 10 }), // WMS Layers
                new VectorLayer({ source: new VectorSource(), zIndex: 10000, style: highlightStyle }),
                new VectorLayer({ source: new VectorSource(), zIndex: 20000 }),
                new VectorLayer({ source: measureSource.current, zIndex: 30000 }),
            ],
            view: new View({ 
                center: proj.fromLonLat([106.619, 11.284]), 
                zoom: 13, 
                minZoom: 5, 
                maxZoom: 22,
                multiWorld: false,
                constrainResolution: true
            }),
            controls: defaultControls({ attribution: false })
        });

        baseLayerRef.current = map.getLayers().getArray()[0] as TileLayer<any>;
        wmsLayerGroup.current = map.getLayers().getArray()[1] as LayerGroup;
        highlightLayer.current = map.getLayers().getArray()[2] as VectorLayer<VectorSource>;
        locationLayer.current = map.getLayers().getArray()[3] as VectorLayer<VectorSource>;

        map.on('pointermove', (evt) => { 
            if (!evt.dragging && evt.coordinate) {
                const lonLat = proj.toLonLat(evt.coordinate);
                if (isSafeCoordinate(lonLat)) setMouseCoord(lonLat);
            }
        });

        map.getView().on('change:rotation', () => setMapRotation(map.getView().getRotation()));
        map.getView().on('change:resolution', () => setMapZoom(map.getView().getZoom() || 0));

        mapInstance.current = map;
        const resizeObserver = new ResizeObserver(() => map.updateSize());
        resizeObserver.observe(mapElement.current);
        return () => resizeObserver.disconnect();
    }, []);

    // Sync Basemap
    useEffect(() => {
        if (!baseLayerRef.current || !activeBasemapId || !Array.isArray(basemaps) || basemaps.length === 0) return;
        const config = basemaps.find(m => m && m.id === activeBasemapId);
        if (!config) return;
        let source;
        if (config.type === 'OSM') source = new OSM({ crossOrigin: 'anonymous' });
        else {
            const rawUrl = config.url.startsWith('/') ? `${API_URL}${config.url}` : config.url;
            const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(rawUrl)}`.split('%7Bz%7D').join('{z}').split('%7Bx%7D').join('{x}').split('%7By%7D').join('{y}');
            source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
        }
        baseLayerRef.current.setSource(source);
    }, [activeBasemapId, basemaps]);

    // Sync WMS Layers
    useEffect(() => {
        if (!wmsLayerGroup.current || !Array.isArray(availableLayers)) return;

        const safeVisibleIds = Array.isArray(visibleLayerIds) ? visibleLayerIds : [];
        const olLayers = availableLayers.filter(l => l && safeVisibleIds.includes(l.id)).map(config => {
            let source;
            if (config.type === 'XYZ') {
                const proxiedUrl = `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`.split('%7Bz%7D').join('{z}').split('%7Bx%7D').join('{x}').split('%7By%7D').join('{y}');
                source = new XYZ({ url: proxiedUrl, crossOrigin: 'anonymous' });
            } else {
                source = new TileWMS({ 
                    url: `${API_URL}/api/proxy/forward?url=${encodeURIComponent(config.url)}`, 
                    params: { 'LAYERS': config.layers, 'TILED': true, 'TRANSPARENT': true, 'FORMAT': 'image/png', 't': wmsCacheBust }, 
                    crossOrigin: 'anonymous' 
                });
            }
            let zIndex = config.category === 'PLANNING' ? 100 : 10;
            if (activeLayerId === config.id) zIndex += 50;
            const layer = new TileLayer({ source: source, opacity: Number(config.opacity ?? 1), zIndex: zIndex });
            layer.set('layerId', config.id);
            return layer;
        });
        wmsLayerGroup.current.setLayers(new Collection(olLayers));
    }, [availableLayers, visibleLayerIds, activeLayerId, wmsCacheBust]);

    const zoomToLayer = useCallback(async (tableName: string) => {
        if (!mapInstance.current) return;
        try {
            const extentData = await parcelApi.getExtent(tableName);
            if (extentData && extentData.xmin !== null && extentData.xmin !== undefined) {
                const xmin = parseFloat(extentData.xmin), ymin = parseFloat(extentData.ymin);
                const xmax = parseFloat(extentData.xmax), ymax = parseFloat(extentData.ymax);

                if (Number.isFinite(xmin) && Number.isFinite(ymin) && Number.isFinite(xmax) && Number.isFinite(ymax)) {
                    const extent = [xmin, ymin, xmax, ymax];
                    let sourceProj = Math.abs(xmin) > 300000 && Math.abs(xmin) < 900000 ? 'EPSG:9210' : 'EPSG:4326';
                    if (Math.abs(xmin) > 1000000) sourceProj = 'EPSG:3857';

                    const transformed = proj.transformExtent(extent, sourceProj, 'EPSG:3857');
                    if (isSafeExtent(transformed)) {
                        mapInstance.current.getView().fit(transformed, { padding: [100, 100, 100, 100], duration: 1000, maxZoom: 20 });
                    }
                }
            }
        } catch (e) { console.error("Zoom failed", e); }
    }, []);

    const getFeatureInfoUrl = (coordinate: Coordinate, layerId: string) => {
        if (!mapInstance.current || !wmsLayerGroup.current) return null;
        const view = mapInstance.current.getView();
        const resolution = view.getResolution();
        const projection = view.getProjection();

        const olLayer = wmsLayerGroup.current.getLayers().getArray()
            .find(l => l.get('layerId') === layerId) as TileLayer<TileWMS>;

        if (!olLayer || !olLayer.getSource()?.getFeatureInfoUrl) return null;

        return olLayer.getSource()!.getFeatureInfoUrl(
            coordinate, 
            resolution!, 
            projection, 
            { 'INFO_FORMAT': 'application/json', 'FEATURE_COUNT': 1 }
        );
    };

    return { 
        mapElement, 
        mapInstance, 
        highlightLayer, 
        measureSource, 
        mapRotation, 
        mapZoom, 
        mouseCoord, 
        zoomToLayer, 
        getFeatureInfoUrl,
        refreshWMS: () => setWmsCacheBust(Date.now()) 
    };
};
